import { motion } from "framer-motion";
import { useEffect, useMemo, useState } from "react";
import { buildChallengeSlug } from "../../lib/challengeSlug";
import { ihkGradeFromPercent, ihkGradeLabel } from "../../lib/mockExamGrading";
import { cn } from "../../lib/cn";
import { springHeavy } from "../../motion/variants";
import { useAppStore } from "../../store/useAppStore";

function fmtClock(totalSec: number): string {
  const s = Math.max(0, Math.floor(totalSec));
  const m = Math.floor(s / 60);
  const r = s % 60;
  return `${String(m).padStart(2, "0")}:${String(r).padStart(2, "0")}`;
}

export function MockExamView() {
  const run = useAppStore((s) => s.mockExam);
  const setAnswer = useAppStore((s) => s.setMockExamAnswer);
  const next = useAppStore((s) => s.nextMockExamQuestion);
  const prev = useAppStore((s) => s.prevMockExamQuestion);
  const jump = useAppStore((s) => s.jumpMockExamQuestion);
  const tick = useAppStore((s) => s.tickMockExamTimer);
  const submit = useAppStore((s) => s.submitMockExam);
  const abandon = useAppStore((s) => s.abandonMockExam);
  const acceptChallenge = useAppStore((s) => s.acceptMockExamChallenge);
  const operatorHandle = useAppStore((s) => s.operatorHandle);
  const [shareState, setShareState] = useState<null | "ok" | "err">(null);

  useEffect(() => {
    if (!run || run.submitted || !run.challengeAccepted) return;
    const id = window.setInterval(() => tick(), 1000);
    return () => window.clearInterval(id);
  }, [run, tick]);

  useEffect(() => {
    if (!run || run.submitted || !run.challengeAccepted) return;
    const onBeforeUnload = (event: BeforeUnloadEvent) => {
      event.preventDefault();
      event.returnValue = "";
    };
    window.addEventListener("beforeunload", onBeforeUnload);
    return () => window.removeEventListener("beforeunload", onBeforeUnload);
  }, [run]);

  if (!run) {
    return (
      <div className="border border-white/[0.1] bg-surface/80 px-5 py-8 text-center font-mono text-xs uppercase tracking-[0.2em] text-foreground-muted">
        Keine aktive Prüfung
      </div>
    );
  }

  const total = run.questionSet.length;
  const idx = Math.max(0, Math.min(total - 1, run.questionIndex));
  const question = run.questionSet[idx];
  if (!question || total === 0) {
    return (
      <div className="border border-white/[0.1] bg-surface/80 px-5 py-8 text-center font-mono text-xs uppercase tracking-[0.2em] text-foreground-muted">
        Fragepool nicht verfügbar
      </div>
    );
  }
  const answeredCount = run.answers.filter((x) => x !== null).length;
  const progressPercent = total > 0 ? (answeredCount / total) * 100 : 0;
  const elapsedMs = Math.max(
    0,
    ((run.submitted ? run.finishedAtMs : Date.now()) ?? Date.now()) - run.startedAtMs,
  );

  const result = useMemo(() => {
    let correct = 0;
    const wrongTags = new Map<string, number>();
    run.questionSet.forEach((q, i) => {
      const a = run.answers[i];
      if (a === q.correctIndex) {
        correct += 1;
        return;
      }
      for (const t of q.tags) wrongTags.set(t, (wrongTags.get(t) ?? 0) + 1);
    });
    const percent = total > 0 ? (correct / total) * 100 : 0;
    const grade = ihkGradeFromPercent(percent);
    const weakTags = [...wrongTags.entries()]
      .sort((a, b) => b[1] - a[1])
      .slice(0, 6);
    return { correct, percent, grade, weakTags };
  }, [run.answers, run.questionSet, total]);

  const challengeCompare = useMemo(() => {
    const meta = run.challengeMeta;
    if (!meta || meta.elapsedMs == null || meta.elapsedMs <= 0) return null;
    const delta = meta.elapsedMs - elapsedMs;
    const pct = Math.abs((delta / meta.elapsedMs) * 100);
    return {
      faster: delta > 0,
      pct,
      by: meta.by,
      scoreDelta: result.percent - (meta.percent ?? result.percent),
    };
  }, [elapsedMs, result.percent, run.challengeMeta]);

  if (!run.challengeAccepted) {
    return (
      <div className="space-y-5 border border-emerald-400/38 bg-emerald-500/[0.08] p-6 shadow-[inset_0_0_24px_rgb(16_185_129_/0.22),0_0_28px_rgb(16_185_129_/0.12)] sm:p-8">
        <p className="font-mono text-[10px] font-black uppercase tracking-[0.32em] text-emerald-200">
          CHALLENGE ACCEPTED
        </p>
        <div className="space-y-2 border border-emerald-300/35 bg-black/30 p-4 font-mono text-xs uppercase tracking-[0.2em] text-foreground">
          <p>Herausforderer {run.challengeMeta?.by ?? "Unknown_Operator"}</p>
          <p>Fragenset {total} Items</p>
          {run.challengeMeta?.percent != null ? (
            <p>Zielwert {run.challengeMeta.percent.toFixed(1)}%</p>
          ) : null}
        </div>
        <motion.button
          type="button"
          whileTap={{ scale: 0.95, y: 2 }}
          transition={springHeavy}
          onClick={() => acceptChallenge()}
          className="border border-emerald-300/45 bg-emerald-500/[0.14] px-5 py-2.5 font-mono text-xs font-black uppercase tracking-[0.24em] text-emerald-100 hover-breathe hover:border-emerald-200/65"
        >
          START CHALLENGE
        </motion.button>
      </div>
    );
  }

  if (run.submitted) {
    return (
      <div className="space-y-5 border border-white/[0.1] bg-[#070808] p-6 sm:p-8">
        <p className="font-mono text-[10px] font-semibold uppercase tracking-[0.3em] text-foreground-muted">
          Exam Result
        </p>
        <div className="border border-emerald-400/30 bg-emerald-500/[0.06] px-4 py-3 font-mono text-sm uppercase tracking-[0.18em] text-emerald-200">
          Note {result.grade} · {ihkGradeLabel(result.grade)} · {result.percent.toFixed(1)}%
        </div>
        <div className="grid gap-3 border border-white/[0.1] p-4 font-mono text-[11px] uppercase tracking-[0.16em] text-foreground-muted sm:grid-cols-3">
          <p>Fragen {total}</p>
          <p>Richtig {result.correct}</p>
          <p>Falsch {Math.max(0, total - result.correct)}</p>
        </div>
        {challengeCompare ? (
          <div className="border border-emerald-400/35 bg-emerald-500/[0.07] p-4 font-mono text-xs uppercase tracking-[0.18em] text-emerald-100">
            {challengeCompare.faster
              ? `Du warst ${challengeCompare.pct.toFixed(1)}% schneller als ${challengeCompare.by}`
              : `Du warst ${challengeCompare.pct.toFixed(1)}% langsamer als ${challengeCompare.by}`}
            <br />
            Score Delta {challengeCompare.scoreDelta >= 0 ? "+" : ""}
            {challengeCompare.scoreDelta.toFixed(1)}%
          </div>
        ) : null}
        <div className="border border-white/[0.1] bg-black/35 p-4">
          <p className="font-mono text-[10px] uppercase tracking-[0.24em] text-foreground-muted">Schwachstellen</p>
          {result.weakTags.length === 0 ? (
            <p className="mt-3 font-mono text-xs uppercase tracking-[0.18em] text-emerald-200">
              Keine offensichtliche Schwachstelle erkannt
            </p>
          ) : (
            <ul className="mt-3 space-y-2 font-mono text-xs uppercase tracking-[0.16em] text-foreground">
              {result.weakTags.map(([tag, count]) => (
                <li key={tag}>
                  {tag} · {count} Fehler
                </li>
              ))}
            </ul>
          )}
        </div>
        <div className="flex flex-wrap items-center gap-2">
          <motion.button
            type="button"
            whileTap={{ scale: 0.95, y: 2 }}
            transition={springHeavy}
            onClick={async () => {
              const slug = buildChallengeSlug({
                ids: run.questionSet.map((q) => q.id),
                by: operatorHandle ?? "Unknown_Operator",
                elapsedMs,
                percent: result.percent,
              });
              const url = `${window.location.origin}${window.location.pathname}?challenge=${encodeURIComponent(slug)}`;
              try {
                await navigator.clipboard.writeText(url);
                setShareState("ok");
              } catch {
                setShareState("err");
              }
            }}
            className="border border-emerald-400/45 bg-emerald-500/[0.12] px-5 py-2.5 font-mono text-xs font-black uppercase tracking-[0.22em] text-emerald-100 hover-breathe hover:border-emerald-300/65"
          >
            ISSUE CHALLENGE
          </motion.button>
          {shareState === "ok" ? (
            <span className="font-mono text-[10px] uppercase tracking-[0.2em] text-emerald-200">Challenge Link kopiert</span>
          ) : shareState === "err" ? (
            <span className="font-mono text-[10px] uppercase tracking-[0.2em] text-signal">Clipboard Zugriff blockiert</span>
          ) : null}
        </div>
        <motion.button
          type="button"
          whileTap={{ scale: 0.95, y: 2 }}
          transition={springHeavy}
          onClick={() => abandon()}
          className="border border-white/[0.14] bg-white/[0.06] px-5 py-2.5 font-mono text-xs font-semibold uppercase tracking-[0.2em] text-foreground hover-breathe hover:border-white/[0.2]"
        >
          Zurück zum Hub
        </motion.button>
      </div>
    );
  }

  return (
    <div className="space-y-5 border border-white/[0.1] bg-surface/88 p-6 sm:p-8">
      <div className="flex flex-wrap items-center justify-between gap-3">
        <p className="font-mono text-[10px] font-semibold uppercase tracking-[0.3em] text-foreground-muted">
          IHK Mock Exam Protocol
        </p>
        <p className="font-mono text-sm font-semibold uppercase tracking-[0.14em] text-foreground">
          Restzeit {fmtClock(run.timeRemainingSec)}
        </p>
      </div>

      <div className="space-y-2">
        <div className="h-2 overflow-hidden border border-white/[0.12] bg-black/40">
          <div className="h-full bg-white/70 transition-[width] duration-300" style={{ width: `${progressPercent}%` }} />
        </div>
        <div className="flex items-center justify-between font-mono text-[10px] uppercase tracking-[0.18em] text-foreground-muted">
          <span>
            Frage {idx + 1} von {total}
          </span>
          <span>
            Beantwortet {answeredCount}/{total}
          </span>
        </div>
      </div>

      <div className="space-y-3 border border-white/[0.1] bg-black/35 p-4">
        <p className="font-mono text-[10px] uppercase tracking-[0.2em] text-foreground-muted">
          {question.type === "sql_challenge" ? "SQL Challenge" : "Multiple Choice"}
        </p>
        <h2 className="font-serif text-xl font-semibold text-foreground sm:text-2xl">{question.prompt}</h2>
      </div>

      <div className="space-y-2">
        {question.options.map((opt, optionIndex) => {
          const selected = run.answers[idx] === optionIndex;
          return (
            <button
              key={`${question.id}-${optionIndex}`}
              type="button"
              onClick={() => setAnswer(optionIndex)}
              className={cn(
                "w-full border px-4 py-3 text-left font-sans text-sm transition-colors",
                selected
                  ? "border-emerald-400/45 bg-emerald-500/[0.1] text-foreground"
                  : "border-white/[0.1] bg-transparent text-foreground hover-breathe hover:border-white/[0.18]",
              )}
            >
              <span className="font-mono text-[10px] uppercase tracking-[0.16em] text-foreground-muted">
                Option {optionIndex + 1}
              </span>
              <p className="mt-1">{opt}</p>
            </button>
          );
        })}
      </div>

      <div className="flex flex-wrap items-center gap-2 border-t border-white/[0.1] pt-4">
        <motion.button
          type="button"
          whileTap={{ scale: 0.95, y: 2 }}
          transition={springHeavy}
          onClick={() => prev()}
          className="border border-white/[0.14] px-4 py-2 font-mono text-[11px] font-semibold uppercase tracking-[0.18em] text-foreground-muted hover-breathe hover:text-foreground"
        >
          Zurück
        </motion.button>
        <motion.button
          type="button"
          whileTap={{ scale: 0.95, y: 2 }}
          transition={springHeavy}
          onClick={() => next()}
          className="border border-white/[0.14] px-4 py-2 font-mono text-[11px] font-semibold uppercase tracking-[0.18em] text-foreground-muted hover-breathe hover:text-foreground"
        >
          Weiter
        </motion.button>
        <motion.button
          type="button"
          whileTap={{ scale: 0.95, y: 2 }}
          transition={springHeavy}
          onClick={() => submit()}
          className="ml-auto border border-signal/45 bg-signal/[0.1] px-4 py-2 font-mono text-[11px] font-semibold uppercase tracking-[0.2em] text-signal hover-breathe hover:border-signal/65"
        >
          Prüfung beenden
        </motion.button>
      </div>

      <div className="flex flex-wrap gap-1.5 border-t border-white/[0.1] pt-4">
        {run.answers.map((a, i) => (
          <button
            key={`jump-${i}`}
            type="button"
            onClick={() => jump(i)}
            className={cn(
              "h-7 min-w-7 border px-2 font-mono text-[10px] font-semibold tabular-nums",
              i === idx
                ? "border-foreground/35 bg-white/[0.12] text-foreground"
                : a === null
                  ? "border-white/[0.1] text-foreground-muted"
                  : "border-emerald-400/35 bg-emerald-500/[0.08] text-emerald-200",
            )}
            aria-label={`Frage ${i + 1}`}
          >
            {i + 1}
          </button>
        ))}
      </div>
    </div>
  );
}
