export type NexusActivityKind =
  | "NEW_RANK"
  | "NEW_HINT"
  | "FACTION_GAIN"
  | "FORGE_DROP"
  | "GLOBAL_OVERDRIVE"
  | "LORE_UNLOCK"
  | "CHALLENGE_INIT"
  | "CHALLENGE_ACCEPT"
  | "DUEL_RESULT"
  | "GLOBAL_BOSS_GHOST"
  | "SYSTEM_INFECTED"
  | "NEURAL_PURGE"
  | "SYSTEM_CURED"
  | "SYNDICATE_FOUNDED"
  | "SYNDICATE_ASCENSION"
  | "SECTOR_CAPTURED"
  | "COUNCIL_PROPOSAL"
  | "COUNCIL_DECREE";

export type NexusActivityEventPayload = {
  kind: NexusActivityKind;
  userId?: string;
  handle?: string;
  label: string;
  routeHint?: "public_dossier";
  meta?: Record<string, string | number | boolean | null>;
};

export type NexusActivityItem = {
  id: string;
  ts: number;
  kind: NexusActivityKind;
  userId?: string;
  handle?: string;
  label: string;
  routeHint?: "public_dossier";
  meta?: Record<string, string | number | boolean | null>;
};

export function formatNexusActivityLine(item: NexusActivityItem): string {
  if (item.kind === "NEW_RANK") return `RANK_UPLINK ${item.label}`;
  if (item.kind === "NEW_HINT") return `HINT_FRAGMENT ${item.label}`;
  if (item.kind === "FACTION_GAIN") return `WARSHIFT ${item.label}`;
  if (item.kind === "GLOBAL_OVERDRIVE") return `OVERDRIVE ${item.label}`;
  if (item.kind === "LORE_UNLOCK") return `LORE SIGNAL ${item.label}`;
  if (item.kind === "CHALLENGE_INIT") return `DUEL CHALLENGE ${item.label}`;
  if (item.kind === "CHALLENGE_ACCEPT") return `DUEL LINK ${item.label}`;
  if (item.kind === "DUEL_RESULT") return `DUEL RESULT ${item.label}`;
  if (item.kind === "GLOBAL_BOSS_GHOST") return `BOSS GHOST ${item.label}`;
  if (item.kind === "SYSTEM_INFECTED") return `OUTBREAK ${item.label}`;
  if (item.kind === "NEURAL_PURGE") return `PURGE ${item.label}`;
  if (item.kind === "SYSTEM_CURED") return `CURE ${item.label}`;
  if (item.kind === "SYNDICATE_FOUNDED") return `SYNDICATE LINK ${item.label}`;
  if (item.kind === "SYNDICATE_ASCENSION") return `SYNDICATE ASCENSION ${item.label}`;
  if (item.kind === "SECTOR_CAPTURED") return `SECTOR CAPTURE ${item.label}`;
  if (item.kind === "COUNCIL_PROPOSAL") return `COUNCIL MOTION ${item.label}`;
  if (item.kind === "COUNCIL_DECREE") return `COUNCIL DECREE ${item.label}`;
  return `FORGE_DROP ${item.label}`;
}
