import { motion, useReducedMotion } from "framer-motion";
import { cn } from "../../lib/cn";
import type { LinkPulseStatus } from "../../lib/connectivity";
import { useAppStore } from "../../store/useAppStore";

const LABELS: Record<LinkPulseStatus, string> = {
  online: "ONLINE",
  slow: "SLOW",
  offline: "OFFLINE",
};

/**
 * Phase 51 — dynamischer Uplink-Heartbeat im Header
 * UI-Texte ohne Satzzeichen am Ende
 */
export function LinkHeartbeatChip() {
  const prefersReduced = useReducedMotion();
  const status = useAppStore((s) => s.linkPulseStatus);

  const tone =
    status === "online"
      ? {
          border: "border-cyan-400/35",
          ring: "ring-cyan-400/12",
          bg: "bg-cyan-500/[0.06]",
          dot: "text-cyan-300",
          text: "text-cyan-100/90",
        }
      : status === "slow"
        ? {
            border: "border-amber-400/35",
            ring: "ring-amber-400/12",
            bg: "bg-amber-500/[0.07]",
            dot: "text-amber-300",
            text: "text-amber-100/90",
          }
        : {
            border: "border-red-500/40",
            ring: "ring-red-500/15",
            bg: "bg-red-500/[0.07]",
            dot: "text-red-400",
            text: "text-red-100/90",
          };

  const pulseDot = status === "online" && !prefersReduced;

  return (
    <div
      className={cn(
        "hidden items-center gap-2 rounded-full border px-3 py-1 font-mono text-[10px] uppercase tracking-[0.14em] ring-1 sm:flex",
        tone.border,
        tone.ring,
        tone.bg,
      )}
      role="status"
      aria-live="polite"
    >
      {pulseDot ? (
        <motion.span
          className={cn("inline-block leading-none", tone.dot)}
          aria-hidden
          animate={{ scale: [1, 1.14, 1], opacity: [1, 0.78, 1] }}
          transition={{ duration: 2.6, repeat: Infinity, ease: "easeInOut" }}
        >
          ●
        </motion.span>
      ) : (
        <span className={cn("leading-none", tone.dot)} aria-hidden>
          ●
        </span>
      )}
      <span className={tone.text}>{LABELS[status]}</span>
    </div>
  );
}
