import { motion } from "framer-motion";
import { useCallback } from "react";
import { cn } from "../../lib/cn";
import type { RankArtifact } from "../../lib/rankEngine";
import { itemReveal, staggerContainer } from "../../motion/variants";
import { useAppStore, type UserProgress } from "../../store/useAppStore";
import { CircularStatRing } from "./CircularStatRing";

export interface ProfileGlassPanelProps {
  progress: UserProgress;
  prestigeTitle: string;
  prestigeArtifact: RankArtifact;
  className?: string;
}

export function ProfileGlassPanel({ progress, prestigeTitle, prestigeArtifact, className }: ProfileGlassPanelProps) {
  const xpRatio = progress.xpToNext > 0 ? progress.xpCurrent / progress.xpToNext : 0;
  const levelCap = 20;
  const streakCap = 30;

  const ammoDropImportFeed = useAppStore((s) => s.ammoDropImportFeed);
  const clearAmmoDropImportLog = useAppStore((s) => s.clearAmmoDropImportLog);
  const isAdmin = useAppStore((s) => s.isAdmin);

  const onInitiateAmmoDrop = useCallback(() => {
    clearAmmoDropImportLog();
    void import("../../lib/syncController").then((m) => void m.injectAmmoDropMasterSeed());
  }, [clearAmmoDropImportLog]);

  return (
    <motion.div
      variants={staggerContainer}
      initial="initial"
      animate="animate"
      className={cn(
        "relative overflow-hidden rounded-2xl border border-white/[0.1] bg-surface-muted/45 p-5 backdrop-blur-xl",
        className,
      )}
      style={{
        boxShadow: `inset 0 0 36px ${prestigeArtifact.auraColor}`,
      }}
    >
      <div className="pointer-events-none absolute inset-0 noise-overlay opacity-40" />
      <div className="relative flex flex-wrap items-start justify-between gap-6">
        <motion.div variants={itemReveal} className="min-w-0 flex-1 space-y-2">
          <p className="font-mono text-[10px] font-medium uppercase tracking-[0.32em] text-foreground-muted">
            Operative Status
          </p>
          <p className="font-sans text-3xl font-semibold tracking-[-0.05em] text-foreground sm:text-4xl">
            {progress.displayName}
          </p>
          <p
            className={cn(
              "font-mono text-sm font-bold uppercase tracking-[0.14em] sm:text-base",
              prestigeArtifact.accentClass,
            )}
          >
            {prestigeTitle}
          </p>
          <p className="font-sans text-sm text-foreground-muted">
            Synced und IHK progression vector stable
          </p>
          {isAdmin ? (
            <motion.div variants={itemReveal} className="pt-2">
              <button
                type="button"
                onClick={onInitiateAmmoDrop}
                className="border border-signal/40 bg-signal/[0.12] px-3 py-2 font-mono text-[10px] font-bold uppercase tracking-[0.2em] text-signal hover-breathe hover:border-signal/60 hover:bg-signal/[0.18]"
              >
                INITIATE AMMO DROP
              </button>
              <p className="mt-2 font-mono text-[9px] uppercase tracking-[0.16em] text-foreground-muted">
                Admin-Kernel aktiv · Aktion wird serverseitig erneut geprüft
              </p>
            </motion.div>
          ) : null}
        </motion.div>
        <motion.div
          variants={itemReveal}
          className="flex flex-wrap justify-center gap-5 sm:justify-end"
        >
          <CircularStatRing
            label="Level"
            value={Math.min(progress.level, levelCap)}
            max={levelCap}
            accent="magenta"
            centerLabel={String(progress.level)}
            sublabel="Rang"
          />
          <CircularStatRing
            label="XP"
            value={progress.xpCurrent}
            max={progress.xpToNext}
            accent="cyan"
            centerLabel={`${Math.round(xpRatio * 100)}%`}
            sublabel={`${progress.xpCurrent} / ${progress.xpToNext}`}
          />
          <CircularStatRing
            label="Streak"
            value={progress.streakDays}
            max={streakCap}
            accent="toxic"
            centerLabel={`${progress.streakDays}d`}
            sublabel="Hot run"
          />
        </motion.div>
      </div>

      {ammoDropImportFeed.length > 0 ? (
        <div className="relative mt-4 rounded-xl border border-white/[0.08] bg-black/70 p-3">
          <div className="mb-2 flex items-center justify-between gap-2">
            <span className="font-mono text-[9px] font-semibold uppercase tracking-[0.24em] text-foreground-muted">
              Ammo Terminal
            </span>
            <button
              type="button"
              onClick={() => clearAmmoDropImportLog()}
              className="font-mono text-[9px] uppercase tracking-[0.16em] text-signal hover:text-foreground"
            >
              Leeren
            </button>
          </div>
          <pre className="max-h-36 overflow-y-auto whitespace-pre-wrap break-all font-mono text-[10px] leading-relaxed text-foreground-muted">
            {ammoDropImportFeed.join("\n")}
          </pre>
        </div>
      ) : null}
    </motion.div>
  );
}
