import { AnimatePresence, motion, useReducedMotion } from "framer-motion";
import { useEffect, useState } from "react";
import type { ArenaQuestion } from "../../lib/questionContent";
import { AnalysisReportBlock } from "../blocks/AnalysisReportBlock";
import { QuestionBlueprintAfterPrompt } from "../blocks/QuestionBlueprintAfterPrompt";
import { springHeavy } from "../../motion/variants";
import { cn } from "../../lib/cn";
import { IconX } from "../icons/ThinLineIcons";

const dockTap = { scale: 0.94 as const, y: 3 as const };

type HelpdeskDiagnosticOverlayProps = {
  open: boolean;
  question: ArenaQuestion | null;
  onClose: () => void;
  onWrongPick: () => void;
  onCorrectCommit: (index: number) => void;
};

export function HelpdeskDiagnosticOverlay({
  open,
  question,
  onClose,
  onWrongPick,
  onCorrectCommit,
}: HelpdeskDiagnosticOverlayProps) {
  const prefersReduced = useReducedMotion();
  const [phase, setPhase] = useState<"pick" | "review">("pick");
  const [picked, setPicked] = useState<number | null>(null);
  const [analysisGate, setAnalysisGate] = useState(false);

  useEffect(() => {
    if (!question) {
      setPhase("pick");
      setPicked(null);
      setAnalysisGate(false);
      return;
    }
    setPhase("pick");
    setPicked(null);
    setAnalysisGate(false);
  }, [question?.id]);

  useEffect(() => {
    if (phase !== "review") {
      setAnalysisGate(false);
      return;
    }
    const id = requestAnimationFrame(() => setAnalysisGate(true));
    return () => cancelAnimationFrame(id);
  }, [phase]);

  const handleOption = (idx: number) => {
    if (!question || phase !== "pick") return;
    setPicked(idx);
    setPhase("review");
  };

  const handleContinue = () => {
    if (!question || picked === null || phase !== "review" || !analysisGate) return;
    const ok = picked === question.correctIndex;
    if (ok) {
      onCorrectCommit(picked);
      setPhase("pick");
      setPicked(null);
      setAnalysisGate(false);
      return;
    }
    onWrongPick();
    setPhase("pick");
    setPicked(null);
    setAnalysisGate(false);
  };

  const analysisBody =
    question?.explanation?.trim() || "Keine Kurzbegründung in der Bank hinterlegt";

  return (
    <AnimatePresence>
      {open ? (
        <>
          <motion.button
            type="button"
            key="diag-backdrop"
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            transition={{ duration: prefersReduced ? 0.12 : 0.22 }}
            aria-label="Uplink schließen"
            className="fixed inset-0 z-[240] bg-black/82 backdrop-blur-[2px]"
            onClick={onClose}
          />
          <motion.aside
            key="diag-panel"
            role="dialog"
            aria-modal="true"
            initial={prefersReduced ? { opacity: 0 } : { x: "100%", opacity: 0.65 }}
            animate={{ x: 0, opacity: 1 }}
            exit={prefersReduced ? { opacity: 0 } : { x: "100%", opacity: 0.5 }}
            transition={{ type: "spring", stiffness: 300, damping: 32 }}
            className="fixed inset-y-0 right-0 z-[250] flex w-full max-w-lg flex-col border-l border-signal/40 bg-black/92 shadow-[inset_0_0_0_1px_rgb(179_24_38_/0.12)]"
          >
            <div className="pointer-events-none absolute inset-0 hud-grid opacity-[0.14]" aria-hidden />
            <div
              className="pointer-events-none absolute inset-x-0 top-0 h-px bg-gradient-to-r from-transparent via-signal/55 to-transparent"
              aria-hidden
            />
            <div className="relative flex items-start justify-between gap-3 border-b border-white/[0.08] px-4 py-3">
              <div>
                <p className="font-mono text-[9px] font-semibold uppercase tracking-[0.32em] text-signal/90">System uplink</p>
                <p className="mt-1 font-mono text-[10px] uppercase tracking-[0.22em] text-foreground-muted">Diagnostic channel locked</p>
              </div>
              <motion.button
                type="button"
                whileTap={dockTap}
                transition={springHeavy}
                onClick={onClose}
                className="rounded-none border border-white/[0.12] bg-white/[0.04] p-2 text-foreground-muted hover-breathe hover:border-signal/35 hover:text-foreground"
              >
                <IconX className="size-4 shrink-0" aria-hidden />
              </motion.button>
            </div>

            <div className="relative flex-1 overflow-y-auto px-4 py-4">
              {question ? (
                <div className="space-y-6">
                  <div>
                    <p className="font-mono text-[10px] uppercase tracking-widest text-foreground-muted">
                      {question.type === "sql_challenge" ? "SQL Challenge" : "IHK Frage"}
                    </p>
                    <h4 className="mt-2 max-w-3xl font-serif text-lg font-semibold leading-snug tracking-[-0.015em] text-foreground sm:text-xl">
                      {question.prompt}
                    </h4>
                    <QuestionBlueprintAfterPrompt question={question} />
                  </div>

                  {phase === "pick" ? (
                    <div>
                      <p className="mb-2 font-mono text-[10px] uppercase tracking-[0.2em] text-magenta/90">Antwort wählen</p>
                      <div className="flex flex-col">
                        {question.options.map((opt, idx) => {
                          const isLast = idx === question.options.length - 1;
                          return (
                            <motion.button
                              key={idx}
                              type="button"
                              whileTap={dockTap}
                              transition={springHeavy}
                              onClick={() => handleOption(idx)}
                              className={cn(
                                "w-full border-0 bg-transparent px-0 py-3.5 text-left font-sans text-sm text-foreground transition-colors duration-500 hover-breathe hover:bg-white/[0.04]",
                                !isLast && "border-b border-white/[0.1]",
                              )}
                            >
                              <span className="font-mono text-[10px] uppercase tracking-wider text-foreground-muted">
                                {question.type === "sql_challenge" ? `Query ${idx + 1}` : `Option ${idx + 1}`}
                              </span>
                              <p className="mt-1 max-h-28 overflow-auto leading-snug">{opt}</p>
                            </motion.button>
                          );
                        })}
                      </div>
                    </div>
                  ) : (
                    <div className="space-y-4">
                      <AnalysisReportBlock>{analysisBody}</AnalysisReportBlock>
                      <motion.button
                        type="button"
                        whileTap={dockTap}
                        transition={springHeavy}
                        disabled={!analysisGate}
                        onClick={handleContinue}
                        className={cn(
                          "w-full border px-4 py-3 font-mono text-[10px] font-bold uppercase tracking-[0.22em] transition-colors",
                          analysisGate
                            ? "border-amber-400/45 bg-amber-500/15 text-amber-100 hover:bg-amber-500/25"
                            : "cursor-not-allowed border-white/[0.08] text-foreground-muted opacity-40",
                        )}
                      >
                        {picked === question.correctIndex ? "Ticket abschließen" : "Antwort erneut wählen"}
                      </motion.button>
                    </div>
                  )}
                </div>
              ) : (
                <div className="space-y-2 border border-signal/30 bg-signal/[0.06] px-3 py-4 font-mono text-[11px] uppercase tracking-[0.14em] text-signal/95">
                  <p>Kein Fragen-Eintrag für diesen Slug im Archiv</p>
                  <p className="text-[10px] tracking-[0.2em] text-foreground-muted">Uplink beenden und Slug prüfen</p>
                </div>
              )}
            </div>

            <div className="relative border-t border-white/[0.08] px-4 py-2 font-mono text-[9px] uppercase tracking-[0.24em] text-foreground-muted">
              Handshake aktiv und IHK Katalog gebunden
            </div>
          </motion.aside>
        </>
      ) : null}
    </AnimatePresence>
  );
}
