import { motion, useReducedMotion } from "framer-motion";
import { SYNDICATE_TECH_NODES, type SyndicateTechNodeId } from "../../data/techTreeNodes";

type Props = {
  unlockedNodeIds: SyndicateTechNodeId[];
  vaultXp: number;
  myRole: "founder" | "officer" | "member";
  unlockBusyId: SyndicateTechNodeId | null;
  onUnlock: (nodeId: SyndicateTechNodeId) => void;
};

export function TechGridMap({ unlockedNodeIds, vaultXp, myRole, unlockBusyId, onUnlock }: Props) {
  const prefersReduced = !!useReducedMotion();
  const unlocked = new Set(unlockedNodeIds);
  const canInvest = myRole === "founder";
  const nodeById = new Map(SYNDICATE_TECH_NODES.map((node) => [node.id, node]));
  const links = SYNDICATE_TECH_NODES.flatMap((node) =>
    node.requires.map((reqId) => {
      const from = nodeById.get(reqId);
      if (!from) return null;
      return { from, to: node };
    }),
  ).filter((row): row is { from: (typeof SYNDICATE_TECH_NODES)[number]; to: (typeof SYNDICATE_TECH_NODES)[number] } => !!row);

  return (
    <div className="relative overflow-hidden border border-cyan-300/25 bg-black/35 p-3">
      <div className="pointer-events-none absolute inset-0 hud-grid opacity-[0.06]" aria-hidden />
      <div className="pointer-events-none absolute inset-0 noise-overlay opacity-[0.14]" aria-hidden />
      <p className="relative mb-2 font-mono text-[9px] uppercase tracking-[0.16em] text-cyan-100/88">
        Neural Grid Invest Link {canInvest ? "Lead Access" : "Read Only"} Vault {vaultXp}
      </p>
      <div className="relative h-[330px]">
        <svg viewBox="0 0 100 70" className="absolute inset-0 h-full w-full" aria-hidden>
          {links.map((line) => {
            const active = unlocked.has(line.from.id) && unlocked.has(line.to.id);
            return (
              <motion.line
                key={`${line.from.id}-${line.to.id}`}
                x1={line.from.pos.x}
                y1={line.from.pos.y}
                x2={line.to.pos.x}
                y2={line.to.pos.y}
                stroke={active ? "rgba(34,211,238,0.95)" : "rgba(148,163,184,0.4)"}
                strokeWidth={active ? 1.3 : 0.8}
                strokeDasharray={active ? "0" : "1.2 1"}
                animate={
                  active && !prefersReduced
                    ? { opacity: [0.45, 1, 0.55] }
                    : { opacity: 0.75 }
                }
                transition={prefersReduced ? { duration: 0 } : { duration: 0.9, repeat: Infinity, ease: "linear" }}
              />
            );
          })}
        </svg>

        {SYNDICATE_TECH_NODES.map((node) => {
          const isUnlocked = unlocked.has(node.id);
          const prereqDone = node.requires.every((id) => unlocked.has(id));
          const affordable = vaultXp >= node.costXp;
          const canUnlock = canInvest && !isUnlocked && prereqDone && affordable;
          const busy = unlockBusyId === node.id;
          const branchClass =
            node.branch === "OFFENSIVE"
              ? "border-orange-300/45 bg-orange-500/[0.16] text-orange-100"
              : node.branch === "DEFENSIVE"
              ? "border-cyan-300/45 bg-cyan-500/[0.16] text-cyan-100"
              : "border-lime-300/45 bg-lime-500/[0.16] text-lime-100";
          return (
            <motion.button
              key={node.id}
              type="button"
              disabled={!canUnlock || busy}
              onClick={() => onUnlock(node.id)}
              className={[
                "absolute -translate-x-1/2 -translate-y-1/2 border px-2 py-1 text-left font-mono text-[8px] uppercase tracking-[0.12em]",
                isUnlocked
                  ? "border-emerald-300/55 bg-emerald-500/[0.24] text-emerald-100"
                  : canUnlock
                  ? branchClass
                  : "border-slate-400/35 bg-slate-700/[0.2] text-slate-200/80",
              ].join(" ")}
              style={{ left: `${node.pos.x}%`, top: `${(node.pos.y / 70) * 100}%` }}
              animate={
                isUnlocked && !prefersReduced
                  ? { boxShadow: ["0 0 0 rgba(16,185,129,0.1)", "0 0 12px rgba(16,185,129,0.45)", "0 0 0 rgba(16,185,129,0.1)"] }
                  : undefined
              }
              transition={prefersReduced ? { duration: 0 } : { duration: 1, repeat: Infinity, ease: "linear" }}
            >
              <span className="block font-bold">{node.label}</span>
              <span className="mt-0.5 block opacity-90">{node.short}</span>
              <span className="mt-0.5 block opacity-80">{isUnlocked ? "Online" : busy ? "Linking" : `Cost ${node.costXp}`}</span>
            </motion.button>
          );
        })}
      </div>
    </div>
  );
}
