import { motion, useReducedMotion } from "framer-motion";
import { useEffect, useMemo, useState } from "react";
import type { QuestionModule } from "../../data/questionSchema";
import type { CouncilPowerRow, CouncilProposal } from "../../lib/syncController";
import { useAppStore } from "../../store/useAppStore";

const MODULES: QuestionModule[] = [
  "networking",
  "security",
  "operating_systems",
  "hardware",
  "programming",
  "databases",
  "testing",
  "architecture",
  "process",
  "wiso",
];

export function CouncilChamber() {
  const prefersReduced = !!useReducedMotion();
  const [busy, setBusy] = useState(false);
  const [proposals, setProposals] = useState<CouncilProposal[]>([]);
  const [powerRows, setPowerRows] = useState<CouncilPowerRow[]>([]);
  const [proposalBusy, setProposalBusy] = useState(false);
  const [voteBusyId, setVoteBusyId] = useState<string | null>(null);
  const [titleDraft, setTitleDraft] = useState("XP BOOST FUR NETZWERKTECHNIK");
  const [moduleDraft, setModuleDraft] = useState<QuestionModule>("networking");
  const [xpBoostDraft, setXpBoostDraft] = useState(1.12);
  const [dropDraft, setDropDraft] = useState(0.08);
  const [errorLine, setErrorLine] = useState<string | null>(null);
  const runtime = useAppStore((s) => s.councilRuntime);
  const syndicateRole = useAppStore((s) => s.syndicateRuntimeBuffs.role);
  const canGovern = syndicateRole === "founder";

  const refresh = () => {
    setBusy(true);
    setErrorLine(null);
    void import("../../lib/syncController")
      .then((m) => Promise.all([m.fetchCouncilChamberState(), m.refreshCouncilRuntimeOverride()]))
      .then(([snapshot]) => {
        setProposals(snapshot.proposals);
        setPowerRows(snapshot.power);
      })
      .catch(() => setErrorLine("Council uplink blockiert"))
      .finally(() => setBusy(false));
  };

  useEffect(() => {
    refresh();
  }, []);

  const activeCount = useMemo(() => proposals.filter((p) => p.status === "active").length, [proposals]);

  return (
    <section className="relative overflow-hidden rounded-3xl border border-amber-300/40 bg-gradient-to-br from-black via-amber-900/[0.18] to-black p-6 ring-1 ring-amber-200/22">
      <div className="pointer-events-none absolute inset-0 hud-grid opacity-[0.06]" aria-hidden />
      <div className="pointer-events-none absolute inset-0 noise-overlay opacity-[0.14]" aria-hidden />
      <div className="relative space-y-4">
        <div className="flex flex-wrap items-end justify-between gap-3">
          <div className="space-y-1">
            <p className="font-mono text-[10px] font-semibold uppercase tracking-[0.32em] text-amber-200/90">
              Neural Council
            </p>
            <h3 className="font-display text-2xl font-bold uppercase tracking-wide text-amber-50">Council Chamber</h3>
          </div>
          <span className="border border-amber-300/35 bg-amber-500/[0.16] px-3 py-1 font-mono text-[9px] uppercase tracking-[0.14em] text-amber-100">
            Active Motions {activeCount}
          </span>
        </div>

        {runtime.active ? (
          <motion.div
            initial={prefersReduced ? false : { opacity: 0.65, y: -2 }}
            animate={prefersReduced ? { opacity: 1, y: 0 } : { opacity: [0.64, 1, 0.72], x: [0, -1, 1, 0] }}
            transition={prefersReduced ? { duration: 0 } : { duration: 0.72, repeat: Infinity, ease: "linear" }}
            className="border border-amber-300/50 bg-amber-500/[0.14] px-3 py-2"
          >
            <p className="font-mono text-[9px] font-bold uppercase tracking-[0.16em] text-amber-100">
              DECREE LIVE {runtime.label || "COUNCIL OVERRIDE"}
            </p>
            <p className="mt-1 font-mono text-[8px] uppercase tracking-[0.14em] text-amber-100/88">
              Module {runtime.targetModule ?? "none"} XP x{runtime.xpBoostMultiplier.toFixed(2)} Drop +{Math.round(runtime.dropScaleDelta * 100)}%
            </p>
          </motion.div>
        ) : null}

        <div className="grid gap-3 lg:grid-cols-[1.2fr_1fr]">
          <div className="space-y-2">
            {busy ? (
              <p className="font-mono text-[10px] uppercase tracking-[0.14em] text-amber-100/84">Council sync läuft</p>
            ) : proposals.length === 0 ? (
              <p className="font-mono text-[10px] uppercase tracking-[0.14em] text-amber-100/84">Keine aktiven motions</p>
            ) : (
              proposals.map((proposal) => {
                const total = Math.max(1, proposal.supportWeight + proposal.rejectWeight);
                const supportPct = Math.round((proposal.supportWeight / total) * 100);
                const rejectPct = 100 - supportPct;
                return (
                  <article key={proposal.id} className="border border-amber-200/25 bg-black/35 p-3">
                    <div className="flex flex-wrap items-center justify-between gap-2">
                      <p className="font-mono text-[9px] font-semibold uppercase tracking-[0.15em] text-amber-50">
                        {proposal.title}
                      </p>
                      <span className="border border-amber-300/35 bg-amber-500/[0.14] px-1.5 py-0.5 font-mono text-[8px] uppercase tracking-[0.14em] text-amber-100">
                        {proposal.status}
                      </span>
                    </div>
                    <p className="mt-1 font-mono text-[8px] uppercase tracking-[0.14em] text-amber-100/86">
                      {proposal.proposerSyndicateName} Modul {proposal.targetModule} XP x{proposal.xpBoostMultiplier.toFixed(2)} Drop +{Math.round(proposal.dropScaleDelta * 100)}%
                    </p>
                    <div className="mt-2 h-2 overflow-hidden border border-amber-200/25 bg-black/60">
                      <div className="flex h-full">
                        <div className="bg-emerald-400/75" style={{ width: `${supportPct}%` }} />
                        <div className="bg-rose-400/75" style={{ width: `${rejectPct}%` }} />
                      </div>
                    </div>
                    <p className="mt-1 font-mono text-[8px] uppercase tracking-[0.14em] text-amber-100/82">
                      Support {proposal.supportWeight} Reject {proposal.rejectWeight} MyVote {proposal.myVote ?? "none"}
                    </p>
                    {proposal.status === "active" ? (
                      <div className="mt-2 flex gap-2">
                        <button
                          type="button"
                          disabled={!canGovern || voteBusyId === proposal.id}
                          onClick={() => {
                            setVoteBusyId(proposal.id);
                            setErrorLine(null);
                            void import("../../lib/syncController")
                              .then((m) => m.castCouncilVote(proposal.id, "support"))
                              .then((res) => {
                                if (!res.ok) {
                                  setErrorLine(res.error ?? "Vote support blockiert");
                                  return;
                                }
                                refresh();
                              })
                              .finally(() => setVoteBusyId(null));
                          }}
                          className="border border-emerald-300/45 bg-emerald-500/[0.2] px-2 py-1 font-mono text-[8px] uppercase tracking-[0.13em] text-emerald-100 hover:bg-emerald-500/[0.3] disabled:opacity-45"
                        >
                          Support
                        </button>
                        <button
                          type="button"
                          disabled={!canGovern || voteBusyId === proposal.id}
                          onClick={() => {
                            setVoteBusyId(proposal.id);
                            setErrorLine(null);
                            void import("../../lib/syncController")
                              .then((m) => m.castCouncilVote(proposal.id, "reject"))
                              .then((res) => {
                                if (!res.ok) {
                                  setErrorLine(res.error ?? "Vote reject blockiert");
                                  return;
                                }
                                refresh();
                              })
                              .finally(() => setVoteBusyId(null));
                          }}
                          className="border border-rose-300/45 bg-rose-500/[0.2] px-2 py-1 font-mono text-[8px] uppercase tracking-[0.13em] text-rose-100 hover:bg-rose-500/[0.3] disabled:opacity-45"
                        >
                          Reject
                        </button>
                      </div>
                    ) : null}
                  </article>
                );
              })
            )}
          </div>

          <div className="space-y-3">
            <div className="border border-amber-200/24 bg-black/35 p-3">
              <p className="font-mono text-[9px] uppercase tracking-[0.16em] text-amber-100/92">Power Matrix</p>
              <div className="mt-2 space-y-1">
                {powerRows.length === 0 ? (
                  <p className="font-mono text-[8px] uppercase tracking-[0.14em] text-amber-100/70">Keine Ratssitze aktiv</p>
                ) : (
                  powerRows.map((row, idx) => (
                    <div key={`${row.syndicateId}-${idx}`} className="flex items-center justify-between border border-amber-300/20 bg-black/30 px-2 py-1">
                      <span className="truncate font-mono text-[8px] uppercase tracking-[0.14em] text-amber-100/88">
                        {row.syndicateName}
                      </span>
                      <span className="font-mono text-[8px] uppercase tracking-[0.14em] text-amber-100">
                        Sectors {row.sectors}
                      </span>
                    </div>
                  ))
                )}
              </div>
            </div>

            <div className="border border-amber-200/24 bg-black/35 p-3">
              <p className="font-mono text-[9px] uppercase tracking-[0.16em] text-amber-100/92">Neue Motion</p>
              <div className="mt-2 space-y-2">
                <input
                  value={titleDraft}
                  onChange={(event) => setTitleDraft(event.target.value)}
                  className="w-full border border-amber-300/30 bg-black/50 px-2 py-1.5 font-mono text-[9px] uppercase tracking-[0.12em] text-amber-50 outline-none"
                  placeholder="Council Motion"
                />
                <select
                  value={moduleDraft}
                  onChange={(event) => setModuleDraft(event.target.value as QuestionModule)}
                  className="w-full border border-amber-300/30 bg-black/50 px-2 py-1.5 font-mono text-[9px] uppercase tracking-[0.12em] text-amber-50 outline-none"
                >
                  {MODULES.map((module) => (
                    <option key={module} value={module}>
                      {module}
                    </option>
                  ))}
                </select>
                <div className="grid grid-cols-2 gap-2">
                  <input
                    type="number"
                    min={1}
                    max={2}
                    step={0.01}
                    value={xpBoostDraft}
                    onChange={(event) => setXpBoostDraft(Number(event.target.value))}
                    className="w-full border border-amber-300/30 bg-black/50 px-2 py-1.5 font-mono text-[9px] uppercase tracking-[0.12em] text-amber-50 outline-none"
                  />
                  <input
                    type="number"
                    min={0}
                    max={1}
                    step={0.01}
                    value={dropDraft}
                    onChange={(event) => setDropDraft(Number(event.target.value))}
                    className="w-full border border-amber-300/30 bg-black/50 px-2 py-1.5 font-mono text-[9px] uppercase tracking-[0.12em] text-amber-50 outline-none"
                  />
                </div>
                <button
                  type="button"
                  disabled={!canGovern || proposalBusy}
                  onClick={() => {
                    setProposalBusy(true);
                    setErrorLine(null);
                    void import("../../lib/syncController")
                      .then((m) =>
                        m.submitCouncilProposal({
                          title: titleDraft,
                          targetModule: moduleDraft,
                          xpBoostMultiplier: xpBoostDraft,
                          dropScaleDelta: dropDraft,
                        }),
                      )
                      .then((res) => {
                        if (!res.ok) {
                          setErrorLine(res.error ?? "Motion blockiert");
                          return;
                        }
                        refresh();
                      })
                      .finally(() => setProposalBusy(false));
                  }}
                  className="border border-amber-300/45 bg-amber-500/[0.2] px-3 py-1.5 font-mono text-[8px] font-bold uppercase tracking-[0.14em] text-amber-100 hover:bg-amber-500/[0.3] disabled:opacity-45"
                >
                  {proposalBusy ? "Broadcast" : "Submit Motion"}
                </button>
                {!canGovern ? (
                  <p className="font-mono text-[8px] uppercase tracking-[0.14em] text-amber-100/76">
                    Nur Syndicate Leads mit Sektorbesitz sind stimmberechtigt
                  </p>
                ) : null}
              </div>
            </div>
          </div>
        </div>

        {errorLine ? <p className="font-mono text-[9px] uppercase tracking-[0.14em] text-rose-200">{errorLine}</p> : null}
      </div>
    </section>
  );
}
