import { AnimatePresence, motion, useReducedMotion } from "framer-motion";
import { useEffect, useRef, useState } from "react";
import { CodeSnapLogo } from "./components/brand/CodeSnapLogo";
import { CloudAuthView } from "./components/cloud/CloudAuthView";
import { CloudSyncLed } from "./components/cloud/CloudSyncLed";
import { AppShell } from "./components/layout/AppShell";
import { springHeavy } from "./motion/variants";
import { MedalAwardHost } from "./components/achievements/MedalAwardHost";
import { LinkHeartbeatChip } from "./components/system/LinkHeartbeatChip";
import { GlobalLiveEventRibbon } from "./components/system/GlobalLiveEventRibbon";
import { SystemPatchOverlay } from "./components/system/SystemPatchOverlay";
import { parseChallengeSlug } from "./lib/challengeSlug";
import { useAppStore } from "./store/useAppStore";

const HYDRAULIC_ROWS = 4;
const SEGMENTS_PER_ROW = 22;

function HydraulicLockRow({
  rowIndex,
  prefersReduced,
}: {
  rowIndex: number;
  prefersReduced: boolean;
}) {
  const reduced = prefersReduced;
  const baseDelay = reduced ? 0 : 0.04 + rowIndex * 0.07;
  return (
    <div
      className="absolute left-[4%] right-[4%] flex justify-between gap-px"
      style={{ top: `${22 + rowIndex * 17}%` }}
      aria-hidden
    >
      {Array.from({ length: SEGMENTS_PER_ROW }).map((_, seg) => {
        const stagger = reduced ? seg * 0.008 : seg * 0.012 + (rowIndex % 2) * 0.006;
        return (
          <motion.div
            key={seg}
            className="h-px min-w-0 flex-1 origin-center bg-gradient-to-r from-white/[0.22] via-white/[0.14] to-white/[0.22]"
            initial={{ scaleX: 1, opacity: 0.92 }}
            animate={{ scaleX: 0.04, opacity: 0 }}
            transition={
              reduced
                ? { duration: 0.14, ease: [0.22, 1, 0.36, 1] as const, delay: baseDelay + stagger }
                : {
                    type: "spring",
                    stiffness: 320,
                    damping: 22,
                    mass: 0.55,
                    delay: baseDelay + stagger,
                  }
            }
          />
        );
      })}
    </div>
  );
}

function AccessGrantedGate({ open }: { open: boolean }) {
  const prefersReduced = !!useReducedMotion();
  const leftSlide = prefersReduced
    ? ({ duration: 0.2, ease: [0.22, 1, 0.36, 1] as const } as const)
    : ({ ...springHeavy, mass: 1.05, damping: 28 } as const);
  const rightSlide = prefersReduced
    ? ({ duration: 0.2, ease: [0.22, 1, 0.36, 1] as const } as const)
    : ({ ...springHeavy, mass: 0.92, damping: 32 } as const);

  return (
    <AnimatePresence>
      {open ? (
        <motion.div
          key="gateway-door"
          className="pointer-events-none fixed inset-0 z-[460] overflow-hidden bg-[#030303]"
          initial={{ opacity: 1 }}
          animate={{ opacity: 1 }}
          exit={{ opacity: 0 }}
          transition={{ duration: prefersReduced ? 0.14 : 0.32 }}
        >
          <div className="absolute inset-0 hud-grid opacity-[0.08]" />

          {/* Phase 38.5 — entry scanline pulse */}
          <motion.div
            className="pointer-events-none absolute inset-x-0 z-30 h-[2px] bg-[linear-gradient(90deg,transparent_0%,rgb(255_255_255_/_0.85)_50%,transparent_100%)] shadow-[0_0_24px_rgb(255_255_255_/_0.35)]"
            initial={{ top: "-2%", opacity: 0 }}
            animate={{
              top: prefersReduced ? "48%" : ["0%", "52%", "100%"],
              opacity: prefersReduced ? [0, 0.9, 0] : [0, 1, 0.95, 0.75, 0],
            }}
            transition={{
              duration: prefersReduced ? 0.18 : 0.58,
              ease: prefersReduced ? "easeOut" : "easeInOut",
              times: prefersReduced ? undefined : [0, 0.12, 0.38, 0.78, 1],
            }}
          />

          {Array.from({ length: HYDRAULIC_ROWS }).map((_, row) => (
            <HydraulicLockRow key={row} rowIndex={row} prefersReduced={prefersReduced} />
          ))}

          <motion.div
            className="absolute inset-y-0 left-0 w-1/2 border-r border-white/[0.12] bg-[#030303]"
            initial={{ x: 0 }}
            animate={{ x: prefersReduced ? "-100%" : "-118%" }}
            transition={leftSlide}
          />
          <motion.div
            className="absolute inset-y-0 right-0 w-1/2 border-l border-white/[0.12] bg-[#030303]"
            initial={{ x: 0 }}
            animate={{ x: prefersReduced ? "100%" : "118%" }}
            transition={rightSlide}
          />

          <motion.div
            className="absolute inset-x-0 top-0 h-[14vh] bg-gradient-to-b from-white/20 via-white/8 to-transparent"
            initial={{ y: "-18%", opacity: 0 }}
            animate={{ y: "118%", opacity: [0, 0.82, 0] }}
            transition={{
              duration: prefersReduced ? 0.24 : 0.78,
              ease: "easeInOut",
              delay: prefersReduced ? 0.05 : 0.22,
            }}
          />
          <motion.div
            className="absolute inset-0 flex items-center justify-center"
            initial={{ opacity: 0 }}
            animate={{ opacity: [0, 1, 0] }}
            transition={{ duration: prefersReduced ? 0.22 : 0.68, ease: "easeInOut", delay: prefersReduced ? 0 : 0.08 }}
          >
            <div className="border border-white/[0.12] bg-white/[0.03] px-8 py-6 text-center ring-1 ring-white/[0.06]">
              <p className="font-mono text-[10px] uppercase tracking-[0.36em] text-foreground-muted">
                Sovereign Gateway
              </p>
              <h2 className="mt-3 headline-cinema text-4xl font-semibold sm:text-6xl">
                ACCESS GRANTED
              </h2>
            </div>
          </motion.div>
        </motion.div>
      ) : null}
    </AnimatePresence>
  );
}

export default function App() {
  const prefersReduced = !!useReducedMotion();
  const syncStatus = useAppStore((s) => s.syncStatus);
  const cloudUplinkBusy = useAppStore((s) => s.cloudUplinkBusy);
  const cloudAuthPending = useAppStore((s) => s.cloudAuthPending);
  const authReady = useAppStore((s) => s.authReady);
  const authUser = useAppStore((s) => s.authUser);
  const onboardingCompleted = useAppStore((s) => s.onboardingCompleted);
  const hasBooted = useAppStore((s) => s.hasBooted);
  const activeSection = useAppStore((s) => s.activeSection);
  const startMockExamChallenge = useAppStore((s) => s.startMockExamChallenge);
  const prevDashboardRef = useRef(false);
  const [doorOpen, setDoorOpen] = useState(false);

  const gatewayResolved = !hasBooted || authReady;
  const showDashboard = gatewayResolved && !!authUser && onboardingCompleted;
  const showLockdown = gatewayResolved && !!authUser && !onboardingCompleted;

  useEffect(() => {
    const movedIntoDashboard = showDashboard && !prevDashboardRef.current;
    prevDashboardRef.current = showDashboard;
    if (!movedIntoDashboard) return;
    setDoorOpen(true);
    const timer = window.setTimeout(() => setDoorOpen(false), prefersReduced ? 720 : 1180);
    return () => window.clearTimeout(timer);
  }, [showDashboard, prefersReduced]);

  useEffect(() => {
    if (!showDashboard) return;
    let offPulse: () => void = () => {};
    let offFaction: () => void = () => {};
    let offActivity: () => void = () => {};
    let offOverdrive: () => void = () => {};
    let offLore: () => void = () => {};
    let offOutbreak: () => void = () => {};
    let offSector: () => void = () => {};
    let offCouncil: () => void = () => {};
    void import("./lib/syncController").then((m) => {
      offPulse = m.subscribeSystemPulseIngest();
      offFaction = m.subscribeFactionXpWarTotals();
      offActivity = m.subscribeNexusActivityBus();
      offOverdrive = m.startGlobalOverdriveController();
      offLore = m.startGlobalLoreWatcher();
      offOutbreak = m.startGlobalOutbreakWatcher();
      offSector = m.startGlobalSectorDominanceWatcher();
      offCouncil = m.startGlobalCouncilWatcher();
    });
    return () => {
      offPulse();
      offFaction();
      offActivity();
      offOverdrive();
      offLore();
      offOutbreak();
      offSector();
      offCouncil();
    };
  }, [showDashboard]);

  useEffect(() => {
    if (!showDashboard) return;
    const url = new URL(window.location.href);
    const raw = url.searchParams.get("challenge");
    if (!raw) return;
    const parsed = parseChallengeSlug(raw);
    if (!parsed) return;
    startMockExamChallenge({
      ids: parsed.ids,
      by: parsed.by,
      elapsedMs: parsed.elapsedMs,
      percent: parsed.percent,
    });
    url.searchParams.delete("challenge");
    window.history.replaceState({}, "", `${url.pathname}${url.search}${url.hash}`);
  }, [showDashboard, startMockExamChallenge]);

  return (
    <>
      <AppShell
        mode={showDashboard ? "dashboard" : showLockdown ? "lockdown" : "gateway"}
        content={showDashboard ? undefined : showLockdown ? <div className="min-h-dvh bg-[#030303]" /> : <CloudAuthView gatewayMode />}
        header={
          <div className="flex w-full flex-wrap items-center justify-between gap-3 sm:flex-nowrap sm:gap-4">
            <div className="flex min-w-0 shrink-0 items-center gap-3 sm:gap-4">
              <motion.div
                layout
                className="flex shrink-0 items-center"
                whileHover={{
                  scale: 1.01,
                  transition: { type: "spring", stiffness: 200, damping: 40, mass: 0.85 },
                }}
              >
                <CodeSnapLogo heightClass="h-10 sm:h-11" className="opacity-[0.98]" />
              </motion.div>
              <div className="min-w-0">
                <span className="sr-only">CodeSnap</span>
                <p className="font-sans text-xs tracking-[-0.02em] text-foreground-muted sm:text-sm">
                  Cinematic operator stack · offline first
                </p>
              </div>
            </div>
            <div className="flex min-w-0 flex-1 justify-center px-1">
              {activeSection === "mockExam" ? (
                <div className="border border-white/[0.12] bg-white/[0.04] px-3 py-1.5 font-mono text-[10px] font-semibold uppercase tracking-[0.24em] text-foreground">
                  IHK Mock Exam
                </div>
              ) : (
                <GlobalLiveEventRibbon />
              )}
            </div>
            <div className="flex shrink-0 items-center gap-2 sm:gap-3">
              {activeSection === "mockExam" ? null : (
                <>
                  <CloudSyncLed syncStatus={syncStatus} busy={cloudUplinkBusy || cloudAuthPending} />
                  <LinkHeartbeatChip />
                </>
              )}
            </div>
          </div>
        }
      />
      <MedalAwardHost />
      <SystemPatchOverlay />
      <AccessGrantedGate open={doorOpen} />
    </>
  );
}
