import { motion, useReducedMotion } from "framer-motion";
import { cn } from "../../lib/cn";

export type SignalLineTrackProps = {
  /** 0–100 optional fill behind the sweep */
  progress?: number;
  className?: string;
  /** viewport = volle Breite wie Top-Bar, inline = schmaler Container */
  scope?: "viewport" | "inline";
};

/** Schmale Uplink-Linie — gleiche Physik wie SupabaseActivityBar */
export function SignalLineTrack({
  progress,
  className,
  scope = "inline",
}: SignalLineTrackProps) {
  const prefersReduced = useReducedMotion();
  const pct =
    typeof progress === "number" ? Math.min(100, Math.max(0, progress)) : undefined;

  const sweepMotion =
    scope === "viewport"
      ? {
          initial: { x: "-100%" as const },
          animate: { x: "calc(100vw + 100%)" as const },
          transition: { duration: 1.45, repeat: Infinity, ease: "linear" as const },
        }
      : {
          initial: { x: "-100%" as const },
          animate: { x: "360%" as const },
          transition: { duration: 1.45, repeat: Infinity, ease: "linear" as const },
        };

  return (
    <div
      className={cn("relative h-[2px] w-full overflow-hidden bg-white/[0.06]", className)}
      aria-hidden
    >
      {pct != null ? (
        <div
          className="absolute inset-y-0 left-0 z-[1] bg-signal/30"
          style={{ width: `${pct}%` }}
        />
      ) : null}
      {prefersReduced ? (
        pct != null ? (
          <div
            className="absolute inset-y-0 left-0 z-[2] h-full bg-signal/70"
            style={{ width: `${pct}%` }}
          />
        ) : (
          <div className="absolute inset-0 z-[2] h-full w-full bg-signal/70" />
        )
      ) : (
        <motion.div
          className="absolute inset-y-0 top-0 z-[2] w-[min(38%,220px)] bg-gradient-to-r from-transparent via-signal/95 to-transparent"
          initial={sweepMotion.initial}
          animate={sweepMotion.animate}
          transition={sweepMotion.transition}
        />
      )}
    </div>
  );
}
