import { useCallback, useEffect, useState } from "react";
import {
  fetchAdminCmdTelemetry,
  type AdminCmdPainRow,
  type AdminCmdTelemetrySnapshot,
} from "../lib/syncController";
import { useAppStore } from "../store/useAppStore";

const POLL_MS = 30_000;

const EMPTY: AdminCmdTelemetrySnapshot = {
  activeOperators: 0,
  painPoints: [],
  factionFisiXp: 0,
  factionFiaeXp: 0,
};

/**
 * Phase 62 — Overseer: Supabase-RPCs für aktive Operatoren Top-Misses und Fraktions-Summen
 */
export function useAdminTelemetry(): {
  loading: boolean;
  activeOperators: number;
  painPoints: AdminCmdPainRow[];
  factionFisiXp: number;
  factionFiaeXp: number;
  refresh: () => Promise<void>;
} {
  const isAdmin = useAppStore((s) => s.isAdmin);
  const [loading, setLoading] = useState(true);
  const [snap, setSnap] = useState<AdminCmdTelemetrySnapshot>(EMPTY);

  const refresh = useCallback(async () => {
    if (!isAdmin) {
      setSnap(EMPTY);
      setLoading(false);
      return;
    }
    setLoading(true);
    const next = await fetchAdminCmdTelemetry();
    setSnap(next);
    setLoading(false);
  }, [isAdmin]);

  useEffect(() => {
    void refresh();
    if (!isAdmin) return undefined;
    const id = window.setInterval(() => void refresh(), POLL_MS);
    return () => window.clearInterval(id);
  }, [refresh, isAdmin]);

  return {
    loading,
    activeOperators: snap.activeOperators,
    painPoints: snap.painPoints,
    factionFisiXp: snap.factionFisiXp,
    factionFiaeXp: snap.factionFiaeXp,
    refresh,
  };
}
