export type SystemPulsePromotionEvent = {
  id: string;
  ts: number;
  kind: "PROMOTION";
  handle: string;
  rankTitle: string;
};

export type SystemPulseMissionEvent = {
  id: string;
  ts: number;
  kind: "MISSION_SOLVED";
  handle: string;
  ticketId: string;
  score?: number;
};

export type SystemPulseStreakEvent = {
  id: string;
  ts: number;
  kind: "STREAK_MILESTONE";
  handle: string;
  days: number;
};

export type SystemPulseFactionShiftEvent = {
  id: string;
  ts: number;
  kind: "FACTION_SHIFT";
  leading: "FISI" | "FIAE" | "TIE";
  fisiPct: number;
  fiaePct: number;
};

export type SystemPulseSystemAnnouncementEvent = {
  id: string;
  ts: number;
  kind: "SYSTEM_ANNOUNCEMENT";
  message: string;
};

/** Phase 52 — globales Live-Event (fett im Pulse-Head) */
export type SystemPulseGlobalLiveEvent = {
  id: string;
  ts: number;
  kind: "GLOBAL_LIVE_EVENT";
  headline: string;
};

export type SystemPulseEvent =
  | SystemPulsePromotionEvent
  | SystemPulseMissionEvent
  | SystemPulseStreakEvent
  | SystemPulseFactionShiftEvent
  | SystemPulseSystemAnnouncementEvent
  | SystemPulseGlobalLiveEvent;

/** Omit auf Union-Gesamttype liefert nur Schnittmenge — daher explizite Draft-Union */
export type SystemPulseEventDraft =
  | Omit<SystemPulsePromotionEvent, "id" | "ts">
  | Omit<SystemPulseMissionEvent, "id" | "ts">
  | Omit<SystemPulseStreakEvent, "id" | "ts">
  | Omit<SystemPulseFactionShiftEvent, "id" | "ts">
  | Omit<SystemPulseSystemAnnouncementEvent, "id" | "ts">
  | Omit<SystemPulseGlobalLiveEvent, "id" | "ts">;

export function formatPulseTickerLine(e: SystemPulseEvent): string {
  switch (e.kind) {
    case "PROMOTION": {
      const H = e.handle.toUpperCase();
      const R = e.rankTitle.toUpperCase().replace(/\s+/g, "_");
      return `UPLINK: ${H} REACHED ${R}`;
    }
    case "MISSION_SOLVED": {
      const H = e.handle.toUpperCase();
      const T = e.ticketId.toUpperCase().replace(/\s+/g, "_");
      const band = typeof e.score === "number" ? ` BAND ${e.score}` : "";
      return `UPLINK: ${H} MISSION_SOLVED TICKET ${T}${band}`;
    }
    case "STREAK_MILESTONE": {
      const H = e.handle.toUpperCase();
      return `UPLINK: ${H} STREAK_LOCK ${e.days}D_GRID`;
    }
    case "SYSTEM_ANNOUNCEMENT":
      return `SYSWIDE: ${e.message}`;
    case "GLOBAL_LIVE_EVENT":
      return e.headline;
    case "FACTION_SHIFT": {
      const L = e.leading;
      return `NETSHIFT: ${L} EDGE FISI_${e.fisiPct.toFixed(1)} FIAE_${e.fiaePct.toFixed(1)}`;
    }
    default: {
      const _exhaustive: never = e;
      return _exhaustive;
    }
  }
}

export function obfuscatePulseGlyph(seed: number): string {
  const charset = "0123456789ABCDEF//::";
  let s = "";
  for (let i = 0; i < 96; i += 1) {
    s += charset[(seed + i * 17) % charset.length]!;
  }
  return s;
}
