import { useEffect, useMemo } from "react";
import {
  getPwaThemeColorHexForTerminalThemeId,
  normalizeTerminalThemeId,
} from "../data/terminalThemes";
import { computeLifetimeXp } from "../lib/xpCurve";
import { useAppStore } from "../store/useAppStore";

let cachedMeta: HTMLMetaElement | null = null;

function getThemeColorMeta(): HTMLMetaElement | null {
  if (typeof document === "undefined") return null;
  if (cachedMeta?.isConnected) return cachedMeta;
  cachedMeta = document.querySelector('meta[name="theme-color"]');
  return cachedMeta;
}

/**
 * Phase 60 — PWA Symbiosis: meta theme-color folgt dem aktiven Rig-Theme
 * Fallback bleibt index.html bis dieser Effect läuft
 */
export function usePwaThemeColor(): void {
  const userLevel = useAppStore((s) => s.userLevel);
  const globalXP = useAppStore((s) => s.globalXP);
  const rigTerminalThemeId = useAppStore((s) => s.rigTerminalThemeId);

  const themeId = useMemo(() => {
    const life = computeLifetimeXp(userLevel, globalXP);
    return normalizeTerminalThemeId(rigTerminalThemeId, life);
  }, [userLevel, globalXP, rigTerminalThemeId]);

  const hex = useMemo(() => getPwaThemeColorHexForTerminalThemeId(themeId), [themeId]);

  useEffect(() => {
    const meta = getThemeColorMeta();
    if (!meta) return;
    meta.setAttribute("content", hex);
  }, [hex]);
}
