import { AnimatePresence, motion, type Variants } from "framer-motion";
import { useEffect, useState } from "react";
import { IconArrowLeft } from "../icons/ThinLineIcons";
import { cn } from "../../lib/cn";
import { itemReveal, staggerContainer } from "../../motion/variants";
import { useAppStore, type NexusViewId } from "../../store/useAppStore";
import { ArcadeHub } from "./ArcadeHub";
import { FactionSelect } from "./FactionSelect";
import { TechTreeMap } from "./TechTreeMap";
import { RealmQuestBoard } from "../realm/RealmQuestBoard";
import { SqlMissionList } from "../sql/SqlMissionList";
import { SqlSandboxTerminal } from "../sql/SqlSandboxTerminal";
import { PseudoCodeTrainer } from "../pseudo/PseudoCodeTrainer";
import { HelpdeskTerminalView } from "../simulator/HelpdeskTerminalView";
import { LoreTerminal } from "./LoreTerminal";
import { BossRankboard } from "./BossRankboard";
import { BountyBoard } from "./BountyBoard";
import { SyndicatePanel } from "./SyndicatePanel";
import { CouncilChamber } from "./CouncilChamber";
import type { SeasonHistoryEntry } from "../../lib/syncController";

const subVariants: Variants = {
  initial: { opacity: 0, y: 12, filter: "blur(6px)" },
  animate: {
    opacity: 1,
    y: 0,
    filter: "blur(0px)",
    transition: { type: "spring", stiffness: 320, damping: 28 },
  },
  exit: {
    opacity: 0,
    y: -8,
    filter: "blur(4px)",
    transition: { duration: 0.2, ease: [0.4, 0, 0.2, 1] },
  },
};

function NexusHub() {
  const openNexusTree = useAppStore((s) => s.openNexusTree);
  const setNexusView = useAppStore((s) => s.setNexusView);
  const [seasonRows, setSeasonRows] = useState<SeasonHistoryEntry[]>([]);
  const [seasonBusy, setSeasonBusy] = useState(false);

  useEffect(() => {
    setSeasonBusy(true);
    void import("../../lib/syncController")
      .then((m) => m.fetchSeasonHistory(3))
      .then((rows) => setSeasonRows(rows))
      .finally(() => setSeasonBusy(false));
  }, []);

  return (
    <motion.div
      variants={staggerContainer}
      initial="initial"
      animate="animate"
      className="space-y-10"
    >
      <motion.div variants={itemReveal} className="space-y-3 text-center sm:text-left">
        <p className="font-sans text-[11px] font-semibold uppercase tracking-[0.35em] text-cyber-cyan">
          The Nexus
        </p>
        <h1 className="font-display text-4xl font-bold uppercase tracking-tight text-foreground sm:text-5xl">
          Zentraler Warp
        </h1>
        <p className="mx-auto max-w-2xl font-sans text-sm text-foreground-muted sm:mx-0 sm:text-base">
          Spring zwischen Fahrplan und Arcade — alles offline, alles instant
        </p>
      </motion.div>
      <motion.div
        variants={itemReveal}
        className="grid grid-cols-1 gap-5 md:grid-cols-2"
      >
        <motion.button
          type="button"
          whileHover={{ y: -4, scale: 1.01 }}
          whileTap={{ scale: 0.98 }}
          onClick={() => openNexusTree()}
          className={cn(
            "relative overflow-hidden rounded-3xl border border-border-glass bg-surface/90 p-8 text-left ring-1 ring-cyber-cyan/20 transition-[border-color,background-color] hover:border-white/[0.14] hover:bg-white/[0.03]",
          )}
        >
          <div className="pointer-events-none absolute inset-0 bg-gradient-to-br from-cyber-cyan/15 to-transparent" />
          <div className="pointer-events-none absolute inset-0 noise-overlay opacity-20" />
          <div className="relative space-y-2">
            <h2 className="font-display text-2xl font-bold uppercase tracking-wide text-cyber-cyan">
              Der Fahrplan
            </h2>
            <p className="font-sans text-sm text-foreground-muted">
              Skill-Tree Map mit leuchtenden Pfaden und harten Locks
            </p>
          </div>
        </motion.button>
        <motion.button
          type="button"
          whileHover={{ y: -4, scale: 1.01 }}
          whileTap={{ scale: 0.98 }}
          onClick={() => setNexusView("arcade")}
          className={cn(
            "relative overflow-hidden rounded-3xl border border-border-glass bg-surface/90 p-8 text-left ring-1 ring-magenta/20 transition-[border-color,background-color] hover:border-magenta/35 hover:bg-white/[0.03]",
          )}
        >
          <div className="pointer-events-none absolute inset-0 bg-gradient-to-br from-magenta/15 to-transparent" />
          <div className="pointer-events-none absolute inset-0 noise-overlay opacity-20" />
          <div className="relative space-y-2">
            <h2 className="font-display text-2xl font-bold uppercase tracking-wide text-magenta">
              Die Arcade
            </h2>
            <p className="font-sans text-sm text-foreground-muted">
              RealmQuest, SQL und Terminal — Parallax und Neon bis zum Anschlag
            </p>
          </div>
        </motion.button>
      </motion.div>
      <motion.section
        variants={itemReveal}
        className="relative overflow-hidden rounded-3xl border border-amber-300/35 bg-gradient-to-br from-amber-500/[0.08] via-slate-300/[0.05] to-amber-500/[0.09] p-6 ring-1 ring-slate-200/10"
      >
        <div className="pointer-events-none absolute inset-0 noise-overlay opacity-20" />
        <div className="relative space-y-4">
          <div className="flex flex-wrap items-end justify-between gap-3">
            <div className="space-y-1">
              <p className="font-mono text-[10px] font-semibold uppercase tracking-[0.3em] text-amber-100/90">
                Legacy Archiv
              </p>
              <h3 className="font-display text-2xl font-bold uppercase tracking-wide text-amber-50">
                Season Relikte
              </h3>
            </div>
            <span className="border border-slate-100/20 bg-slate-200/10 px-3 py-1 font-mono text-[10px] uppercase tracking-[0.18em] text-slate-100/80">
              Saisons {seasonRows.length}
            </span>
          </div>

          {seasonBusy ? (
            <p className="font-mono text-[10px] uppercase tracking-[0.2em] text-foreground-muted">
              Archiv sync läuft
            </p>
          ) : seasonRows.length === 0 ? (
            <p className="font-mono text-[10px] uppercase tracking-[0.2em] text-foreground-muted">
              Noch kein Season Snapshot vorhanden
            </p>
          ) : (
            <div className="grid gap-3 md:grid-cols-3">
              {seasonRows.map((season) => (
                <article
                  key={season.seasonKey}
                  className="border border-slate-200/18 bg-black/35 p-4 shadow-[inset_0_0_24px_rgb(255_255_255_/0.04)]"
                >
                  <p className="font-mono text-[9px] uppercase tracking-[0.2em] text-slate-300/85">
                    {season.seasonLabel}
                  </p>
                  <p className="mt-1 font-mono text-[10px] uppercase tracking-[0.2em] text-amber-200/95">
                    Sieger {season.winnerFaction}
                  </p>
                  <p className="mt-2 truncate font-sans text-sm font-semibold text-foreground">
                    Champion {season.top[0]?.handle ?? "Unknown_Operator"}
                  </p>
                  <p className="mt-1 font-mono text-[10px] uppercase tracking-[0.18em] text-foreground-muted">
                    FISI {season.fisiTotalXp} · FIAE {season.fiaeTotalXp}
                  </p>
                </article>
              ))}
            </div>
          )}
        </div>
      </motion.section>
      <motion.div variants={itemReveal}>
        <BossRankboard />
      </motion.div>
      <motion.div variants={itemReveal}>
        <BountyBoard />
      </motion.div>
      <motion.div variants={itemReveal}>
        <SyndicatePanel />
      </motion.div>
      <motion.div variants={itemReveal}>
        <CouncilChamber />
      </motion.div>
      <motion.div variants={itemReveal}>
        <LoreTerminal />
      </motion.div>
    </motion.div>
  );
}

function backLabel(target: NexusViewId): string {
  if (target === "hub") return "Zur Nexus-Mitte";
  if (target === "arcade") return "Zur Arcade";
  if (target === "faction") return "Zur Hauswahl";
  if (target === "sqlMissions") return "Zu den Missionen";
  return "Zurück";
}

function NexusBackBar({ target }: { target: NexusViewId }) {
  const setNexusView = useAppStore((s) => s.setNexusView);
  return (
    <div className="mb-6 flex justify-start">
      <motion.button
        type="button"
        whileTap={{ scale: 0.97 }}
        onClick={() => setNexusView(target)}
        className="inline-flex items-center gap-2 rounded-full border border-border-glass bg-surface-muted/60 px-4 py-2 font-sans text-xs font-semibold uppercase tracking-wide text-foreground-muted ring-1 ring-white/10 transition hover:border-white/[0.14] hover:text-cyber-cyan"
      >
        <IconArrowLeft className="size-4 shrink-0 text-foreground-muted" aria-hidden />
        {backLabel(target)}
      </motion.button>
    </div>
  );
}

export function NexusShell() {
  const nexusView = useAppStore((s) => s.nexusView);

  const backTarget: NexusViewId =
    nexusView === "sqlSandbox"
      ? "sqlMissions"
      : nexusView === "sqlMissions"
        ? "arcade"
        : nexusView === "pseudoTrainer" || nexusView === "itSupport"
          ? "arcade"
          : nexusView === "faction"
            ? "arcade"
            : nexusView === "realm"
              ? "faction"
              : "hub";

  return (
    <div className="relative space-y-2">
      <AnimatePresence mode="wait">
        <motion.div
          key={nexusView}
          variants={subVariants}
          initial="initial"
          animate="animate"
          exit="exit"
          className="relative"
        >
          {nexusView !== "hub" ? <NexusBackBar target={backTarget} /> : null}
          {nexusView === "hub" ? <NexusHub /> : null}
          {nexusView === "tree" ? <TechTreeMap /> : null}
          {nexusView === "arcade" ? <ArcadeHub /> : null}
          {nexusView === "faction" ? <FactionSelect /> : null}
          {nexusView === "realm" ? <RealmQuestBoard /> : null}
          {nexusView === "sqlMissions" ? <SqlMissionList /> : null}
          {nexusView === "sqlSandbox" ? <SqlSandboxTerminal /> : null}
          {nexusView === "pseudoTrainer" ? <PseudoCodeTrainer /> : null}
          {nexusView === "itSupport" ? <HelpdeskTerminalView /> : null}
        </motion.div>
      </AnimatePresence>
    </div>
  );
}
