const PUBLIC_DOSSIER_CACHE_MS = 60_000;

function dossierMemoryHit(
  s: {
    publicDossierCachedUserId: string | null;
    publicDossierLastFetchedAt: number | null;
    publicDossierCachedPayload: PublicDossierData | null;
  },
  userId: string,
): boolean {
  return (
    s.publicDossierCachedUserId === userId &&
    s.publicDossierLastFetchedAt != null &&
    s.publicDossierCachedPayload?.userId === userId &&
    Date.now() - s.publicDossierLastFetchedAt < PUBLIC_DOSSIER_CACHE_MS
  );
}

