import { AnimatePresence, motion, useReducedMotion } from "framer-motion";
import { useEffect, useMemo, useState } from "react";
import { cn } from "../../lib/cn";
import { springHeavy } from "../../motion/variants";
import { useAppStore } from "../../store/useAppStore";
import { formatPulseTickerLine, obfuscatePulseGlyph } from "../../types/systemPulse";

const CIPHER_TICK_MS = 140;

export function SystemPulseTicker() {
  const prefersReduced = useReducedMotion();
  const systemPulse = useAppStore((s) => s.systemPulse);
  const [cipherSeed, setCipherSeed] = useState(0);

  useEffect(() => {
    if (prefersReduced) return;
    const id = window.setInterval(() => setCipherSeed((n) => (n + 1) % 1_000_000), CIPHER_TICK_MS);
    return () => window.clearInterval(id);
  }, [prefersReduced]);

  const tickerTape = useMemo(() => {
    if (systemPulse.length === 0) return "STREAM_IDLE · AWAITING_UPLINK_NODES";
    return systemPulse.map((e) => formatPulseTickerLine(e)).join("   ··   ");
  }, [systemPulse]);

  const duplicated = `${tickerTape}   ··   ${tickerTape}`;

  const head = systemPulse[0] ?? null;

  return (
    <div
      className={cn(
        "relative overflow-hidden border border-white/[0.1] bg-black/60",
        !prefersReduced && "system-pulse-beacon",
      )}
    >
      <div className="pointer-events-none absolute inset-0 hud-grid opacity-[0.05]" aria-hidden />
      <div className="relative border-b border-white/[0.08] px-4 py-2 sm:px-5">
        <div className="flex flex-wrap items-center justify-between gap-2">
          <p className="font-mono text-[10px] font-semibold uppercase tracking-[0.28em] text-foreground-muted">
            System Pulse Ticker
          </p>
          <p className="font-mono text-[9px] uppercase tracking-[0.2em] text-foreground-muted">
            Encrypted edge stream
          </p>
        </div>
        <div className="relative mt-2 h-10 overflow-hidden">
          <AnimatePresence initial={false} mode="popLayout">
            {head ? (
              <motion.div
                key={head.id}
                layout={!prefersReduced}
                initial={prefersReduced ? false : { opacity: 0, y: -16 }}
                animate={{ opacity: 1, y: 0 }}
                exit={prefersReduced ? undefined : { opacity: 0, y: 10 }}
                transition={springHeavy}
                className={cn(
                  "absolute inset-x-0 top-0 font-mono text-[11px] leading-snug tracking-tight sm:text-xs",
                  head.kind === "GLOBAL_LIVE_EVENT"
                    ? "font-extrabold text-amber-200 drop-shadow-[0_0_14px_rgb(251_191_36/0.45)]"
                    : head.kind === "SYSTEM_ANNOUNCEMENT"
                      ? "font-medium text-emerald-400 drop-shadow-[0_0_12px_rgb(52_211_153/0.35)]"
                      : "font-medium text-signal",
                )}
              >
                {formatPulseTickerLine(head)}
              </motion.div>
            ) : (
              <motion.div
                key="idle-head"
                className="absolute inset-x-0 top-0 font-mono text-[11px] text-foreground-muted sm:text-xs"
                initial={false}
              >
                NO_SIGNAL · PULSE_CHANNEL_OPEN
              </motion.div>
            )}
          </AnimatePresence>
        </div>
      </div>

      <div className="relative h-9 overflow-hidden border-t border-white/[0.06]">
        <div
          className="pointer-events-none absolute inset-0 z-10 bg-gradient-to-r from-black via-transparent to-black opacity-90"
          aria-hidden
        />
        <p
          className={cn(
            "pointer-events-none absolute inset-x-0 top-1 z-[11] truncate px-2 font-mono text-[9px] tracking-[0.12em] text-white/16",
            prefersReduced && "opacity-0",
          )}
          aria-hidden
        >
          {obfuscatePulseGlyph(cipherSeed)}
        </p>
        <div
          className={cn(
            "system-pulse-ticker-rail pointer-events-none pt-1.5 font-mono text-[10px] tracking-tight text-foreground/88",
            prefersReduced && "system-pulse-ticker-rail-static",
          )}
          aria-live="polite"
        >
          <span className="inline-block whitespace-nowrap">{duplicated}</span>
        </div>
      </div>
    </div>
  );
}
