import { AnimatePresence, motion, useReducedMotion } from "framer-motion";
import { useEffect } from "react";
import { ACHIEVEMENTS, isAchievementId } from "../../data/achievementSchema";
import { springHeavy } from "../../motion/variants";
import { useAppStore } from "../../store/useAppStore";

export function MedalAwardHost() {
  const prefersReduced = useReducedMotion();
  const head = useAppStore((s) => s.medalToastQueue[0] ?? null);
  const dismissMedalToast = useAppStore((s) => s.dismissMedalToast);

  useEffect(() => {
    if (!head) return;
    const t = window.setTimeout(() => dismissMedalToast(), 4200);
    return () => window.clearTimeout(t);
  }, [head, dismissMedalToast]);

  const def = head && isAchievementId(head) ? ACHIEVEMENTS[head] : null;

  return (
    <div className="pointer-events-none fixed right-4 top-4 z-[420] flex max-w-[min(92vw,18rem)] flex-col items-end gap-2">
      <AnimatePresence mode="wait">
        {def ? (
          <motion.div
            key={def.id}
            initial={prefersReduced ? { opacity: 0 } : { opacity: 0, x: 18, y: -8 }}
            animate={{ opacity: 1, x: 0, y: 0 }}
            exit={prefersReduced ? { opacity: 0 } : { opacity: 0, x: 12, y: -6 }}
            transition={springHeavy}
            className="pointer-events-auto w-full border border-amber-500/45 bg-black/90 px-3 py-3 shadow-[inset_0_0_0_1px_rgb(245_158_11_/0.2),0_0_24px_rgb(245_158_11_/0.12)]"
          >
            <p className="font-mono text-[9px] font-bold uppercase tracking-[0.28em] text-amber-200/95">MEDAL AWARDED</p>
            <div className="mt-2 flex items-start gap-3">
              <svg viewBox="0 0 32 32" className="size-9 shrink-0 text-amber-300 drop-shadow-[0_0_10px_rgb(251_191_36_/0.45)]" aria-hidden>
                <path fill="currentColor" d="M16 2 20.5 11h9.2L23 17.2l3.5 9.1L16 20.8 5.5 26.3 9 17.2 2.3 11h9.2L16 2Z" opacity="0.95" />
              </svg>
              <div className="min-w-0">
                <p className="font-mono text-xs font-semibold uppercase tracking-tight text-foreground/90">{def.title}</p>
                <p className="mt-1 line-clamp-3 font-mono text-[10px] leading-snug text-foreground-muted">{def.requirement}</p>
              </div>
            </div>
            <button
              type="button"
              onClick={() => dismissMedalToast()}
              className="mt-2 w-full border border-white/[0.1] bg-white/[0.04] py-1.5 font-mono text-[9px] font-semibold uppercase tracking-[0.2em] text-foreground-muted hover:bg-white/[0.07]"
            >
              Verstanden
            </button>
          </motion.div>
        ) : null}
      </AnimatePresence>
    </div>
  );
}
