import { AnimatePresence, motion } from "framer-motion";
import { cn } from "../../lib/cn";
import { REALM_BUILD_COSTS, type RealmBuildKind } from "../../types/realmQuest";
import { useAppStore } from "../../store/useAppStore";

export function BuildMenuPanel() {
  const realmBuildSelection = useAppStore((s) => s.realmBuildSelection);
  const realmGold = useAppStore((s) => s.realmGold);
  const buildStructure = useAppStore((s) => s.buildStructure);
  const closeRealmBuildMenu = useAppStore((s) => s.closeRealmBuildMenu);

  const open = realmBuildSelection !== null;

  return (
    <AnimatePresence>
      {open ? (
        <motion.div
          key="build"
          initial={{ y: 48, opacity: 0 }}
          animate={{ y: 0, opacity: 1 }}
          exit={{ y: 32, opacity: 0 }}
          transition={{ type: "spring", stiffness: 320, damping: 30 }}
          className={cn(
            "pointer-events-auto fixed inset-x-3 bottom-[calc(5.5rem+env(safe-area-inset-bottom))] z-[55] mx-auto max-w-lg sm:inset-x-8",
            "rounded-2xl border border-border-glass bg-surface-muted/55 p-4 ring-1 ring-white/10 backdrop-blur-2xl",
            "ring-2 ring-cyber-cyan/25",
          )}
        >
          <div className="pointer-events-none absolute inset-0 noise-overlay opacity-25" />
          <div className="relative space-y-3">
            <div className="flex items-start justify-between gap-3">
              <div>
                <p className="font-sans text-[10px] font-semibold uppercase tracking-[0.25em] text-magenta">
                  Bau-Menü
                </p>
                <h3 className="font-display text-lg font-bold uppercase tracking-wide text-foreground">
                  Feld {realmBuildSelection?.q},{realmBuildSelection?.r}
                </h3>
                <p className="font-sans text-xs text-foreground-muted">
                  Wähle eine Struktur — nur wenn dein Gold reicht
                </p>
              </div>
              <button
                type="button"
                onClick={() => closeRealmBuildMenu()}
                className="rounded-full border border-border-glass px-3 py-1 font-sans text-[10px] font-semibold uppercase tracking-wide text-foreground-muted transition hover:text-foreground"
              >
                Schließen
              </button>
            </div>
            <div className="grid grid-cols-2 gap-3">
              {(
                [
                  {
                    kind: "goldmine" as const,
                    title: "Goldmine",
                    blurb: "Push Wissen und langfristigen Goldfluss",
                  },
                  {
                    kind: "barracks" as const,
                    title: "Kaserne",
                    blurb: "Verteidigung plus Diamant-Bonus beim Setzen",
                  },
                ] satisfies { kind: RealmBuildKind; title: string; blurb: string }[]
              ).map((opt) => {
                const cost = REALM_BUILD_COSTS[opt.kind].gold;
                const ok = realmGold >= cost;
                return (
                  <motion.button
                    key={opt.kind}
                    type="button"
                    whileHover={ok ? { scale: 1.03 } : undefined}
                    whileTap={ok ? { scale: 0.97 } : undefined}
                    disabled={!ok}
                    onClick={() => buildStructure(opt.kind)}
                    className={cn(
                      "rounded-xl border border-border-glass bg-surface/85 p-4 text-left",
                      ok
                        ? "ring-1 ring-white/10 hover:border-cyber-cyan/40 hover:bg-white/[0.04]"
                        : "cursor-not-allowed opacity-45",
                    )}
                  >
                    <p className="font-display text-sm font-bold uppercase tracking-wide text-cyber-cyan">
                      {opt.title}
                    </p>
                    <p className="mt-1 font-sans text-[11px] leading-snug text-foreground-muted">
                      {opt.blurb}
                    </p>
                    <p className="mt-2 font-mono text-xs text-toxic">{cost} Gold</p>
                  </motion.button>
                );
              })}
            </div>
          </div>
        </motion.div>
      ) : null}
    </AnimatePresence>
  );
}
