import type { Transition, Variants } from "framer-motion";

/** Phase 19 — schwere Metall-Feder (mass 1, damping 30) */
export const springHeavy: Transition = {
  type: "spring",
  stiffness: 280,
  damping: 30,
  mass: 1,
};

/** Phase 64 — Fraktions-Leiste: etwas straffer für Tug-of-War */
export const springFactionWar: Transition = {
  type: "spring",
  stiffness: 420,
  damping: 28,
  mass: 0.82,
};

const springSnappy: Transition = {
  type: "spring",
  stiffness: 300,
  damping: 30,
  mass: 0.92,
};

const springSoft: Transition = {
  type: "spring",
  stiffness: 260,
  damping: 30,
  mass: 1.05,
};

const reducedTransition: Transition = {
  duration: 0.01,
};

/** Sektionswechsel: alt weicht zur Seite, neu rückt mit Feder nach */
export const pageTransition: Variants = {
  initial: { opacity: 0, x: 52, filter: "blur(8px)" },
  animate: {
    opacity: 1,
    x: 0,
    filter: "blur(0px)",
    transition: { ...springHeavy, delay: 0.07 },
  },
  exit: {
    opacity: 0,
    x: -64,
    filter: "blur(6px)",
    transition: { duration: 0.36, ease: [0.45, 0, 0.2, 1] },
  },
};

export const pageTransitionReduced: Variants = {
  initial: { opacity: 0 },
  animate: { opacity: 1, transition: reducedTransition },
  exit: { opacity: 0, transition: reducedTransition },
};

