export type IhkGrade = 1 | 2 | 3 | 4 | 5 | 6;

export function ihkGradeFromPercent(percent: number): IhkGrade {
  const p = Math.max(0, Math.min(100, Math.floor(percent)));
  if (p >= 92) return 1;
  if (p >= 81) return 2;
  if (p >= 67) return 3;
  if (p >= 50) return 4;
  if (p >= 30) return 5;
  return 6;
}

export function ihkGradeLabel(grade: IhkGrade): string {
  if (grade === 1) return "Sehr gut";
  if (grade === 2) return "Gut";
  if (grade === 3) return "Befriedigend";
  if (grade === 4) return "Ausreichend";
  if (grade === 5) return "Mangelhaft";
  return "Ungenügend";
}
