import { useEffect, useRef } from "react";
import { deriveLinkPulseStatus, type LinkPulseStatus } from "../lib/connectivity";
import { getSupabase } from "../lib/supabase";
import { useAppStore } from "../store/useAppStore";

let navigatorOnlineFlag = typeof navigator !== "undefined" && navigator.onLine;

function computeLinkPulseStatus(): LinkPulseStatus {
  const s = useAppStore.getState();
  const configured = getSupabase() !== null;
  return deriveLinkPulseStatus({
    navigatorOnline: navigatorOnlineFlag,
    supabaseConfigured: configured,
    authUserPresent: !!s.authUser,
    syncStatus: s.syncStatus,
    cloudLastError: s.cloudLastError,
    cloudUplinkBusy: s.cloudUplinkBusy,
    cloudAuthPending: s.cloudAuthPending,
  });
}

/**
 * Phase 51 — hält `linkPulseStatus` im Store synchron (rAF-gedrosselt) und
 * triggert bei OFFLINE → ONLINE sofort Pull+Push ohne Dauer-Polling
 */
export function useLinkPulseBridge() {
  const rafRef = useRef<number | null>(null);

  useEffect(() => {
    const flush = () => {
      if (rafRef.current != null) {
        cancelAnimationFrame(rafRef.current);
        rafRef.current = null;
      }
      const next = computeLinkPulseStatus();
      const before = useAppStore.getState().linkPulseStatus;
      if (before !== next) {
        useAppStore.setState({ linkPulseStatus: next });
        if (before === "offline" && next !== "offline") {
          const { authUser, fetchFromCloud, pushToCloud } = useAppStore.getState();
          if (authUser && getSupabase()) {
            void fetchFromCloud().then(() => {
              void pushToCloud();
            });
          }
        }
      }
    };

    const scheduleFlush = () => {
      if (rafRef.current != null) return;
      rafRef.current = requestAnimationFrame(() => {
        rafRef.current = null;
        flush();
      });
    };

    navigatorOnlineFlag = typeof navigator !== "undefined" && navigator.onLine;
    flush();

    const onOnline = () => {
      navigatorOnlineFlag = true;
      flush();
    };
    const onOffline = () => {
      navigatorOnlineFlag = false;
      flush();
    };
    window.addEventListener("online", onOnline);
    window.addEventListener("offline", onOffline);

    const unsub = useAppStore.subscribe(scheduleFlush);

    return () => {
      window.removeEventListener("online", onOnline);
      window.removeEventListener("offline", onOffline);
      unsub();
      if (rafRef.current != null) cancelAnimationFrame(rafRef.current);
    };
  }, []);
}
