import { useReducedMotion } from "framer-motion";
import { useMemo } from "react";
import {
  DEFAULT_TERMINAL_THEME_ID,
  getTerminalThemeById,
  normalizeTerminalThemeId,
  prestigeRankIndexFromLifetimeXp,
  resolveScanlineAlpha,
} from "../data/terminalThemes";
import { computeLifetimeXp } from "../lib/xpCurve";
import { useAppStore } from "../store/useAppStore";

export function useRigThemeMotionProps() {
  const userLevel = useAppStore((s) => s.userLevel);
  const globalXP = useAppStore((s) => s.globalXP);
  const rigTerminalThemeId = useAppStore((s) => s.rigTerminalThemeId);
  const rigScanlineDial = useAppStore((s) => s.rigScanlineDial);
  const reduceMotion = useReducedMotion();

  const lifetimeXp = useMemo(() => computeLifetimeXp(userLevel, globalXP), [userLevel, globalXP]);
  const normalizedId = useMemo(
    () => normalizeTerminalThemeId(rigTerminalThemeId, lifetimeXp),
    [rigTerminalThemeId, lifetimeXp],
  );
  const theme = useMemo(
    () => getTerminalThemeById(normalizedId) ?? getTerminalThemeById(DEFAULT_TERMINAL_THEME_ID)!,
    [normalizedId],
  );
  const prestigeRankIndex = useMemo(() => prestigeRankIndexFromLifetimeXp(lifetimeXp), [lifetimeXp]);
  const scanlineAlpha = useMemo(
    () => resolveScanlineAlpha(theme, rigScanlineDial, prestigeRankIndex),
    [theme, rigScanlineDial, prestigeRankIndex],
  );

  const cssVars = useMemo(
    () =>
      ({
        "--color-signal": theme.signalHex,
        "--color-magenta": theme.magentaHex,
        "--color-magenta-dim": `rgb(${theme.magentaDimRgb} / 0.45)`,
        "--rig-scanline-alpha": scanlineAlpha,
        "--rig-selection-bg": theme.selectionBg,
        "--rig-focus-ring": theme.focusRing,
      }) as Record<string, string | number>,
    [theme, scanlineAlpha],
  );

  const transition = reduceMotion
    ? { duration: 0.12, ease: "easeOut" as const }
    : { duration: 0.88, ease: [0.16, 1, 0.3, 1] as const };

  const phosphor = useMemo(
    () => ({
      opacity: theme.crtBloomOpacity,
      background: `radial-gradient(ellipse 78% 64% at 50% 42%, ${theme.phosphorCenter}, transparent 58%)`,
    }),
    [theme],
  );

  return { cssVars, transition, phosphor, theme, normalizedId, prestigeRankIndex };
}
