import { useEffect, useRef, useState } from "react";
import { cn } from "../../lib/cn";

type BlueprintViewerProps = {
  src: string;
  alt?: string;
  className?: string;
};

/** Phase 50 — Bild erst bei Sichtbarkeit mounten (spart Bandbreite beim ersten Start) */
export function BlueprintViewer({ src, alt = "Fragenreferenz", className }: BlueprintViewerProps) {
  const rootRef = useRef<HTMLDivElement | null>(null);
  const [inView, setInView] = useState(false);
  const [loaded, setLoaded] = useState(false);
  const [failed, setFailed] = useState(false);

  useEffect(() => {
    const el = rootRef.current;
    if (!el || typeof IntersectionObserver === "undefined") {
      setInView(true);
      return;
    }
    const obs = new IntersectionObserver(
      (entries) => {
        if (entries.some((e) => e.isIntersecting)) setInView(true);
      },
      { root: null, rootMargin: "120px 0px", threshold: 0.01 },
    );
    obs.observe(el);
    return () => obs.disconnect();
  }, []);

  return (
    <div
      ref={rootRef}
      className={cn(
        "relative mt-4 aspect-video w-full max-w-full overflow-hidden",
        "border border-emerald-500/30 bg-zinc-950/90",
        "shadow-[inset_0_0_28px_rgb(16_185_129_/0.12),0_0_0_1px_rgb(0_0_0_/0.65)]",
        className,
      )}
    >
      <div
        className="pointer-events-none absolute inset-0 z-[2] opacity-[0.16]"
        aria-hidden
        style={{
          backgroundImage:
            "repeating-linear-gradient(0deg, transparent 0px, transparent 2px, rgba(0,0,0,0.5) 2px, rgba(0,0,0,0.5) 3px)",
        }}
      />
      <div
        className="pointer-events-none absolute inset-0 z-[2] mix-blend-soft-light opacity-[0.22]"
        aria-hidden
        style={{
          background:
            "linear-gradient(115deg, transparent 0%, rgba(34,197,94,0.07) 42%, transparent 62%, rgba(6,182,212,0.05) 100%)",
        }}
      />
      {!inView ? (
        <div
          className="absolute inset-0 z-[1] animate-pulse bg-gradient-to-br from-zinc-950 via-black to-zinc-900"
          aria-hidden
        />
      ) : null}
      {inView && !loaded && !failed ? (
        <div className="absolute inset-0 z-[1] animate-pulse bg-gradient-to-br from-zinc-950 via-black to-zinc-900" aria-hidden />
      ) : null}
      {failed ? (
        <div className="absolute inset-0 z-[1] flex items-center justify-center px-4 font-mono text-[10px] uppercase tracking-[0.2em] text-foreground-muted">
          Bild nicht ladbar
        </div>
      ) : inView ? (
        <img
          src={src}
          alt={alt}
          loading="lazy"
          decoding="async"
          fetchPriority="low"
          onLoad={() => setLoaded(true)}
          onError={() => {
            setFailed(true);
            setLoaded(true);
          }}
          className={cn(
            "relative z-[1] h-full w-full object-contain transition-opacity duration-500 ease-out",
            loaded ? "opacity-100" : "opacity-0",
          )}
        />
      ) : null}
    </div>
  );
}
