import { AnimatePresence, motion } from "framer-motion";
import { cn } from "../../lib/cn";
import {
  IconChart,
  IconHexagon,
  IconMoreHorizontal,
  IconOrbit,
  IconUser,
} from "../icons/ThinLineIcons";
import { dockIcon } from "../../motion/variants";
import { useFeedback } from "../../hooks/useFeedback";
import {
  type DockSectionId,
  useAppStore,
} from "../../store/useAppStore";

const items: {
  id: DockSectionId;
  label: string;
  Icon: typeof IconHexagon;
}[] = [
  { id: "command", label: "Command", Icon: IconHexagon },
  { id: "nexus", label: "Nexus", Icon: IconOrbit },
  { id: "stats", label: "Stats", Icon: IconChart },
  { id: "profile", label: "Profil", Icon: IconUser },
];

export function FloatingDock() {
  const activeSection = useAppStore((s) => s.activeSection);
  const setActiveSection = useAppStore((s) => s.setActiveSection);
  const dockHoveredId = useAppStore((s) => s.dockHoveredId);
  const setDockHoveredId = useAppStore((s) => s.setDockHoveredId);
  const openMoreMenu = useAppStore((s) => s.openMoreMenu);
  const feedback = useFeedback();

  return (
    <div
      data-print-hide
      className="pointer-events-none fixed inset-x-0 bottom-0 z-50 flex justify-center pb-[calc(1rem+env(safe-area-inset-bottom))]"
    >
      <div className="pointer-events-auto relative mx-4 flex w-full max-w-lg items-end justify-center gap-3">
        <nav aria-label="Hauptnavigation" className="relative w-full max-w-md flex-1">
          <div
            className={cn(
              "relative overflow-hidden rounded-full",
              "border border-white/10 bg-surface-muted/55 px-2 py-2 ring-1 ring-white/10 backdrop-blur-2xl",
            )}
          >
            <div className="pointer-events-none absolute inset-0 noise-overlay opacity-20" />
            <div className="relative flex items-center justify-between gap-1 sm:gap-2">
              {items.map(({ id, label, Icon }) => {
                const commandStack =
                  activeSection === "loadout" ||
                  activeSection === "arena" ||
                  activeSection === "mockExam" ||
                  activeSection === "flashcards";
                const active =
                  activeSection === id ||
                  (commandStack && id === "command") ||
                  (activeSection === "vault" && id === "profile") ||
                  (activeSection === "cloud" && id === "stats") ||
                  (activeSection === "adminCmd" && id === "stats");
                const hovered = dockHoveredId === id;
                return (
                  <motion.button
                    key={id}
                    type="button"
                    aria-current={active ? "page" : undefined}
                    aria-label={label}
                    variants={dockIcon}
                    initial="rest"
                    whileHover="hover"
                    whileTap="tap"
                    onPointerEnter={() => setDockHoveredId(id)}
                    onPointerLeave={() => setDockHoveredId(null)}
                    onFocus={() => setDockHoveredId(id)}
                    onBlur={() => setDockHoveredId(null)}
                  onClick={() => {
                    feedback.menuTap();
                    setActiveSection(id);
                  }}
                  className={cn(
                      "relative flex min-h-11 min-w-11 flex-1 items-center justify-center rounded-full",
                      "text-foreground-muted transition-colors duration-300",
                      (active || hovered) && "text-foreground",
                    )}
                  >
                    {active ? (
                      <motion.span
                        layoutId="dock-active-pip"
                        className="absolute inset-1 rounded-full border border-white/10 bg-white/[0.08] ring-1 ring-white/10"
                        transition={{ type: "spring", stiffness: 280, damping: 30, mass: 0.95 }}
                      />
                    ) : null}
                    <Icon
                      className={cn(
                        "relative z-10 size-6 sm:size-[22px]",
                        active && "text-signal",
                      )}
                    />
                    <AnimatePresence>
                      {hovered ? (
                        <motion.span
                          initial={{ opacity: 0, y: 6, scale: 0.92 }}
                          animate={{ opacity: 1, y: 0, scale: 1 }}
                          exit={{ opacity: 0, y: 4, scale: 0.95 }}
                          transition={{ duration: 0.2, ease: [0.16, 1, 0.3, 1] }}
                          className="pointer-events-none absolute -top-9 left-1/2 z-20 -translate-x-1/2 rounded-lg border border-white/10 bg-surface-muted/95 px-2 py-1 font-mono text-[10px] font-medium uppercase tracking-wide text-foreground backdrop-blur-md ring-1 ring-white/10"
                        >
                          {label}
                        </motion.span>
                      ) : null}
                    </AnimatePresence>
                  </motion.button>
                );
              })}
            </div>
          </div>
        </nav>
        <motion.button
          type="button"
          aria-label="Mehr"
          whileTap={{ scale: 0.92, y: 3 }}
          transition={{ type: "spring", stiffness: 280, damping: 30, mass: 1 }}
          onClick={() => {
            feedback.menuTap();
            openMoreMenu();
          }}
          className={cn(
            "relative flex size-12 shrink-0 items-center justify-center rounded-full border border-white/[0.1]",
            "bg-surface-muted/50 backdrop-blur-2xl",
            "text-foreground-muted hover-breathe hover:text-foreground",
          )}
        >
          <div className="pointer-events-none absolute inset-0 rounded-full noise-overlay opacity-20" />
          <IconMoreHorizontal className="relative z-10 size-6" />
        </motion.button>
      </div>
    </div>
  );
}
