import { AnimatePresence, motion, useReducedMotion } from "framer-motion";
import { ArtifactPedestal } from "../profile/ArtifactPedestal";
import { getRankArtifact } from "../../lib/rankEngine";
import type { MissionReportPayload } from "../../lib/helpdeskMissionReport";
import { cn } from "../../lib/cn";
import { springHeavy } from "../../motion/variants";
import { useAppStore } from "../../store/useAppStore";

const dockTap = { scale: 0.94 as const, y: 3 as const };

type MissionReportOverlayProps = {
  open: boolean;
  payload: MissionReportPayload | null;
  onDismiss: () => void;
};

export function MissionReportOverlay({ open, payload, onDismiss }: MissionReportOverlayProps) {
  const prefersReduced = useReducedMotion();
  const userLevel = useAppStore((s) => s.userLevel);
  const artifact = getRankArtifact(userLevel);
  const ok = payload?.outcome === "resolved";

  return (
    <AnimatePresence>
      {open && payload ? (
        <motion.div
          key="mission-report"
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          exit={{ opacity: 0 }}
          transition={{ duration: prefersReduced ? 0.12 : 0.22 }}
          className="fixed inset-0 z-[280] flex items-center justify-center bg-black/80 px-4 py-8 backdrop-blur-[3px]"
          role="dialog"
          aria-modal="true"
        >
          <motion.div
            initial={prefersReduced ? false : { scale: 0.96, y: 14, opacity: 0 }}
            animate={{ scale: 1, y: 0, opacity: 1 }}
            exit={prefersReduced ? { opacity: 0 } : { scale: 0.97, y: 10, opacity: 0 }}
            transition={{ type: "spring", stiffness: 320, damping: 30 }}
            className={cn(
              "relative w-full max-w-md border bg-black/90 p-6 shadow-[inset_0_0_0_1px_rgba(255,255,255,0.06)]",
              ok ? "border-white/[0.12]" : "border-signal/45",
            )}
            style={
              ok
                ? {
                    boxShadow: `inset 0 0 42px ${artifact.auraColor}, 0 0 0 1px rgba(255,255,255,0.06)`,
                  }
                : { boxShadow: "inset 0 0 38px rgb(179 24 38 / 0.18)" }
            }
          >
            <div className="pointer-events-none absolute inset-0 hud-grid opacity-[0.12]" aria-hidden />
            <div
              className={cn(
                "pointer-events-none absolute inset-x-0 top-0 h-px bg-gradient-to-r from-transparent to-transparent",
                ok ? "via-cyber-cyan/40" : "via-signal/55",
              )}
              aria-hidden
            />

            <div className="relative flex items-start justify-between gap-4">
              <div>
                <p
                  className={cn(
                    "font-mono text-[9px] font-semibold uppercase tracking-[0.32em]",
                    ok ? artifact.accentClass : "text-signal",
                  )}
                >
                  {ok ? "After action report" : "Mission failure"}
                </p>
                <p className="mt-2 font-mono text-xs uppercase tracking-[0.14em] text-foreground-muted">{payload.title}</p>
              </div>
              {ok ? (
                <div className="w-14 shrink-0 saturate-[0.85]">
                  <ArtifactPedestal artifact={artifact} variant="compact" className="border-white/[0.1] bg-black/50" />
                </div>
              ) : null}
            </div>

            <div className="relative mt-5 grid grid-cols-2 gap-3 font-mono text-[10px] uppercase tracking-[0.18em]">
              <div className="border border-white/[0.08] bg-white/[0.03] px-3 py-2">
                <p className="text-foreground-muted">Efficiency tier</p>
                <p className={cn("mt-1 text-2xl font-bold tabular-nums", ok ? artifact.accentClass : "text-signal")}>{payload.tier}</p>
              </div>
              <div className="border border-white/[0.08] bg-white/[0.03] px-3 py-2">
                <p className="text-foreground-muted">SLA reserve</p>
                <p className={cn("mt-1 text-lg font-semibold tabular-nums", ok ? "text-foreground/88" : "text-signal")}>
                  {Math.round(payload.slaRatio * 100)}%
                </p>
              </div>
            </div>

            <div className="relative mt-4 border border-white/[0.08] bg-black/50 px-3 py-3">
              <p className="font-mono text-[9px] uppercase tracking-[0.22em] text-foreground-muted">XP settlement</p>
              <div className="mt-2 space-y-1 font-mono text-[11px] text-foreground/78">
                {ok ? (
                  <>
                    <p>
                      <span className="text-foreground-muted">Base</span>{" "}
                      <span className="tabular-nums text-foreground">{payload.baseXp}</span>
                    </p>
                    <p>
                      <span className="text-foreground-muted">SLA bonus</span>{" "}
                      <span className="tabular-nums text-cyber-cyan/90">+{payload.bonusXp}</span>
                    </p>
                    <p className={cn("border-t border-white/[0.08] pt-2 text-sm font-bold tabular-nums", artifact.accentClass)}>
                      Total +{payload.totalXp} XP
                    </p>
                  </>
                ) : (
                  <p className="text-signal">No XP granted wegen Abbruch</p>
                )}
              </div>
            </div>

            <div className="relative mt-4 border border-white/[0.06] bg-black/60 px-3 py-2">
              <p className="mb-2 font-mono text-[9px] uppercase tracking-[0.2em] text-foreground-muted">Log stream</p>
              <ul className="space-y-1 font-mono text-[10px] leading-relaxed text-foreground/70">
                {payload.terminalLines.map((line) => (
                  <li key={line}>{line}</li>
                ))}
              </ul>
            </div>

            <motion.button
              type="button"
              whileTap={dockTap}
              transition={springHeavy}
              onClick={onDismiss}
              className={cn(
                "relative mt-6 w-full border py-3 font-mono text-[10px] font-semibold uppercase tracking-[0.24em] transition-colors",
                ok
                  ? "border-white/[0.14] bg-white/[0.05] text-foreground hover-breathe hover:border-cyber-cyan/35"
                  : "border-signal/40 bg-signal/[0.12] text-signal hover-breathe hover:border-signal/55",
              )}
            >
              ACK CLOSE
            </motion.button>
          </motion.div>
        </motion.div>
      ) : null}
    </AnimatePresence>
  );
}
