/** Heuristik für typische Netzwerk-/Transport-Fehler (Supabase fetch) */
export function isCloudTransportErrorMessage(message: string | null | undefined): boolean {
  if (!message || message.length > 800) return false;
  const m = message.toLowerCase();
  return (
    m.includes("failed to fetch") ||
    m.includes("load failed") ||
    m.includes("networkerror") ||
    m.includes("network request failed") ||
    m.includes("timeout") ||
    m.includes("timed out") ||
    m.includes("econnrefused") ||
    m.includes("enotfound") ||
    m.includes("err_network") ||
    m.includes("offline") ||
    m.includes("connection refused") ||
    m.includes("could not connect")
  );
}

/** Phase 51 — Heartbeat / Header-Chip (performant, nur Primitiven) */
export type LinkPulseStatus = "online" | "slow" | "offline";

type LinkPulseSync = "offline" | "cloud-synced" | "cloud-outdated";

export function deriveLinkPulseStatus(input: {
  navigatorOnline: boolean;
  supabaseConfigured: boolean;
  authUserPresent: boolean;
  syncStatus: LinkPulseSync;
  cloudLastError: string | null;
  cloudUplinkBusy: boolean;
  cloudAuthPending: boolean;
}): LinkPulseStatus {
  const {
    navigatorOnline,
    supabaseConfigured,
    authUserPresent,
    syncStatus,
    cloudLastError,
    cloudUplinkBusy,
    cloudAuthPending,
  } = input;

  if (!navigatorOnline) return "offline";

  if (!supabaseConfigured || !authUserPresent) {
    return "online";
  }

  const transportLikelyDown =
    !cloudUplinkBusy && !cloudAuthPending && isCloudTransportErrorMessage(cloudLastError);
  if (transportLikelyDown) return "offline";

  if (cloudUplinkBusy || cloudAuthPending) return "online";

  if (syncStatus === "cloud-outdated") return "slow";
  if (syncStatus === "offline") return "slow";

  return "online";
}
