import { useEffect, useRef } from "react";
import { pickVaultStateFromStore } from "../lib/vaultBackup";
import { getSupabase } from "../lib/supabase";
import { useAppStore } from "../store/useAppStore";

const DEBOUNCE_MS = 2600;

function vaultSnapshotJson(get: () => ReturnType<typeof useAppStore.getState>): string {
  return JSON.stringify(pickVaultStateFromStore(get()));
}

/**
 * Debounced Push zu Supabase bei persist-relevanten Store-Änderungen
 */
export function useCloudAutoSync() {
  const timerRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  useEffect(() => {
    return useAppStore.subscribe((state, prev) => {
      if (!getSupabase()) return;
      if (!state.authUser || !state.authReady) return;
      if (!prev) return;
      const vaultSame = vaultSnapshotJson(() => state) === vaultSnapshotJson(() => prev);
      const authSame = state.authUser?.id === prev.authUser?.id;
      if (vaultSame && authSame) return;

      useAppStore.setState({ syncStatus: "cloud-outdated" });

      if (timerRef.current) clearTimeout(timerRef.current);
      timerRef.current = setTimeout(() => {
        timerRef.current = null;
        void useAppStore.getState().pushToCloud();
      }, DEBOUNCE_MS);
    });
  }, []);

  useEffect(
    () => () => {
      if (timerRef.current) clearTimeout(timerRef.current);
    },
    [],
  );
}
