type ChallengePayloadV1 = {
  v: 1;
  ids: string[];
  by?: string;
  elapsedMs?: number;
  percent?: number;
};

export type DecodedChallenge = {
  ids: string[];
  by: string;
  elapsedMs: number | null;
  percent: number | null;
};

function base64UrlEncode(value: string): string {
  const bytes = new TextEncoder().encode(value);
  let bin = "";
  bytes.forEach((b) => {
    bin += String.fromCharCode(b);
  });
  return btoa(bin).replace(/\+/g, "-").replace(/\//g, "_").replace(/=+$/g, "");
}

function base64UrlDecode(value: string): string | null {
  const b64 = value.replace(/-/g, "+").replace(/_/g, "/");
  const pad = b64.length % 4 === 0 ? "" : "=".repeat(4 - (b64.length % 4));
  try {
    const bin = atob(b64 + pad);
    const bytes = Uint8Array.from(bin, (c) => c.charCodeAt(0));
    return new TextDecoder().decode(bytes);
  } catch {
    return null;
  }
}

function sanitizeIds(raw: unknown): string[] {
  if (!Array.isArray(raw)) return [];
  const out: string[] = [];
  for (const item of raw) {
    if (typeof item !== "string") continue;
    const v = item.trim();
    if (!v || v.length > 128) continue;
    if (!out.includes(v)) out.push(v);
  }
  return out;
}

export function buildChallengeSlug(input: {
  ids: string[];
  by?: string;
  elapsedMs?: number;
  percent?: number;
}): string {
  const payload: ChallengePayloadV1 = {
    v: 1,
    ids: sanitizeIds(input.ids).slice(0, 64),
    by: input.by?.trim() || undefined,
    elapsedMs:
      typeof input.elapsedMs === "number" && Number.isFinite(input.elapsedMs)
        ? Math.max(0, Math.floor(input.elapsedMs))
        : undefined,
    percent:
      typeof input.percent === "number" && Number.isFinite(input.percent)
        ? Math.max(0, Math.min(100, input.percent))
        : undefined,
  };
  return base64UrlEncode(JSON.stringify(payload));
}

export function parseChallengeSlug(slug: string): DecodedChallenge | null {
  const raw = base64UrlDecode(slug.trim());
  if (!raw) return null;
  try {
    const parsed = JSON.parse(raw) as Partial<ChallengePayloadV1>;
    if (parsed.v !== 1) return null;
    const ids = sanitizeIds(parsed.ids).slice(0, 64);
    if (ids.length === 0) return null;
    return {
      ids,
      by: typeof parsed.by === "string" && parsed.by.trim() ? parsed.by.trim() : "Unknown_Operator",
      elapsedMs:
        typeof parsed.elapsedMs === "number" && Number.isFinite(parsed.elapsedMs)
          ? Math.max(0, Math.floor(parsed.elapsedMs))
          : null,
      percent:
        typeof parsed.percent === "number" && Number.isFinite(parsed.percent)
          ? Math.max(0, Math.min(100, parsed.percent))
          : null,
    };
  } catch {
    return null;
  }
}
