import type { ArenaQuestion } from "./questionContent";
import { getQuestionOracleHint } from "../data/questionHints";

/** Muss mit `consumeArenaNeuralHintCost` im Store übereinstimmen */
export const ARENA_NEURAL_GEM_COST = 2;

/** UI-Regel: kein Satzzeichen am Textende (Edge-Antworten mittrimmen) */
export function stripOracleTerminalPunctuation(text: string): string {
  return text.replace(/[.!?…]+$/u, "").trim();
}

function buildSyntheticNeuralFragment(q: ArenaQuestion): string {
  const t = q.tags[0] ?? "null";
  const slugShort = q.slug.slice(0, 14);
  return `[Ghost · ${t}] · Träger ${slugShort} · die Nadel zittert dort wo die erste Antwort nur Täuschrauschen war`;
}

async function fetchArenaHintFromEdge(q: ArenaQuestion, signal?: AbortSignal): Promise<string | null> {
  const custom = import.meta.env.VITE_ARENA_HINT_FUNCTION_URL?.trim();
  const base = (import.meta.env.VITE_SUPABASE_URL as string | undefined)?.replace(/\/$/, "") ?? "";
  const anon = (import.meta.env.VITE_SUPABASE_ANON_KEY as string | undefined)?.trim() ?? "";
  const url = custom || (base && anon ? `${base}/functions/v1/arena-hint` : "");
  if (!url || !anon) return null;
  try {
    const res = await fetch(url, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        Authorization: `Bearer ${anon}`,
        apikey: anon,
      },
      body: JSON.stringify({
        questionId: q.id,
        slug: q.slug,
        tags: q.tags,
        prompt: q.prompt.slice(0, 420),
      }),
      signal,
    });
    if (!res.ok) return null;
    const data = (await res.json()) as { hint?: unknown };
    const h = data?.hint;
    if (typeof h !== "string" || !h.trim()) return null;
    return stripOracleTerminalPunctuation(h.trim());
  } catch {
    return null;
  }
}

/** Registry → Bank-Hint → Edge → synthetischer Funk-Scrap */
export async function resolveNeuralHint(q: ArenaQuestion, signal?: AbortSignal): Promise<string> {
  const fromRegistry = getQuestionOracleHint(q.id, q.slug);
  if (fromRegistry?.trim()) return stripOracleTerminalPunctuation(fromRegistry.trim());
  if (q.hint?.trim()) return stripOracleTerminalPunctuation(q.hint.trim());
  const remote = await fetchArenaHintFromEdge(q, signal);
  if (remote) return remote;
  return buildSyntheticNeuralFragment(q);
}
