import { useEffect, useRef } from "react";
import {
  setAmbientHotZoneEscalationEnabled,
  setAmbientTerminalAudioEnabled,
  triggerAudioCue,
} from "../lib/webAudioUi";
import { useAppStore } from "../store/useAppStore";

/**
 * Phase 68 — systemweite Audio-Feedback-Bridge
 * Nutzt Store-States, feuert Cues latenzarm und steuert Ambient-Hum
 */
export function useAudioFeedback(): void {
  const enabled = useAppStore((s) => s.feedbackEnabled);
  const activeSection = useAppStore((s) => s.activeSection);
  const levelUpCelebration = useAppStore((s) => s.levelUpCelebration);
  const promotionCelebration = useAppStore((s) => s.promotionCelebration);
  const medalHead = useAppStore((s) => s.medalToastQueue[0] ?? null);
  const factionWarPulseKey = useAppStore((s) => s.factionWarPulseKey);
  const hotZoneActive = useAppStore((s) => !!s.duelState?.bountyHotZone);

  const prevSectionRef = useRef(activeSection);
  const prevLevelKeyRef = useRef<number | null>(null);
  const prevPromoKeyRef = useRef<string | null>(null);
  const prevMedalRef = useRef<string | null>(null);
  const prevWarPulseRef = useRef<string | null>(null);

  useEffect(() => {
    if (prevSectionRef.current !== activeSection) {
      if (enabled) triggerAudioCue("CLICK");
      prevSectionRef.current = activeSection;
    }
  }, [activeSection, enabled]);

  useEffect(() => {
    const key = levelUpCelebration?.level ?? null;
    if (key != null && key !== prevLevelKeyRef.current && enabled) {
      triggerAudioCue("LEVEL_UP");
    }
    prevLevelKeyRef.current = key;
  }, [levelUpCelebration, enabled]);

  useEffect(() => {
    const key = promotionCelebration
      ? `${promotionCelebration.fromIndex}->${promotionCelebration.toIndex}`
      : null;
    if (key && key !== prevPromoKeyRef.current && enabled) {
      triggerAudioCue("LEVEL_UP");
    }
    prevPromoKeyRef.current = key;
  }, [promotionCelebration, enabled]);

  useEffect(() => {
    if (medalHead && medalHead !== prevMedalRef.current && enabled) {
      triggerAudioCue("LEVEL_UP");
    }
    prevMedalRef.current = medalHead;
  }, [medalHead, enabled]);

  useEffect(() => {
    if (factionWarPulseKey && factionWarPulseKey !== prevWarPulseRef.current && enabled) {
      triggerAudioCue("WAR_PULSE");
    }
    prevWarPulseRef.current = factionWarPulseKey;
  }, [factionWarPulseKey, enabled]);

  useEffect(() => {
    setAmbientTerminalAudioEnabled(enabled);
    return () => {
      setAmbientHotZoneEscalationEnabled(false);
      setAmbientTerminalAudioEnabled(false);
    };
  }, [enabled]);

  useEffect(() => {
    setAmbientHotZoneEscalationEnabled(enabled && hotZoneActive);
    return () => {
      setAmbientHotZoneEscalationEnabled(false);
    };
  }, [enabled, hotZoneActive]);
}
