import { motion, useReducedMotion } from "framer-motion";
import { useCallback, useEffect, useMemo, useRef, useState } from "react";
import mockTickets from "../../data/mock_tickets.json";
import type { SupportTicket, SupportTicketSeverity } from "../../data/ticketSchema";
import { buildMissionReport, type MissionReportPayload } from "../../lib/helpdeskMissionReport";
import { getArenaQuestionBySlug, type ArenaQuestion } from "../../lib/questionContent";
import { cn } from "../../lib/cn";
import { useAppStore } from "../../store/useAppStore";
import { HelpdeskDiagnosticOverlay } from "./HelpdeskDiagnosticOverlay";
import { MissionReportOverlay } from "./MissionReportOverlay";

const TYPEWRITER_MS = 20;
const REPORT_DELAY_MS = 520;

type TicketLife = "open" | "resolved" | "failed";

type SimSlice = {
  slaRemaining: Record<string, number>;
  ticketStatus: Record<string, TicketLife>;
};

function formatSla(seconds: number): string {
  const m = Math.floor(seconds / 60);
  const s = seconds % 60;
  return `${m}:${s.toString().padStart(2, "0")}`;
}

function severityLabel(sev: SupportTicketSeverity): string {
  if (sev === "critical") return "KRITISCH";
  if (sev === "high") return "HOCH";
  return "MITTEL";
}

function severityAccent(sev: SupportTicketSeverity): string {
  if (sev === "critical") return "text-red-300/90";
  if (sev === "high") return "text-amber-200/85";
  return "text-foreground-muted";
}

function initialSlaMap(tickets: SupportTicket[]): Record<string, number> {
  const o: Record<string, number> = {};
  for (const t of tickets) o[t.id] = t.slaSeconds;
  return o;
}

function initialSim(tickets: SupportTicket[]): SimSlice {
  return {
    slaRemaining: initialSlaMap(tickets),
    ticketStatus: Object.fromEntries(tickets.map((t) => [t.id, "open" as const])),
  };
}

function statusChip(status: TicketLife): { label: string; className: string } {
  if (status === "failed") return { label: "FAILED", className: "text-signal" };
  if (status === "resolved") return { label: "RESOLVED", className: "text-cyber-cyan/90" };
  return { label: "OPEN", className: "text-foreground-muted" };
}

export function HelpdeskTerminalView() {
  const tickets = useMemo(() => mockTickets as SupportTicket[], []);
  const prefersReduced = useReducedMotion();
  const [activeId, setActiveId] = useState<string | null>(tickets[0]?.id ?? null);
  const [sim, setSim] = useState<SimSlice>(() => initialSim(tickets));
  const prevTicketStatusRef = useRef<Record<string, TicketLife>>(initialSim(tickets).ticketStatus);
  const [reportPending, setReportPending] = useState<MissionReportPayload[]>([]);
  const [reportVisible, setReportVisible] = useState<MissionReportPayload | null>(null);
  const [logRevealLen, setLogRevealLen] = useState(0);
  const [diagOpen, setDiagOpen] = useState(false);
  const [diagQuestion, setDiagQuestion] = useState<ArenaQuestion | null>(null);

  const active = tickets.find((t) => t.id === activeId) ?? null;
  const fullLog = active?.incidentLog ?? "";
  const typewriterDone = !!active && logRevealLen >= fullLog.length;
  const visibleLog = fullLog.slice(0, logRevealLen);

  const activeStatus = activeId ? sim.ticketStatus[activeId] : undefined;
  const activeRem = activeId ? sim.slaRemaining[activeId] ?? 0 : 0;
  const canInitiateDiagnostics =
    !!active &&
    typewriterDone &&
    activeStatus === "open" &&
    activeRem > 0 &&
    !diagOpen;

  useEffect(() => {
    const id = window.setInterval(() => {
      setSim((s) => {
        const nextSla = { ...s.slaRemaining };
        const nextSt = { ...s.ticketStatus };
        for (const t of tickets) {
          const tid = t.id;
          if (nextSt[tid] === "resolved") continue;
          if (nextSt[tid] === "failed") {
            nextSla[tid] = 0;
            continue;
          }
          const r = Math.max(0, (nextSla[tid] ?? 0) - 1);
          nextSla[tid] = r;
          if (r === 0) nextSt[tid] = "failed";
        }
        return { slaRemaining: nextSla, ticketStatus: nextSt };
      });
    }, 1000);
    return () => clearInterval(id);
  }, [tickets]);

  useEffect(() => {
    if (!diagOpen || !activeId) return;
    if (sim.ticketStatus[activeId] === "failed") {
      setDiagOpen(false);
      setDiagQuestion(null);
    }
  }, [diagOpen, activeId, sim.ticketStatus]);

  useEffect(() => {
    const prev = prevTicketStatusRef.current;
    const next = sim.ticketStatus;
    const batch: MissionReportPayload[] = [];
    for (const t of tickets) {
      const was = prev[t.id] ?? "open";
      const now = next[t.id];
      if (was === "open" && (now === "resolved" || now === "failed")) {
        batch.push(buildMissionReport(t, now, sim.slaRemaining[t.id] ?? 0, t.slaSeconds));
      }
    }
    prevTicketStatusRef.current = { ...next };
    if (batch.length > 0) {
      setReportPending((p) => [...p, ...batch]);
    }
  }, [sim.ticketStatus, sim.slaRemaining, tickets]);

  useEffect(() => {
    if (reportVisible) return;
    if (reportPending.length === 0) return;
    const nextPayload = reportPending[0];
    const tid = window.setTimeout(() => {
      if (nextPayload.outcome === "resolved" && nextPayload.totalXp > 0) {
        useAppStore.getState().awardGlobalXp(nextPayload.totalXp);
      }
      setReportVisible(nextPayload);
      setReportPending((p) => p.slice(1));
    }, REPORT_DELAY_MS);
    return () => clearTimeout(tid);
  }, [reportVisible, reportPending]);

  useEffect(() => {
    if (!active) {
      setLogRevealLen(0);
      return;
    }
    const text = active.incidentLog;
    setLogRevealLen(0);
    let n = 0;
    const timer = window.setInterval(() => {
      n += 1;
      const next = Math.min(n, text.length);
      setLogRevealLen(next);
      if (next >= text.length) {
        window.clearInterval(timer);
      }
    }, TYPEWRITER_MS);
    return () => clearInterval(timer);
  }, [activeId, active?.incidentLog]);

  const onSelectTicket = useCallback((id: string) => {
    setActiveId(id);
    setDiagOpen(false);
    setDiagQuestion(null);
  }, []);

  const onInitiateDiagnostics = useCallback(() => {
    if (!active || !typewriterDone) return;
    if (sim.ticketStatus[active.id] !== "open") return;
    if ((sim.slaRemaining[active.id] ?? 0) <= 0) return;
    const q = getArenaQuestionBySlug(active.ihkQuestionSlug);
    setDiagQuestion(q);
    setDiagOpen(true);
  }, [active, sim.slaRemaining, sim.ticketStatus, typewriterDone]);

  const onDiagnosticWrongPick = useCallback(() => {
    if (!active) return;
    setSim((s) => {
        const tid = active.id;
        const newRem = Math.max(0, Math.floor((s.slaRemaining[tid] ?? 0) / 2));
        const nextSt = { ...s.ticketStatus };
        if (newRem === 0) nextSt[tid] = "failed";
        return {
          slaRemaining: { ...s.slaRemaining, [tid]: newRem },
          ticketStatus: nextSt,
        };
      });
  }, [active]);

  const onDiagnosticCorrectCommit = useCallback(
    (idx: number) => {
      if (!active || !diagQuestion) return;
      if (idx !== diagQuestion.correctIndex) return;
      useAppStore.getState().recordHelpdeskDiagnosticClear();
      setSim((s) => ({
        slaRemaining: s.slaRemaining,
        ticketStatus: { ...s.ticketStatus, [active.id]: "resolved" },
      }));
      setDiagOpen(false);
      setDiagQuestion(null);
    },
    [active, diagQuestion],
  );

  const onCloseOverlay = useCallback(() => {
    setDiagOpen(false);
    setDiagQuestion(null);
  }, []);

  const onDismissMissionReport = useCallback(() => {
    setReportVisible(null);
  }, []);

  return (
    <>
      <div className="flex min-h-[min(70vh,560px)] w-full flex-col border border-white/[0.08] bg-black/55 text-foreground sm:flex-row">
        <aside className="flex w-full shrink-0 flex-col border-b border-white/[0.08] sm:w-[280px] sm:border-b-0 sm:border-r">
          <div className="border-b border-white/[0.08] px-3 py-2 font-mono text-[10px] uppercase tracking-[0.28em] text-foreground-muted">
            Inbound Queue
          </div>
          <div className="relative flex-1 overflow-y-auto">
            <div className="pointer-events-none absolute inset-0 hud-grid opacity-[0.06]" aria-hidden />
            <ul className="relative divide-y divide-white/[0.06]">
              {tickets.map((t) => {
                const on = t.id === activeId;
                const st = sim.ticketStatus[t.id] ?? "open";
                const rem = sim.slaRemaining[t.id] ?? 0;
                const chip = statusChip(st);
                const stress = st === "open" && rem > 0 && rem < 15;
                return (
                  <li key={t.id}>
                    <button
                      type="button"
                      onClick={() => onSelectTicket(t.id)}
                      className={cn(
                        "w-full px-3 py-2.5 text-left font-mono text-[11px] transition-colors hover:bg-white/[0.04]",
                        on && "bg-white/[0.06]",
                      )}
                    >
                      <div className="flex items-center justify-between gap-2">
                        <span className={cn("text-[9px] font-semibold uppercase tracking-wider", severityAccent(t.severity))}>
                          {severityLabel(t.severity)}
                        </span>
                        <span className={cn("text-[9px] font-bold uppercase tracking-wider", chip.className)}>{chip.label}</span>
                      </div>
                      <div className="mt-1 flex items-center justify-between gap-2">
                        {st === "failed" ? (
                          <span className="font-mono text-[10px] font-semibold uppercase tracking-wider text-signal">SLA breached</span>
                        ) : stress && !prefersReduced ? (
                          <motion.span
                            className="tabular-nums text-[10px] font-medium text-signal"
                            animate={{ opacity: [1, 0.38, 1] }}
                            transition={{ duration: 0.55, repeat: Infinity, ease: "easeInOut" }}
                          >
                            SLA {formatSla(rem)}
                          </motion.span>
                        ) : (
                          <span
                            className={cn(
                              "tabular-nums text-[10px] font-medium",
                              stress ? "text-signal" : "text-foreground-muted",
                            )}
                          >
                            SLA {formatSla(rem)}
                          </span>
                        )}
                      </div>
                      <p className="mt-1 line-clamp-2 font-sans text-xs font-medium tracking-tight text-foreground/88">{t.title}</p>
                      <p className="mt-0.5 truncate text-[10px] text-cyber-cyan/80">ihk:{t.ihkQuestionSlug}</p>
                    </button>
                  </li>
                );
              })}
            </ul>
          </div>
        </aside>

        <section className="relative flex min-h-[280px] flex-1 flex-col">
          <div className="pointer-events-none absolute inset-0 hud-grid opacity-[0.08]" aria-hidden />
          <div className="relative flex flex-1 flex-col border-b border-white/[0.08] px-4 py-2 sm:border-b-0">
            <div className="font-mono text-[10px] uppercase tracking-[0.26em] text-foreground-muted">Kommandokanal</div>
            <div className="mt-3 flex flex-1 flex-col rounded-none border border-white/[0.06] bg-black/40 p-4">
              {active ? (
                <>
                  <div className="text-[10px] font-mono uppercase tracking-[0.2em] text-foreground-muted">Incident Log</div>
                  <pre className="mt-2 min-h-[4.5rem] flex-1 whitespace-pre-wrap font-mono text-[11px] leading-relaxed text-foreground/75">
                    {visibleLog}
                    {!typewriterDone ? <span className="inline-block w-2 animate-pulse bg-foreground/35 align-baseline" aria-hidden /> : null}
                  </pre>
                  <div className="mt-4 border-t border-white/[0.06] pt-3">
                    <button
                      type="button"
                      disabled={!canInitiateDiagnostics}
                      onClick={onInitiateDiagnostics}
                      className={cn(
                        "border px-4 py-2 font-mono text-[10px] font-semibold uppercase tracking-[0.22em] transition-colors",
                        canInitiateDiagnostics
                          ? "border-signal/50 bg-signal/10 text-signal hover:bg-signal/18"
                          : "cursor-not-allowed border-white/[0.08] bg-transparent text-foreground-muted opacity-45",
                      )}
                    >
                      INITIATE DIAGNOSTICS
                    </button>
                    {activeStatus === "failed" ? (
                      <p className="mt-2 font-mono text-[10px] uppercase tracking-[0.16em] text-signal">Ticket FAILED wegen SLA auf Null</p>
                    ) : null}
                  </div>
                </>
              ) : (
                <div className="flex h-full flex-col items-center justify-center gap-2 px-4 text-center font-mono text-[10px] uppercase tracking-[0.2em] text-foreground-muted">
                  <span>Kommandorampe leer</span>
                  <span className="text-[9px] tracking-[0.16em]">Ticket in der Sidebar wählen</span>
                </div>
              )}
            </div>
          </div>
          <div className="relative border-t border-white/[0.08] px-4 py-2.5 font-mono text-[10px] uppercase tracking-[0.22em] text-foreground-muted">
            Monitoring-Raster und IHK-Slug-Anker bereit
          </div>
        </section>
      </div>

      <HelpdeskDiagnosticOverlay
        open={diagOpen}
        question={diagQuestion}
        onClose={onCloseOverlay}
        onWrongPick={onDiagnosticWrongPick}
        onCorrectCommit={onDiagnosticCorrectCommit}
      />

      <MissionReportOverlay open={!!reportVisible} payload={reportVisible} onDismiss={onDismissMissionReport} />
    </>
  );
}
