/** Axial-Koordinaten (q,r) mit s = -q-r — Pointy-Top Pixel (Red Blob Games) */

export const AXIAL_NEIGHBORS: readonly [number, number][] = [
  [1, 0],
  [1, -1],
  [0, -1],
  [-1, 0],
  [-1, 1],
  [0, 1],
] as const;

export function tileKey(q: number, r: number): string {
  return `${q},${r}`;
}

export function parseTileKey(key: string): { q: number; r: number } | null {
  const [a, b] = key.split(",").map(Number);
  if (Number.isNaN(a) || Number.isNaN(b)) return null;
  return { q: a, r: b };
}

/** Hex-Radius 2 um Ursprung (19 Felder) */
export function realmHexCoordinates(): { q: number; r: number }[] {
  const out: { q: number; r: number }[] = [];
  for (let q = -2; q <= 2; q++) {
    for (let r = -2; r <= 2; r++) {
      const s = -q - r;
      if (Math.max(Math.abs(q), Math.abs(r), Math.abs(s)) <= 2) {
        out.push({ q, r });
      }
    }
  }
  return out;
}

export function axialNeighbors(q: number, r: number): { q: number; r: number }[] {
  return AXIAL_NEIGHBORS.map(([dq, dr]) => ({ q: q + dq, r: r + dr }));
}

/** Pointy-top axial → Pixel; size = Abstand Mitte zu Ecke */
export function axialToPixel(
  q: number,
  r: number,
  size: number,
): { x: number; y: number } {
  const x = size * Math.sqrt(3) * (q + r / 2);
  const y = size * (3 / 2) * r;
  return { x, y };
}

export interface PlacedHex {
  q: number;
  r: number;
  px: number;
  py: number;
}

/** Layout für absolut positionierte Hex-Zellen, zentriert */
export function computeHexLayout(
  coords: readonly { q: number; r: number }[],
  size: number,
): { hexes: PlacedHex[]; boxW: number; boxH: number } {
  const raw = coords.map(({ q, r }) => {
    const { x, y } = axialToPixel(q, r, size);
    return { q, r, x, y };
  });
  const xs = raw.map((p) => p.x);
  const ys = raw.map((p) => p.y);
  const minX = Math.min(...xs);
  const maxX = Math.max(...xs);
  const minY = Math.min(...ys);
  const maxY = Math.max(...ys);
  const pad = size * 2.2;
  const boxW = maxX - minX + pad * 2;
  const boxH = maxY - minY + pad * 2;
  const hexes = raw.map((p) => ({
    q: p.q,
    r: p.r,
    px: p.x - minX + pad,
    py: p.y - minY + pad,
  }));
  return { hexes, boxW, boxH };
}
