import { AnimatePresence, motion, useReducedMotion } from "framer-motion";
import { useEffect, useMemo, useState } from "react";
import { CodeSnapLogo } from "../brand/CodeSnapLogo";
import { ArtifactPedestal } from "../profile/ArtifactPedestal";
import { SignalLineTrack } from "../system/SignalActivityLine";
import { getRankArtifact } from "../../lib/rankEngine";
import { springHeavy, cinematicStaggerRoot, cinematicBandDeep, cinematicBandMid, cinematicBandShallow } from "../../motion/variants";
import { useFeedback } from "../../hooks/useFeedback";
import { cn } from "../../lib/cn";
import { useAppStore, type CareerPath } from "../../store/useAppStore";

const LOG_LINES = [
  "Checking kernel lattice",
  "Mounting silent operator shell",
  "Establishing secure uplink",
  "Routing biometric signal",
  "Preparing dossier memory",
  "Verifying identity envelope",
  "Granting mission clearance",
] as const;

const CAREER_CARDS: Array<{
  id: CareerPath;
  title: string;
  ihkTitle: string;
  blurb: string;
  stats: string[];
  frameClass: string;
  glowClass: string;
}> = [
  {
    id: "FISI",
    title: "FISI",
    ihkTitle: "Fachinformatiker für Systemintegration",
    blurb: "Netzwerke Systeme Hardening und Infrastruktur unter Druck",
    stats: ["Ops", "Security", "Support"],
    frameClass: "border-cyan-400/35 shadow-[inset_0_0_0_1px_rgb(34_211_238_/0.22),0_0_42px_rgb(34_211_238_/0.12)]",
    glowClass: "from-cyan-400/14 via-transparent to-transparent",
  },
  {
    id: "FIAE",
    title: "FIAE",
    ihkTitle: "Fachinformatiker für Anwendungsentwicklung",
    blurb: "Code Architektur Automatisierung und präzise Produktlogik",
    stats: ["Code", "SQL", "Systems"],
    frameClass: "border-fuchsia-400/35 shadow-[inset_0_0_0_1px_rgb(232_121_249_/0.22),0_0_42px_rgb(232_121_249_/0.12)]",
    glowClass: "from-fuchsia-400/14 via-transparent to-transparent",
  },
];

export function OnboardingOrchestrator() {
  const prefersReduced = useReducedMotion();
  const feedback = useFeedback();
  const authReady = useAppStore((s) => s.authReady);
  const authUser = useAppStore((s) => s.authUser);
  const cloudUplinkBusy = useAppStore((s) => s.cloudUplinkBusy);
  const cloudLastError = useAppStore((s) => s.cloudLastError);
  const onboardingVisible = useAppStore((s) => s.onboardingVisible);
  const onboardingStep = useAppStore((s) => s.onboardingStep);
  const onboardingHandleDraft = useAppStore((s) => s.onboardingHandleDraft);
  const careerPath = useAppStore((s) => s.careerPath);
  const setOnboardingStep = useAppStore((s) => s.setOnboardingStep);
  const setOnboardingHandleDraft = useAppStore((s) => s.setOnboardingHandleDraft);
  const setCareerPath = useAppStore((s) => s.setCareerPath);
  const finishOnboarding = useAppStore((s) => s.finishOnboarding);
  const setActiveSection = useAppStore((s) => s.setActiveSection);
  const [accessGranted, setAccessGranted] = useState(false);
  const [arrivalZoom, setArrivalZoom] = useState(false);
  const rankArtifact = getRankArtifact(0);

  useEffect(() => {
    if (!onboardingVisible || onboardingStep !== "boot") {
      setAccessGranted(false);
      return;
    }
    const first = window.setTimeout(() => setAccessGranted(true), prefersReduced ? 120 : 1700);
    const second = window.setTimeout(() => setOnboardingStep("handle"), prefersReduced ? 540 : 2800);
    return () => {
      window.clearTimeout(first);
      window.clearTimeout(second);
    };
  }, [onboardingVisible, onboardingStep, prefersReduced, setOnboardingStep]);

  const handleValid = /^[A-Za-z0-9_]{3,24}$/.test(onboardingHandleDraft.trim().replace(/\s+/g, "_"));
  const oathReady = handleValid && !!careerPath && !!authUser;
  const oathSummary = useMemo(
    () => [
      `Operator ${onboardingHandleDraft.trim() || "Unknown_Operator"}`,
      `Pfad ${careerPath ?? "Nicht gewählt"}`,
      "Mission IHK Erfolg und operative Ruhe",
    ],
    [careerPath, onboardingHandleDraft],
  );

  if (!onboardingVisible || !authReady || !authUser) return null;

  const goNextFromHandle = () => {
    if (!handleValid) return;
    feedback.terminalKey();
    setOnboardingStep("career");
  };

  const complete = async () => {
    if (!careerPath || !handleValid) return;
    feedback.dossierSyncedElite();
    const result = await import("../../lib/syncController").then((m) =>
      m.completeIdentityOnboarding({
        handle: onboardingHandleDraft.trim().replace(/\s+/g, "_"),
        careerPath,
      }),
    );
    if (!result.ok) return;
    setOnboardingStep("arrival");
    setArrivalZoom(true);
    window.setTimeout(() => {
      setActiveSection("profile");
      finishOnboarding();
      setArrivalZoom(false);
    }, prefersReduced ? 180 : 820);
  };

  return (
    <AnimatePresence>
      <motion.div
        key="identity-uplink"
        className="fixed inset-0 z-[340] overflow-hidden bg-black"
        initial={{ opacity: 0 }}
        animate={{ opacity: 1 }}
        exit={{ opacity: 0 }}
      >
        <div className="absolute inset-0 hud-grid opacity-[0.08]" />
        <div className="absolute inset-0 bg-[radial-gradient(circle_at_center,rgb(255_255_255_/_0.04),transparent_58%)]" />
        <div className="absolute inset-0 onboarding-noise opacity-20" />
        <div className="relative mx-auto flex min-h-dvh max-w-[1240px] items-center justify-center px-6 py-10">
          <motion.div
            animate={arrivalZoom ? { scale: 1.08, opacity: 0.2 } : { scale: 1, opacity: 1 }}
            transition={springHeavy}
            className="w-full max-w-5xl"
          >
            {onboardingStep === "boot" ? (
              <div className="space-y-8 border border-white/[0.08] bg-black/72 p-8 sm:p-12">
                <div className="space-y-4">
                  {LOG_LINES.map((line, index) => (
                    <motion.p
                      key={line}
                      initial={{ opacity: 0, x: -12 }}
                      animate={{ opacity: accessGranted ? 0.3 : 0.86, x: 0 }}
                      transition={{ delay: prefersReduced ? 0 : index * 0.12, duration: 0.3 }}
                      className="font-mono text-[11px] uppercase tracking-[0.28em] text-white/72"
                    >
                      {line}
                    </motion.p>
                  ))}
                </div>
                <AnimatePresence>
                  {accessGranted ? (
                    <motion.div
                      initial={{ opacity: 0, scale: 0.94 }}
                      animate={{ opacity: 1, scale: 1 }}
                      exit={{ opacity: 0 }}
                      transition={springHeavy}
                      className="border border-white/[0.1] bg-white/[0.03] px-6 py-8 text-center"
                    >
                      <p className="font-mono text-[10px] uppercase tracking-[0.36em] text-foreground-muted">
                        Identity Uplink
                      </p>
                      <h1 className="mt-4 headline-cinema text-5xl font-semibold sm:text-7xl">
                        ACCESS GRANTED
                      </h1>
                    </motion.div>
                  ) : null}
                </AnimatePresence>
              </div>
            ) : null}

            {onboardingStep !== "boot" ? (
              <motion.div variants={cinematicStaggerRoot} initial="initial" animate="animate" className="space-y-8">
                <motion.div variants={cinematicBandDeep} className="flex items-center justify-between gap-4 border border-white/[0.08] bg-black/70 px-6 py-5">
                  <div className="space-y-2">
                    <p className="font-mono text-[10px] uppercase tracking-[0.34em] text-foreground-muted">
                      The Identity Uplink
                    </p>
                    <div className="flex items-center gap-4">
                      <CodeSnapLogo heightClass="h-10 sm:h-12" />
                      <p className="font-sans text-sm text-foreground-muted">
                        Operator-Erfassung mit schwerem Raster und gebundener Mission
                      </p>
                    </div>
                  </div>
                  <div className="w-full max-w-[220px]">
                    <SignalLineTrack progress={onboardingStep === "arrival" ? 100 : onboardingStep === "oath" ? 76 : onboardingStep === "career" ? 52 : 28} />
                  </div>
                </motion.div>

                {onboardingStep === "handle" ? (
                  <motion.div variants={cinematicBandMid} className="border border-white/[0.08] bg-black/68 p-8">
                    <p className="font-mono text-[10px] uppercase tracking-[0.34em] text-foreground-muted">
                      Identify Operator
                    </p>
                    <div className="mt-6 grid gap-8 lg:grid-cols-[1fr_220px]">
                      <div className="space-y-4">
                        <h2 className="headline-cinema text-4xl font-semibold sm:text-6xl">
                          Handle festlegen
                        </h2>
                        <p className="max-w-2xl font-sans text-sm leading-relaxed text-foreground-muted">
                          Der biometrische Uplink bindet deinen öffentlichen Operator Namen an das System
                        </p>
                        <div className="relative border border-white/[0.1] px-4 py-4">
                          <div className="pointer-events-none absolute inset-0 overflow-hidden">
                            <motion.div
                              className="absolute inset-y-0 left-[-20%] w-[40%] bg-gradient-to-r from-transparent via-white/20 to-transparent"
                              animate={prefersReduced ? { x: "110%" } : { x: ["0%", "280%"] }}
                              transition={prefersReduced ? { duration: 0.3 } : { duration: 1.4, repeat: Infinity, ease: "linear" }}
                            />
                          </div>
                          <input
                            autoFocus
                            type="text"
                            maxLength={24}
                            value={onboardingHandleDraft}
                            onChange={(e) => setOnboardingHandleDraft(e.target.value)}
                            className="relative z-10 w-full bg-transparent font-mono text-2xl tracking-[0.06em] text-foreground outline-none placeholder:text-foreground-muted/55"
                            placeholder="Unknown_Operator"
                          />
                        </div>
                        <p className={cn("font-mono text-[10px] uppercase tracking-[0.22em]", handleValid ? "text-foreground-muted" : "text-signal")}>
                          {handleValid ? "Handle bereit" : "Nutze 3 bis 24 Zeichen aus A Z 0 9 oder _"}
                        </p>
                        <motion.button
                          type="button"
                          whileTap={{ scale: 0.94, y: 3 }}
                          transition={springHeavy}
                          disabled={!handleValid}
                          onClick={goNextFromHandle}
                          className="border border-white/[0.1] bg-white/[0.04] px-6 py-3 font-mono text-[11px] uppercase tracking-[0.22em] text-foreground disabled:opacity-35"
                        >
                          Scan bestätigen
                        </motion.button>
                      </div>
                      <div className="w-36 justify-self-start saturate-90 lg:justify-self-end">
                        <ArtifactPedestal artifact={rankArtifact} variant="hero" className="border-white/[0.08] bg-black/55" />
                      </div>
                    </div>
                  </motion.div>
                ) : null}

                {onboardingStep === "career" ? (
                  <motion.div variants={cinematicBandMid} className="space-y-6">
                    <div className="space-y-3 border border-white/[0.08] bg-black/55 px-5 py-4 sm:px-6">
                      <p className="font-mono text-[10px] uppercase tracking-[0.34em] text-foreground-muted">
                        Career Path Selection
                      </p>
                      <h2 className="headline-cinema text-4xl font-semibold sm:text-6xl">Klasse wählen</h2>
                      <p className="max-w-3xl font-sans text-sm leading-relaxed text-foreground-muted">
                        Diese Wahl prägt Daily Grind Missionen und Fraktionsdrift bevor du die Arcade öffnest
                      </p>
                    </div>
                    <div className="grid gap-5 lg:grid-cols-2">
                      {CAREER_CARDS.map((card, index) => (
                        <motion.button
                          key={card.id}
                          type="button"
                          variants={index === 0 ? cinematicBandMid : cinematicBandShallow}
                          whileTap={{ scale: 0.94, y: 3 }}
                          transition={springHeavy}
                          onClick={() => {
                            feedback.menuTap();
                            setCareerPath(card.id);
                            setOnboardingStep("oath");
                          }}
                          className={cn(
                            "relative overflow-hidden border bg-black/72 p-6 text-left transition-[box-shadow,transform] duration-300 hover-breathe sm:p-8",
                            card.frameClass,
                            careerPath === card.id ? "ring-1 ring-white/20" : "ring-0 ring-transparent",
                          )}
                        >
                          <div
                            className={cn(
                              "pointer-events-none absolute inset-0 bg-gradient-to-br opacity-90",
                              card.glowClass,
                            )}
                            aria-hidden
                          />
                          <div className="relative space-y-4">
                            <div className="flex flex-wrap items-baseline justify-between gap-3">
                              <p className="font-mono text-[10px] uppercase tracking-[0.3em] text-foreground-muted">
                                IHK Berufsrolle
                              </p>
                              <span className="border border-white/[0.12] bg-white/[0.04] px-2 py-0.5 font-mono text-[9px] uppercase tracking-[0.28em] text-foreground-muted">
                                Pflichtfeld
                              </span>
                            </div>
                            <h3 className="headline-cinema text-5xl font-semibold tracking-tight sm:text-6xl">{card.title}</h3>
                            <p className="font-sans text-xs font-semibold uppercase tracking-[0.18em] text-foreground/90 sm:text-sm">
                              {card.ihkTitle}
                            </p>
                            <p className="max-w-md font-sans text-sm leading-relaxed text-foreground-muted">{card.blurb}</p>
                            <div className="flex flex-wrap gap-2 pt-1">
                              {card.stats.map((stat) => (
                                <span
                                  key={stat}
                                  className="border border-white/[0.1] bg-white/[0.04] px-3 py-1 font-mono text-[10px] uppercase tracking-[0.18em] text-foreground-muted"
                                >
                                  {stat}
                                </span>
                              ))}
                            </div>
                          </div>
                        </motion.button>
                      ))}
                    </div>
                  </motion.div>
                ) : null}

                {onboardingStep === "oath" ? (
                  <motion.div variants={cinematicBandMid} className="border border-white/[0.08] bg-black/68 p-8">
                    <p className="font-mono text-[10px] uppercase tracking-[0.34em] text-foreground-muted">
                      The Oath And Sync
                    </p>
                    <div className="mt-5 grid gap-8 lg:grid-cols-[1fr_220px]">
                      <div className="space-y-5">
                        <h2 className="headline-cinema text-4xl font-semibold sm:text-6xl">
                          Mission bestätigen
                        </h2>
                        <p className="max-w-2xl font-sans text-sm leading-relaxed text-foreground-muted">
                          Dein Handle und dein Pfad werden in das System gespiegelt und an das Dossier gebunden
                        </p>
                        <div className="space-y-3 border border-white/[0.08] bg-white/[0.03] p-4">
                          {oathSummary.map((line) => (
                            <p key={line} className="font-mono text-[11px] uppercase tracking-[0.22em] text-foreground/86">
                              {line}
                            </p>
                          ))}
                        </div>
                        {cloudLastError ? (
                          <p className="font-mono text-[10px] uppercase tracking-[0.22em] text-signal">
                            {cloudLastError}
                          </p>
                        ) : null}
                        <motion.button
                          type="button"
                          whileTap={{ scale: 0.94, y: 3 }}
                          transition={springHeavy}
                          onClick={() => void complete()}
                          disabled={!oathReady || cloudUplinkBusy}
                          className="border border-white/[0.1] bg-white/[0.05] px-6 py-3 font-mono text-[11px] uppercase tracking-[0.24em] text-foreground disabled:opacity-35"
                        >
                          Identity Uplink bestätigen
                        </motion.button>
                      </div>
                      <div className="space-y-4">
                        <ArtifactPedestal artifact={rankArtifact} variant="hero" className="border-white/[0.08] bg-black/55" />
                        {cloudUplinkBusy ? <SignalLineTrack progress={100} /> : null}
                      </div>
                    </div>
                  </motion.div>
                ) : null}

                {onboardingStep === "arrival" ? (
                  <motion.div variants={cinematicBandShallow} className="border border-white/[0.08] bg-black/70 p-8 text-center">
                    <p className="font-mono text-[10px] uppercase tracking-[0.34em] text-foreground-muted">
                      Dossier Arrival
                    </p>
                    <h2 className="mt-4 headline-cinema text-5xl font-semibold sm:text-7xl">
                      Operator Dossier
                    </h2>
                    <p className="mt-4 font-sans text-sm text-foreground-muted">
                      Iron Node ist online und wartet auf den ersten Zugriff
                    </p>
                  </motion.div>
                ) : null}
              </motion.div>
            ) : null}
          </motion.div>
        </div>
      </motion.div>
    </AnimatePresence>
  );
}
