import { useEffect, useState } from "react";
import { motion } from "framer-motion";
import { cn } from "../../lib/cn";
import { useAppStore } from "../../store/useAppStore";

function formatCountdown(remainMs: number): string {
  const sec = Math.max(0, Math.ceil(remainMs / 1000));
  const m = Math.floor(sec / 60);
  const s = sec % 60;
  return `${m}:${s.toString().padStart(2, "0")}`;
}

/**
 * Phase 52 — nur sichtbar bei aktivem globalem Event
 * Texte ohne Satzzeichen am Ende
 */
export function GlobalLiveEventRibbon() {
  const globalLiveEvent = useAppStore((s) => s.globalLiveEvent);
  const serverTimeOffsetMs = useAppStore((s) => s.serverTimeOffsetMs);
  const [, bump] = useState(0);

  useEffect(() => {
    if (!globalLiveEvent) return;
    const id = window.setInterval(() => bump((n) => n + 1), 1000);
    return () => window.clearInterval(id);
  }, [globalLiveEvent]);

  if (!globalLiveEvent) return null;

  const effectiveNow = Date.now() + serverTimeOffsetMs;
  const remain = globalLiveEvent.endsAtMs - effectiveNow;
  const cd = formatCountdown(remain);

  return (
    <motion.div
      layout
      initial={{ opacity: 0, scale: 0.98 }}
      animate={{ opacity: 1, scale: 1 }}
      className="mx-auto flex min-w-0 max-w-[min(100%,320px)] flex-1 flex-col items-stretch px-1 text-center sm:max-w-[min(100%,420px)] sm:px-2"
    >
      <div
        className={cn(
          "inline-flex min-w-0 flex-col items-center justify-center gap-0.5 rounded-md border border-amber-400/35",
          "bg-amber-500/[0.09] px-3 py-1.5 shadow-[inset_0_0_0_1px_rgb(251_191_36_/0.12),0_0_20px_rgb(251_191_36_/0.08)]",
        )}
      >
        <p className="truncate font-mono text-[10px] font-extrabold uppercase tracking-[0.2em] text-amber-100">
          {globalLiveEvent.headlineShort} · {globalLiveEvent.tagline}
        </p>
        <p className="font-mono text-[9px] font-semibold uppercase tracking-[0.24em] text-amber-200/85">
          Bonus endet in {cd}
        </p>
      </div>
    </motion.div>
  );
}
