/**
 * SuperMemo-2 (SM-2) — reine Intervall- und EF-Logik
 * Qualität: 0 = wiederholen, 3 = schwer, 4 = gut, 5 = leicht (klassisches 0–5-Raster)
 */

import { DAILY_FLASHCARDS } from "../data/dailyFlashcards";

export type Sm2Quality = 0 | 3 | 4 | 5;

export interface Sm2CardState {
  /** Ease Factor, Minimum 1,3 */
  ef: number;
  /** zuletzt berechnetes Intervall in Tagen (nach letzter Bewertung) */
  interval: number;
  /** erfolgreiche Wiederholungen in Folge (wird bei Qualität unter 3 auf 0 gesetzt) */
  repetitions: number;
}

export type FlashcardProgressEntry = Sm2CardState & { nextReviewDate: number };

/** Standard-Startwerte vor der ersten Bewertung */
export const SM2_DEFAULT_STATE: Sm2CardState = {
  ef: 2.5,
  interval: 0,
  repetitions: 0,
};

/** EF-Update nach SM-2 (immer, auch bei niedriger Qualität) */
export function nextEaseFactor(ef: number, q: Sm2Quality): number {
  const delta = 0.1 - (5 - q) * (0.08 + (5 - q) * 0.02);
  return Math.max(1.3, ef + delta);
}

/**
 * Wendet eine Bewertung an — Intervall-Berechnung nutzt den EF **vor** diesem Schritt
 * (üblich: I_new = round(I_alt * EF_alt) bei repetitions ≥ 2)
 */
export function applySm2(card: Sm2CardState, q: Sm2Quality): Sm2CardState {
  const oldEf = card.ef;
  const oldInterval = card.interval;
  const oldReps = card.repetitions;

  const ef = nextEaseFactor(oldEf, q);

  if (q < 3) {
    return {
      ef,
      interval: 1,
      repetitions: 0,
    };
  }

  let interval: number;
  if (oldReps === 0) {
    interval = 1;
  } else if (oldReps === 1) {
    interval = 6;
  } else {
    interval = Math.max(1, Math.round(oldInterval * oldEf));
  }

  return {
    ef,
    interval,
    repetitions: oldReps + 1,
  };
}

/** Nächster Review-Zeitpunkt: lokaler Tagesbeginn + `intervalDays` Kalendertage */
export function computeNextReviewTimestamp(intervalDays: number, fromDate: Date = new Date()): number {
  const d = new Date(fromDate);
  d.setHours(0, 0, 0, 0);
  d.setDate(d.getDate() + intervalDays);
  return d.getTime();
}

/** Ende des lokalen Kalendertags (für „fällig heute“) */
export function endOfTodayTimestamp(fromDate: Date = new Date()): number {
  const d = new Date(fromDate);
  d.setHours(23, 59, 59, 999);
  return d.getTime();
}

/** UI-Label für das neue Intervall — ohne Punkt am Ende */
export function formatIntervalBadgeDays(intervalDays: number): string {
  if (intervalDays <= 0) return "Heute erneut";
  if (intervalDays === 1) return "In 1 Tag";
  return `In ${intervalDays} Tagen`;
}

export type FlashcardAnswerRating = "again" | "hard" | "good" | "easy";

export function flashRatingToSm2(rating: FlashcardAnswerRating): Sm2Quality {
  switch (rating) {
    case "again":
      return 0;
    case "hard":
      return 3;
    case "good":
      return 4;
    case "easy":
      return 5;
    default:
      return 4;
  }
}

/** Fällige Karten-IDs bis Tagesende, sortiert nach nächstem Review */
export function selectDueFlashcardIds(
  progress: Record<string, FlashcardProgressEntry>,
): string[] {
  const lim = endOfTodayTimestamp();
  const ids = DAILY_FLASHCARDS.map((c) => c.id).filter((id) => {
    const s = progress[id];
    if (!s) return true;
    return s.nextReviewDate <= lim;
  });
  return ids.sort((a, b) => {
    const ta = progress[a]?.nextReviewDate ?? 0;
    const tb = progress[b]?.nextReviewDate ?? 0;
    return ta - tb;
  });
}
