import type { SupportTicket, SupportTicketSeverity } from "../data/ticketSchema";

export type MissionOutcome = "resolved" | "failed";

export type MissionReportPayload = {
  ticketId: string;
  title: string;
  severity: SupportTicketSeverity;
  outcome: MissionOutcome;
  tier: string;
  slaRatio: number;
  remSec: number;
  startSec: number;
  baseXp: number;
  bonusXp: number;
  totalXp: number;
  terminalLines: string[];
};

export function baseXpForSeverity(sev: SupportTicketSeverity): number {
  if (sev === "critical") return 250;
  if (sev === "high") return 100;
  return 50;
}

/** Rest-SLA / Start-SLA — nur bei Erfolg sinnvoll */
export function efficiencyTier(ratio: number, outcome: MissionOutcome): string {
  if (outcome === "failed") return "F";
  if (ratio > 0.75) return "S";
  if (ratio > 0.5) return "A";
  if (ratio > 0.25) return "B";
  return "C";
}

export function slaTimeBonusXp(ratio: number, outcome: MissionOutcome): number {
  if (outcome === "failed") return 0;
  return Math.min(120, Math.floor(ratio * 95));
}

export function buildTerminalLines(outcome: MissionOutcome): string[] {
  if (outcome === "resolved") {
    return ["> Diagnostics session ACK", "> Connection restored", "> SLA kernel preserved"];
  }
  return ["> Critical failure pathway", "> SLA breached", "> Data path lost"];
}

export function buildMissionReport(
  ticket: SupportTicket,
  outcome: MissionOutcome,
  remSec: number,
  startSec: number,
): MissionReportPayload {
  const start = Math.max(1, startSec);
  const ratio = outcome === "failed" ? 0 : Math.min(1, remSec / start);
  const tier = efficiencyTier(ratio, outcome);
  const baseXp = outcome === "resolved" ? baseXpForSeverity(ticket.severity) : 0;
  const bonusXp = slaTimeBonusXp(ratio, outcome);
  const totalXp = baseXp + bonusXp;
  return {
    ticketId: ticket.id,
    title: ticket.title,
    severity: ticket.severity,
    outcome,
    tier,
    slaRatio: ratio,
    remSec,
    startSec,
    baseXp,
    bonusXp,
    totalXp,
    terminalLines: buildTerminalLines(outcome),
  };
}
