import { motion, useReducedMotion } from "framer-motion";
import { useEffect, useMemo, useState } from "react";
import { LORE_REGISTRY, findLoreFragmentById } from "../../data/loreRegistry";
import { cn } from "../../lib/cn";
import { useAppStore } from "../../store/useAppStore";

function revealTypewriter(text: string, count: number): string {
  if (count <= 0) return "";
  return text.slice(0, Math.min(text.length, count));
}

export function LoreTerminal() {
  const prefersReduced = !!useReducedMotion();
  const globalLore = useAppStore((s) => s.globalLore);
  const [activeId, setActiveId] = useState<string | null>(null);
  const [revealTick, setRevealTick] = useState(0);
  const [glitchTick, setGlitchTick] = useState(0);

  useEffect(() => {
    void import("../../lib/syncController").then((m) => m.refreshGlobalLoreStateAndPulse());
  }, []);

  const unlockedRows = useMemo(() => {
    const unlocked = new Set(globalLore.unlockedLoreIds);
    return LORE_REGISTRY.filter((row) => unlocked.has(row.id));
  }, [globalLore.unlockedLoreIds]);

  useEffect(() => {
    if (unlockedRows.length === 0) {
      setActiveId(null);
      return;
    }
    if (!activeId || !unlockedRows.some((x) => x.id === activeId)) {
      setActiveId(unlockedRows[unlockedRows.length - 1]?.id ?? null);
    }
  }, [activeId, unlockedRows]);

  const activeFragment = activeId ? findLoreFragmentById(activeId) : null;

  useEffect(() => {
    setRevealTick(0);
    if (!activeFragment) return;
    if (prefersReduced) {
      setRevealTick(activeFragment.cipherText.length);
      return;
    }
    const id = window.setInterval(() => {
      setRevealTick((x) => Math.min(activeFragment.cipherText.length, x + 3));
    }, 26);
    return () => window.clearInterval(id);
  }, [activeFragment, prefersReduced]);

  useEffect(() => {
    if (prefersReduced) return;
    const id = window.setInterval(() => setGlitchTick((x) => x + 1), 160);
    return () => window.clearInterval(id);
  }, [prefersReduced]);

  const decodedText = activeFragment ? revealTypewriter(activeFragment.cipherText, revealTick) : "";
  void glitchTick;

  return (
    <section className="relative overflow-hidden rounded-3xl border border-cyan-300/28 bg-black/45 p-5 ring-1 ring-cyan-500/20">
      <div className="pointer-events-none absolute inset-0 noise-overlay opacity-[0.18]" />
      <div
        className="pointer-events-none absolute inset-0 opacity-[0.1]"
        style={{
          backgroundImage:
            "repeating-linear-gradient(to bottom, rgba(255,255,255,0.08) 0px, rgba(255,255,255,0.08) 1px, transparent 2px, transparent 4px)",
        }}
        aria-hidden
      />

      <div className="relative space-y-4">
        <div className="flex flex-wrap items-end justify-between gap-3 border-b border-cyan-300/20 pb-2">
          <div>
            <p className="font-mono text-[10px] font-semibold uppercase tracking-[0.3em] text-cyan-200/90">
              Lore Terminal
            </p>
            <h3 className="font-mono text-lg font-bold uppercase tracking-[0.08em] text-cyan-100">
              Classified Fragments
            </h3>
          </div>
          <span className="border border-cyan-300/25 bg-cyan-500/10 px-2 py-1 font-mono text-[9px] uppercase tracking-[0.16em] text-cyan-100/90">
            Global XP {globalLore.totalGlobalXp}
          </span>
        </div>

        <div className="flex flex-wrap gap-2">
          {LORE_REGISTRY.map((row) => {
            const unlocked = globalLore.unlockedLoreIds.includes(row.id);
            const active = activeId === row.id;
            return (
              <button
                key={row.id}
                type="button"
                disabled={!unlocked}
                onClick={() => setActiveId(row.id)}
                className={cn(
                  "border px-2 py-1 font-mono text-[9px] uppercase tracking-[0.14em]",
                  !unlocked
                    ? "cursor-not-allowed border-white/[0.1] bg-black/25 text-foreground-muted/55"
                    : active
                      ? "border-cyan-300/45 bg-cyan-500/16 text-cyan-100"
                      : "border-cyan-300/25 bg-black/30 text-cyan-200/80 hover:bg-cyan-500/10",
                )}
              >
                {unlocked ? row.title : "Encrypted"}
              </button>
            );
          })}
        </div>

        {activeFragment ? (
          <motion.div
            initial={prefersReduced ? false : { opacity: 0, y: 6 }}
            animate={{ opacity: 1, y: 0 }}
            className="space-y-3 border border-cyan-300/22 bg-black/50 p-3"
          >
            <p className="font-mono text-[10px] font-bold uppercase tracking-[0.22em] text-cyan-100">
              {activeFragment.title}
            </p>
            <pre
              className={cn(
                "max-h-56 overflow-auto whitespace-pre-wrap border border-cyan-300/18 bg-black/65 p-3 font-mono text-[11px] leading-relaxed text-cyan-100/92",
                !prefersReduced && "animate-pulse",
              )}
              style={{ animationDuration: "2.4s" }}
            >
              {decodedText}
            </pre>
            <pre className="border border-cyan-300/16 bg-cyan-500/[0.06] p-2 font-mono text-[10px] leading-snug tracking-[0.12em] text-cyan-100/88">
              {activeFragment.imageGlyph}
            </pre>
          </motion.div>
        ) : (
          <p className="font-mono text-[10px] uppercase tracking-[0.16em] text-foreground-muted">
            Keine Fragmente freigegeben
          </p>
        )}
      </div>
    </section>
  );
}
