import { AnimatePresence, motion, useReducedMotion } from "framer-motion";
import { useEffect, useState } from "react";
import { useAppStore } from "../../store/useAppStore";

/**
 * Phase 50 — dezenter Hinweis bei Browser-Offline oder erkennbaren Cloud-Transport-Fehlern
 * UI-Texte ohne Satzzeichen am Ende
 */
export function SystemConnectivityBanner() {
  const prefersReduced = useReducedMotion();
  const linkPulseStatus = useAppStore((s) => s.linkPulseStatus);
  const [navigatorOnline, setNavigatorOnline] = useState(
    () => typeof navigator === "undefined" || navigator.onLine,
  );

  useEffect(() => {
    const on = () => setNavigatorOnline(true);
    const off = () => setNavigatorOnline(false);
    window.addEventListener("online", on);
    window.addEventListener("offline", off);
    return () => {
      window.removeEventListener("online", on);
      window.removeEventListener("offline", off);
    };
  }, []);

  const show = linkPulseStatus === "offline";
  const label = !navigatorOnline
    ? "Kein Netzwerk · Codesnap bleibt offline nutzbar"
    : "Cloud-Uplink instabil · Sync pausiert · Daten bleiben lokal";

  return (
    <AnimatePresence>
      {show ? (
        <motion.div
          key="connectivity-banner"
          role="status"
          aria-live="polite"
          initial={prefersReduced ? { opacity: 0 } : { opacity: 0, y: -8 }}
          animate={prefersReduced ? { opacity: 1 } : { opacity: 1, y: 0 }}
          exit={prefersReduced ? { opacity: 0 } : { opacity: 0, y: -6 }}
          transition={{ duration: prefersReduced ? 0.2 : 0.45, ease: [0.22, 1, 0.36, 1] }}
          className="pointer-events-none fixed inset-x-0 top-0 z-[470] flex justify-center px-3 pt-[env(safe-area-inset-top,0px)]"
        >
          <div className="max-w-2xl border-b border-amber-400/25 bg-black/55 px-4 py-2 text-center shadow-[inset_0_-1px_0_rgb(251_191_36_/0.12),0_0_28px_rgb(251_191_36_/0.08)] backdrop-blur-md">
            <p className="font-mono text-[10px] font-medium uppercase tracking-[0.22em] text-amber-100/90">{label}</p>
          </div>
        </motion.div>
      ) : null}
    </AnimatePresence>
  );
}
