import { motion, useSpring, useTransform } from "framer-motion";
import { useEffect, useMemo, type ComponentType, type SVGProps } from "react";
import {
  IconGem,
  IconHexagon,
  IconLandmark,
  IconSparkles,
} from "../icons/ThinLineIcons";
import { cn } from "../../lib/cn";
import type { RealmTileState } from "../../types/realmQuest";
import { useAppStore } from "../../store/useAppStore";

function SpringStat({
  value,
  label,
  icon: Icon,
  className,
}: {
  value: number;
  label: string;
  icon: ComponentType<SVGProps<SVGSVGElement>>;
  className?: string;
}) {
  const spring = useSpring(value, { stiffness: 220, damping: 30, mass: 0.4 });
  useEffect(() => {
    spring.set(value);
  }, [value, spring]);
  const rounded = useTransform(spring, (v) => Math.round(v));

  return (
    <div
      className={cn(
        "flex min-w-0 flex-1 items-center gap-2 rounded-xl border border-border-glass bg-surface-muted/55 px-3 py-2 backdrop-blur-xl sm:gap-3 sm:px-4",
        className,
      )}
    >
      <Icon className="size-4 shrink-0 text-foreground-muted sm:size-5" aria-hidden />
      <div className="min-w-0">
        <p className="truncate font-sans text-[9px] font-semibold uppercase tracking-wider text-foreground-muted">
          {label}
        </p>
        <motion.span className="block font-mono text-lg font-bold tabular-nums text-foreground sm:text-xl">
          {rounded}
        </motion.span>
      </div>
    </div>
  );
}

function countFields(tiles: Record<string, RealmTileState>): number {
  return Object.values(tiles).filter((t) => t.structure !== "empty").length;
}

export function RealmHud() {
  const realmGold = useAppStore((s) => s.realmGold);
  const realmDiamonds = useAppStore((s) => s.realmDiamonds);
  const realmKnowledge = useAppStore((s) => s.realmKnowledge);
  const realmTiles = useAppStore((s) => s.realmTiles);

  const fields = useMemo(() => countFields(realmTiles), [realmTiles]);

  return (
    <motion.header
      initial={{ y: -16, opacity: 0 }}
      animate={{ y: 0, opacity: 1 }}
      transition={{ type: "spring", stiffness: 280, damping: 28 }}
      className={cn(
        "pointer-events-auto fixed left-1/2 top-[calc(0.75rem+env(safe-area-inset-top))] z-[60] flex w-[min(100%-1.5rem,56rem)] -translate-x-1/2",
        "rounded-2xl border border-border-glass bg-surface/75 p-2 ring-1 ring-white/10 backdrop-blur-2xl sm:p-3",
        "ring-1 ring-magenta/20",
      )}
    >
      <div className="pointer-events-none absolute inset-0 noise-overlay opacity-20" />
      <div className="relative flex w-full flex-wrap items-stretch justify-center gap-2 sm:flex-nowrap sm:gap-3">
        <SpringStat value={realmGold} label="Gold" icon={IconLandmark} className="ring-1 ring-white/10" />
        <SpringStat value={realmDiamonds} label="Diamanten" icon={IconGem} className="ring-1 ring-white/10" />
        <SpringStat value={realmKnowledge} label="Wissen" icon={IconSparkles} className="ring-1 ring-white/10" />
        <SpringStat value={fields} label="Felder" icon={IconHexagon} className="ring-1 ring-white/10" />
      </div>
    </motion.header>
  );
}
