import { memo } from "react";
import { cn } from "../../lib/cn";
import type { SqlDifficulty } from "../../data/sqlMissions";

const styles: Record<
  SqlDifficulty,
  { label: string; className: string }
> = {
  easy: {
    label: "Leicht",
    className:
      "border border-cyber-cyan/30 bg-cyber-cyan/25 text-cyber-cyan ring-1 ring-white/10",
  },
  medium: {
    label: "Mittel",
    className:
      "border border-magenta/35 bg-magenta/25 text-magenta ring-1 ring-white/10",
  },
  hard: {
    label: "Schwer",
    className:
      "border border-toxic/30 bg-toxic/22 text-toxic ring-1 ring-white/10",
  },
};

export interface SqlDifficultyBadgeProps {
  difficulty: SqlDifficulty;
  className?: string;
}

export const SqlDifficultyBadge = memo(function SqlDifficultyBadge({
  difficulty,
  className,
}: SqlDifficultyBadgeProps) {
  const s = styles[difficulty];
  return (
    <span
      className={cn(
        "inline-flex shrink-0 rounded-full border border-white/10 px-2.5 py-0.5 font-mono text-[10px] font-bold uppercase tracking-wider backdrop-blur-sm",
        s.className,
        className,
      )}
    >
      {s.label}
    </span>
  );
});
