import { memo } from "react";
import { cn } from "../../lib/cn";
import type { RealmFactionId } from "../../types/faction";
import type { RealmTileStructure } from "../../types/realmQuest";

const HEX_CLIP =
  "polygon(50% 0%, 100% 25%, 100% 75%, 50% 100%, 0% 75%, 0% 25%)" as const;

const factionMain: Record<RealmFactionId, string> = {
  humans: "bg-gradient-to-br from-cyber-cyan/50 to-cyber-cyan/15 ring-1 ring-white/10",
  orcs: "bg-gradient-to-br from-magenta/50 to-magenta/15 ring-1 ring-white/10",
  dwarves: "bg-gradient-to-br from-toxic/45 to-toxic/10 ring-1 ring-white/10",
};

export interface HexCellProps {
  q: number;
  r: number;
  structure: RealmTileStructure;
  faction: RealmFactionId;
  pixelLeft: number;
  pixelTop: number;
  cellSizePx: number;
  onPress: (q: number, r: number) => void;
}

export const HexCell = memo(function HexCell({
  q,
  r,
  structure,
  faction,
  pixelLeft,
  pixelTop,
  cellSizePx,
  onPress,
}: HexCellProps) {
  const w = cellSizePx * 2;
  const h = cellSizePx * Math.sqrt(3);

  const isMain = structure === "main";
  const isGold = structure === "goldmine";
  const isBarracks = structure === "barracks";
  const isEmpty = structure === "empty";

  return (
    <button
      type="button"
      aria-label={`Hex ${q} ${r}`}
      onClick={() => onPress(q, r)}
      className={cn(
        "absolute flex items-center justify-center outline-none transition-[transform,filter] duration-150 will-change-transform",
        "hover:z-[2] hover:scale-[1.06] hover:brightness-125 focus-visible:ring-2 focus-visible:ring-magenta",
        "active:scale-[0.98]",
      )}
      style={{
        left: pixelLeft,
        top: pixelTop,
        width: w,
        height: h,
        marginLeft: -w / 2,
        marginTop: -h / 2,
        clipPath: HEX_CLIP,
      }}
    >
      <span
        className={cn(
          "flex size-full items-center justify-center border border-white/10 font-mono text-[9px] font-bold uppercase tracking-wider",
          isEmpty && "bg-zinc-900/95 text-zinc-500 ring-1 ring-black/40",
          isEmpty && "hover:border-cyber-cyan/40 hover:bg-white/[0.03]",
          isMain && factionMain[faction],
          isGold && "bg-gradient-to-br from-amber-400/35 to-zinc-900 ring-1 ring-amber-400/20",
          isBarracks && "bg-gradient-to-br from-slate-400/35 to-zinc-900 ring-1 ring-slate-400/20",
        )}
      >
        {isMain ? "HQ" : null}
        {isGold ? "M" : null}
        {isBarracks ? "K" : null}
      </span>
    </button>
  );
});
