import { AnimatePresence, motion, useReducedMotion } from "framer-motion";
import { useEffect, useMemo, useState } from "react";
import { IconArrowLeft, IconCloud, IconGem, IconLayers, IconTrophy } from "../icons/ThinLineIcons";
import { AchievementCabinet } from "../achievements/AchievementCabinet";
import { ArtifactPedestal } from "./ArtifactPedestal";
import { SignalLineTrack } from "../system/SignalActivityLine";
import { getRankArtifact, getNextRankMilestone, getStreakFlexBand, getStreakInsetGlowMotion } from "../../lib/rankEngine";
import { springHeavy } from "../../motion/variants";
import { cn } from "../../lib/cn";
import { useAppStore, shouldSkipPublicDossierFetch } from "../../store/useAppStore";

function InterceptMask({ active }: { active: boolean }) {
  const prefersReduced = useReducedMotion();
  return (
    <AnimatePresence>
      {active ? (
        <motion.div
          key="intercept-mask"
          className="pointer-events-none fixed inset-0 z-[360] bg-black/78"
          initial={{ opacity: 0.92, clipPath: "inset(0% 0% 0% 0%)" }}
          animate={{ opacity: prefersReduced ? 0 : [0.92, 0.7, 0], clipPath: "inset(46% 0% 46% 0%)" }}
          exit={{ opacity: 0 }}
          transition={{ duration: prefersReduced ? 0.18 : 0.5, ease: [0.22, 1, 0.36, 1] }}
        >
          <div className="absolute inset-0 hud-grid opacity-[0.12]" />
          <div className="absolute inset-x-0 top-1/2 h-px -translate-y-1/2 bg-gradient-to-r from-transparent via-white/35 to-transparent" />
        </motion.div>
      ) : null}
    </AnimatePresence>
  );
}

function StatChip({
  icon: Icon,
  label,
  value,
}: {
  icon: typeof IconGem;
  label: string;
  value: string;
}) {
  return (
    <div className="border border-white/[0.08] bg-white/[0.03] px-4 py-3">
      <div className="flex items-center gap-2 text-foreground-muted">
        <Icon className="size-4" />
        <span className="font-mono text-[10px] uppercase tracking-[0.22em]">{label}</span>
      </div>
      <p className="mt-3 font-sans text-2xl font-semibold tracking-[-0.05em] text-foreground/88">{value}</p>
    </div>
  );
}

export function PublicDossierView() {
  const prefersReduced = useReducedMotion();
  const selectedPublicOperatorId = useAppStore((s) => s.selectedPublicOperatorId);
  const selectedPublicOperatorHandle = useAppStore((s) => s.selectedPublicOperatorHandle);
  const publicDossierBusy = useAppStore((s) => s.publicDossierBusy);
  const publicDossierData = useAppStore((s) => s.publicDossierData);
  const publicDossierOnline = useAppStore((s) => s.publicDossierOnline);
  const cloudLastError = useAppStore((s) => s.cloudLastError);
  const closePublicDossier = useAppStore((s) => s.closePublicDossier);
  const setPublicDossierBusy = useAppStore((s) => s.setPublicDossierBusy);
  const setPublicDossierData = useAppStore((s) => s.setPublicDossierData);
  const [showIntercept, setShowIntercept] = useState(true);

  useEffect(() => {
    const ms = prefersReduced ? 180 : 520;
    const id = window.setTimeout(() => setShowIntercept(false), ms);
    return () => window.clearTimeout(id);
  }, [prefersReduced, selectedPublicOperatorId]);

  useEffect(() => {
    if (!selectedPublicOperatorId) return;
    if (shouldSkipPublicDossierFetch(selectedPublicOperatorId)) return;
    let cancelled = false;
    setPublicDossierBusy(true);
    void import("../../lib/syncController").then(async (m) => {
      const data = await m.fetchPublicOperatorDossier(selectedPublicOperatorId);
      if (cancelled) return;
      if (!data) {
        setPublicDossierData(null);
        setPublicDossierBusy(false);
      }
    });
    return () => {
      cancelled = true;
    };
  }, [selectedPublicOperatorId, setPublicDossierBusy, setPublicDossierData]);

  const dossier = publicDossierData;
  const rankArtifact = getRankArtifact(dossier?.userLevel ?? 0);
  const streakDays = dossier?.dailyStreakDays ?? 0;
  const streakBand = getStreakFlexBand(streakDays);
  const streakGlow = getStreakInsetGlowMotion(rankArtifact, streakBand);
  const nextMilestone = getNextRankMilestone(dossier?.userLevel ?? 0);
  const statusLabel = publicDossierOnline ? "Online Signal aktiv" : "Signal zuletzt empfangen";
  const titleHandle = dossier?.handle ?? selectedPublicOperatorHandle ?? "Unknown_Operator";
  const updatedLabel = useMemo(() => {
    if (!dossier?.updatedAt) return "Kein Remote Snapshot";
    const stamp = new Date(dossier.updatedAt);
    return `Snapshot ${stamp.toLocaleDateString("de-DE")} ${stamp.toLocaleTimeString("de-DE", {
      hour: "2-digit",
      minute: "2-digit",
    })}`;
  }, [dossier?.updatedAt]);

  return (
    <div className="relative -mx-4 space-y-8 pb-20 sm:-mx-6">
      <InterceptMask active={showIntercept} />
      <header className="relative overflow-hidden border border-white/[0.08] bg-surface/55 p-6 sm:p-8">
        <div className="absolute inset-0 hud-grid opacity-[0.08]" />
        <span
          className="pointer-events-none absolute right-0 top-1/2 -translate-y-1/2 select-none font-sans text-[clamp(7rem,24vw,16rem)] font-bold leading-none text-white/[0.04]"
          aria-hidden
        >
          {dossier?.userLevel ?? "--"}
        </span>
        <div className="relative z-10 space-y-5">
          <div className="flex flex-wrap items-center justify-between gap-3">
            <motion.button
              type="button"
              whileTap={{ scale: 0.94, y: 3 }}
              transition={springHeavy}
              onClick={closePublicDossier}
              className="inline-flex items-center gap-2 border border-white/[0.1] bg-white/[0.03] px-3 py-2 font-mono text-[11px] uppercase tracking-[0.18em] text-foreground-muted hover-breathe hover:border-white/[0.16] hover:text-foreground"
            >
              <IconArrowLeft className="size-4" />
              Zurück zum Feed
            </motion.button>
            <div className="min-w-[200px] space-y-2">
              <div className={cn("font-mono text-[10px] uppercase tracking-[0.22em]", publicDossierOnline ? "text-foreground/86" : "text-foreground-muted")}>
                {statusLabel}
              </div>
              <SignalLineTrack scope="inline" className={cn(publicDossierOnline ? "bg-white/[0.08]" : "bg-white/[0.04]")} />
            </div>
          </div>

          <div className="grid gap-6 lg:grid-cols-[160px_1fr] lg:items-end">
            <div className="w-28 saturate-[0.78] sm:w-36">
              <ArtifactPedestal artifact={rankArtifact} variant="hero" className="border-white/[0.08] bg-black/45 saturate-[0.8]" />
            </div>
            <div className="space-y-3">
              <p className="font-mono text-[10px] uppercase tracking-[0.34em] text-foreground-muted">
                Social Intercept
              </p>
              <h1 className="headline-cinema max-w-[18ch] text-4xl font-semibold text-foreground/88 sm:text-6xl">
                {titleHandle}
              </h1>
              <p className="max-w-2xl font-serif text-base leading-relaxed tracking-[-0.01em] text-foreground/66">
                Fremdes Operator Dossier im schattierten Lesemodus mit gespiegelt geladenem Rang und Leistungs-Snapshot
              </p>
              <div className="flex flex-wrap gap-2 font-mono text-[10px] uppercase tracking-[0.18em] text-foreground-muted">
                <span className="border border-white/[0.08] bg-white/[0.03] px-3 py-1">Level {dossier?.userLevel ?? 0}</span>
                <span className="border border-white/[0.08] bg-white/[0.03] px-3 py-1">{rankArtifact.tier.replaceAll("_", " ")}</span>
                {dossier?.bossRaidTitle ? (
                  <span className="border border-amber-300/45 bg-amber-500/[0.16] px-3 py-1 text-amber-100">
                    {dossier.bossRaidTitle}
                  </span>
                ) : null}
                <span
                  className={cn(
                    "relative overflow-hidden border border-white/[0.08] bg-white/[0.03] px-3 py-1",
                    streakBand !== "none" && "ring-1 ring-toxic/25",
                  )}
                >
                  {streakGlow && !prefersReduced ? (
                    <motion.div
                      aria-hidden
                      className="pointer-events-none absolute inset-0 z-0"
                      initial={{ opacity: 0 }}
                      animate={{ opacity: streakGlow.pulseOpacity }}
                      transition={{ duration: streakGlow.duration, repeat: Infinity, ease: "easeInOut" }}
                      style={{ boxShadow: streakGlow.boxShadow }}
                    />
                  ) : null}
                  <span className="relative z-10 inline-flex items-baseline gap-2">
                    <span>Grind Streak</span>
                    <span className="font-sans text-sm font-semibold tabular-nums tracking-[-0.04em] text-foreground/88">{streakDays}d</span>
                  </span>
                </span>
                <span className="border border-white/[0.08] bg-white/[0.03] px-3 py-1">{updatedLabel}</span>
              </div>
            </div>
          </div>

          {publicDossierBusy ? <SignalLineTrack scope="inline" className="mt-2" /> : null}
          {cloudLastError && !publicDossierBusy ? (
            <p className="font-mono text-[10px] uppercase tracking-[0.2em] text-signal">{cloudLastError}</p>
          ) : null}
        </div>
      </header>

      <section className="grid gap-4 md:grid-cols-2 xl:grid-cols-4">
        <StatChip icon={IconGem} label="Gems" value={`${dossier?.gems ?? 0}`} />
        <StatChip icon={IconLayers} label="Reviews" value={`${dossier?.flashcardTotalReviews ?? 0}`} />
        <StatChip icon={IconTrophy} label="Best Score" value={`${dossier?.bestArenaScore ?? 0}`} />
        <StatChip icon={IconCloud} label="Cards" value={`${dossier?.flashcardCardCount ?? 0}`} />
      </section>

      <section className="border border-white/[0.08] bg-surface/40 p-6">
        <AchievementCabinet unlockedIds={dossier?.unlockedAchievementIds ?? []} />
      </section>

      <section className="grid gap-6 xl:grid-cols-[1.2fr_0.8fr]">
        <div className="border border-white/[0.08] bg-surface/45 p-6">
          <p className="font-mono text-[10px] uppercase tracking-[0.28em] text-foreground-muted">
            Remote Analysis
          </p>
          <div className="mt-5 space-y-4">
            <div className="border-b border-white/[0.08] pb-4">
              <p className="font-mono text-[10px] uppercase tracking-[0.2em] text-foreground-muted">Global XP</p>
              <p className="mt-2 font-sans text-3xl font-semibold tracking-[-0.05em] text-foreground/88">
                {dossier?.globalXP ?? 0}
              </p>
              <p className="mt-1 font-serif text-sm text-foreground/62">
                Bis zum nächsten Rangfenster {dossier?.globalXpToNext ?? 0}
              </p>
            </div>
            <div className="grid gap-4 sm:grid-cols-2">
              <div>
                <p className="font-mono text-[10px] uppercase tracking-[0.2em] text-foreground-muted">Dominanter Tag</p>
                <p className="mt-2 font-sans text-lg text-foreground/84">
                  {dossier?.strongestTag ?? "Kein Muster"}
                </p>
              </div>
              <div>
                <p className="font-mono text-[10px] uppercase tracking-[0.2em] text-foreground-muted">Letzte Mission</p>
                <p className="mt-2 font-sans text-lg text-foreground/84">
                  {dossier?.lastMissionType ?? "Keine Arena Spur"}
                </p>
              </div>
            </div>
          </div>
        </div>

        <div className="border border-white/[0.08] bg-surface/35 p-6">
          <p className="font-mono text-[10px] uppercase tracking-[0.28em] text-foreground-muted">
            Rank Trajectory
          </p>
          <div className="mt-5 space-y-4">
            <div>
              <p className="font-serif text-lg leading-snug text-foreground/72">
                Nächste Rangstufe wird bei weiterem Uplink aus dem aktuellen Snapshot berechnet
              </p>
            </div>
            <div className="border border-white/[0.08] bg-white/[0.03] px-4 py-4">
              <p className="font-mono text-[10px] uppercase tracking-[0.2em] text-foreground-muted">Next Milestone</p>
              <p className="mt-2 font-sans text-lg text-foreground/86">
                {nextMilestone
                  ? `${nextMilestone.nextTier.replaceAll("_", " ")} ab Level ${nextMilestone.nextLevel}`
                  : "Maximaler Rang erreicht"}
              </p>
            </div>
            <div className="border border-white/[0.08] bg-white/[0.03] px-4 py-4">
              <p className="font-mono text-[10px] uppercase tracking-[0.2em] text-foreground-muted">Arena Signal</p>
              <p className="mt-2 font-sans text-lg text-foreground/86">
                {dossier?.lastArenaAt ? new Date(dossier.lastArenaAt).toLocaleString("de-DE") : "Kein Arena Ping"}
              </p>
            </div>
          </div>
        </div>
      </section>
    </div>
  );
}
