import { motion, useReducedMotion } from "framer-motion";
import { useMemo } from "react";
import { useTelemetrySnapshot } from "../../hooks/useTelemetrySnapshot";
import type { ArenaBarRow, MockExamSeriesPoint, TagSignalRow } from "../../lib/telemetryMatrix";
import { cn } from "../../lib/cn";
import { itemReveal, staggerContainer } from "../../motion/variants";

function KpiChip({ label, value }: { label: string; value: string }) {
  return (
    <div className="border border-white/[0.1] bg-void/50 px-3 py-2">
      <p className="font-mono text-[9px] font-semibold uppercase tracking-[0.22em] text-foreground-muted">{label}</p>
      <p className="mt-1 font-mono text-lg font-semibold tabular-nums text-foreground">{value}</p>
    </div>
  );
}

function MockExamTrajectoryGraph({ series, reduced }: { series: MockExamSeriesPoint[]; reduced: boolean }) {
  const { pointsAttr, view } = useMemo(() => {
    if (series.length === 0) return { pointsAttr: "", view: null as null | { cx: number; cy: number } };
    const w = 100;
    const h = 44;
    const pad = 4;
    const innerW = w - pad * 2;
    const innerH = h - pad * 2;
    if (series.length === 1) {
      const p = series[0];
      const cy = pad + innerH * (1 - p.percent / 100);
      return { pointsAttr: "", view: { cx: w / 2, cy } };
    }
    const pts = series.map((p, i) => {
      const x = pad + (innerW * i) / (series.length - 1);
      const y = pad + innerH * (1 - p.percent / 100);
      return `${x.toFixed(2)},${y.toFixed(2)}`;
    });
    return { pointsAttr: pts.join(" "), view: null };
  }, [series]);

  if (series.length === 0) {
    return (
      <div className="flex h-[140px] items-center justify-center border border-white/[0.08] bg-black/40 font-mono text-[11px] uppercase tracking-[0.16em] text-foreground-muted">
        Keine Mock Exam Daten
      </div>
    );
  }

  return (
    <div className="relative border border-white/[0.1] bg-black/50 p-3">
      <svg className="h-[140px] w-full" viewBox="0 0 100 44" preserveAspectRatio="none" aria-hidden>
        <defs>
          <linearGradient id="telemetry-line-glow" x1="0%" y1="0%" x2="100%" y2="0%">
            <stop offset="0%" stopColor="var(--color-signal)" stopOpacity="0.15" />
            <stop offset="50%" stopColor="var(--color-signal)" stopOpacity="0.55" />
            <stop offset="100%" stopColor="var(--color-signal)" stopOpacity="0.2" />
          </linearGradient>
        </defs>
        <line x1="4" y1="40" x2="96" y2="40" stroke="rgb(255 255 255 / 0.08)" strokeWidth="0.35" />
        {view ? (
          <circle cx={view.cx} cy={view.cy} r="2.2" fill="var(--color-signal)" className="drop-shadow-[0_0_6px_var(--color-signal)]" />
        ) : (
          <>
            <motion.polyline
              fill="none"
              stroke="url(#telemetry-line-glow)"
              strokeWidth="1.2"
              strokeLinecap="round"
              strokeLinejoin="round"
              points={pointsAttr}
              initial={reduced ? false : { opacity: 0.35 }}
              animate={{ opacity: 1 }}
              transition={reduced ? { duration: 0 } : { duration: 0.45, ease: "easeOut" }}
            />
            <polyline
              fill="none"
              stroke="var(--color-signal)"
              strokeWidth="0.45"
              strokeLinecap="round"
              strokeLinejoin="round"
              points={pointsAttr}
              opacity="0.95"
            />
          </>
        )}
      </svg>
      <p className="mt-2 font-mono text-[9px] uppercase tracking-[0.18em] text-foreground-muted">
        Mock Exam · Prozent über Zeitachse
      </p>
    </div>
  );
}

function MockExamTagBars({ rows, reduced }: { rows: TagSignalRow[]; reduced: boolean }) {
  const max = useMemo(() => Math.max(1, ...rows.map((r) => r.hits)), [rows]);

  if (rows.length === 0) {
    return (
      <div className="flex min-h-[120px] items-center justify-center border border-white/[0.08] bg-black/40 font-mono text-[11px] uppercase tracking-[0.16em] text-foreground-muted">
        Keine Tag Treffer
      </div>
    );
  }

  return (
    <div className="space-y-2 border border-white/[0.1] bg-black/40 p-3">
      <p className="font-mono text-[9px] font-semibold uppercase tracking-[0.22em] text-foreground-muted">
        Korrekte Hits nach Thema
      </p>
      <div className="max-h-[200px] space-y-2 overflow-y-auto pr-1 question-scrollbar">
        {rows.map((row, i) => (
          <div key={row.tag} className="space-y-1">
            <div className="flex justify-between gap-2 font-mono text-[10px] uppercase tracking-wide text-foreground-muted">
              <span className="min-w-0 truncate text-foreground">{row.tag}</span>
              <span className="shrink-0 tabular-nums text-signal">{row.hits}</span>
            </div>
            <div className="h-1.5 w-full overflow-hidden bg-white/[0.06]">
              <motion.div
                className="h-full bg-signal/75"
                initial={reduced ? false : { width: 0 }}
                animate={{ width: `${(row.hits / max) * 100}%` }}
                transition={reduced ? { duration: 0 } : { duration: 0.5, delay: i * 0.04, ease: [0.16, 1, 0.3, 1] }}
              />
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}

function ArenaBestStrip({ rows, reduced }: { rows: ArenaBarRow[]; reduced: boolean }) {
  const max = useMemo(() => Math.max(1, ...rows.map((r) => r.bestScore)), [rows]);
  const any = rows.some((r) => r.bestScore > 0);

  if (!any) {
    return (
      <div className="flex min-h-[100px] items-center justify-center border border-white/[0.08] bg-black/40 font-mono text-[11px] uppercase tracking-[0.16em] text-foreground-muted">
        Noch keine Arena Bestwerte
      </div>
    );
  }

  const barMaxPx = 88;

  return (
    <div className="border border-white/[0.1] bg-black/40 p-3">
      <p className="font-mono text-[9px] font-semibold uppercase tracking-[0.22em] text-foreground-muted">
        Arena Best Scores
      </p>
      <div className="mt-3 flex h-[112px] items-end justify-between gap-2">
        {rows.map((row, i) => {
          const h = Math.max(4, Math.round((row.bestScore / max) * barMaxPx));
          return (
            <div key={row.examId} className="flex min-w-0 flex-1 flex-col items-center justify-end gap-2">
              <div className="flex h-[88px] w-full items-end justify-center">
                <motion.div
                  className="w-[min(100%,3rem)] rounded-t-sm bg-gradient-to-t from-signal/25 to-signal/75"
                  initial={reduced ? false : { height: 0 }}
                  animate={{ height: h }}
                  transition={reduced ? { duration: 0 } : { duration: 0.55, delay: i * 0.06, ease: [0.16, 1, 0.3, 1] }}
                />
              </div>
              <span className="font-mono text-[9px] uppercase tracking-wider text-foreground-muted">{row.title}</span>
              <span className="font-mono text-[10px] tabular-nums text-foreground">{row.bestScore}</span>
            </div>
          );
        })}
      </div>
    </div>
  );
}

function FlashcardStabilityCard({
  cyan,
  yellow,
  magenta,
  totalReviews,
  reduced,
}: {
  cyan: number;
  yellow: number;
  magenta: number;
  totalReviews: number;
  reduced: boolean;
}) {
  const total = cyan + yellow + magenta || 1;
  const pc = (n: number) => `${(n / total) * 100}%`;

  return (
    <div className="border border-white/[0.1] bg-black/40 p-3">
      <p className="font-mono text-[9px] font-semibold uppercase tracking-[0.22em] text-foreground-muted">
        Kartenstabilität SM-2
      </p>
      <p className="mt-1 font-mono text-[10px] tabular-nums text-foreground-muted">Reviews gesamt {totalReviews}</p>
      <div className="mt-4 flex h-4 w-full overflow-hidden border border-white/[0.1]">
        <motion.div
          className="h-full bg-white/35"
          initial={reduced ? false : { width: "0%" }}
          animate={{ width: pc(cyan) }}
          transition={reduced ? { duration: 0 } : { duration: 0.55, ease: [0.16, 1, 0.3, 1] }}
        />
        <motion.div
          className="h-full bg-white/18"
          initial={reduced ? false : { width: "0%" }}
          animate={{ width: pc(yellow) }}
          transition={reduced ? { duration: 0 } : { duration: 0.55, delay: 0.04, ease: [0.16, 1, 0.3, 1] }}
        />
        <motion.div
          className="h-full bg-signal/55"
          initial={reduced ? false : { width: "0%" }}
          animate={{ width: pc(magenta) }}
          transition={reduced ? { duration: 0 } : { duration: 0.55, delay: 0.08, ease: [0.16, 1, 0.3, 1] }}
        />
      </div>
      <div className="mt-2 flex flex-wrap gap-4 font-mono text-[9px] uppercase tracking-wider text-foreground-muted">
        <span className="text-foreground/80">Stabil {cyan}</span>
        <span className="text-titan">Aktiv {yellow}</span>
        <span className="text-signal">Neu {magenta}</span>
      </div>
    </div>
  );
}

export function TelemetryMatrixView() {
  const reduced = !!useReducedMotion();
  const snap = useTelemetrySnapshot();

  return (
    <motion.div
      variants={staggerContainer}
      initial="initial"
      animate="animate"
      className={cn("relative overflow-hidden rounded-3xl border border-white/[0.1] bg-surface/90")}
    >
      <div className="pointer-events-none absolute inset-0 noise-overlay opacity-[0.12]" />
      <div className="pointer-events-none absolute inset-0 hud-grid opacity-[0.06]" />

      <div className="relative space-y-8 p-6 sm:p-8">
        <motion.header variants={itemReveal} className="space-y-2">
          <p className="font-mono text-[10px] font-semibold uppercase tracking-[0.32em] text-foreground-muted">
            Telemetry Matrix
          </p>
          <h1 className="headline-cinema text-3xl font-semibold sm:text-5xl">Performance Telemetry</h1>
          <p className="max-w-2xl font-sans text-sm leading-relaxed text-foreground-muted">
            Live aus lokalem Progress — Mock Exams Arena und Flashcard Matrix ohne Cloud Pflicht
          </p>
        </motion.header>

        <motion.div variants={itemReveal} className="grid grid-cols-2 gap-2 sm:grid-cols-4 lg:grid-cols-4 xl:grid-cols-8">
          <KpiChip label="Level" value={String(snap.pulseKpis.userLevel)} />
          <KpiChip label="Global XP" value={String(snap.pulseKpis.globalXP)} />
          <KpiChip label="XP bis Level" value={String(snap.pulseKpis.globalXpToNext)} />
          <KpiChip label="Gems" value={String(snap.pulseKpis.gems)} />
          <KpiChip label="Streak Tage" value={String(snap.pulseKpis.streakDays)} />
          <KpiChip label="Arena heute" value={String(snap.pulseKpis.arenaWinsToday)} />
          <KpiChip label="Flash heute" value={String(snap.pulseKpis.flashReviewsToday)} />
          <KpiChip label="SQL heute" value={String(snap.pulseKpis.sqlCheckpointToday)} />
        </motion.div>

        <motion.div variants={itemReveal} className="grid gap-6 lg:grid-cols-2">
          <MockExamTrajectoryGraph series={snap.mockExamSeries} reduced={reduced} />
          <MockExamTagBars rows={snap.tagSignalMock} reduced={reduced} />
        </motion.div>

        <motion.div variants={itemReveal} className="grid gap-6 lg:grid-cols-2">
          <ArenaBestStrip rows={snap.arenaBars} reduced={reduced} />
          <FlashcardStabilityCard
            cyan={snap.flashcardStability.cyan}
            yellow={snap.flashcardStability.yellow}
            magenta={snap.flashcardStability.magenta}
            totalReviews={snap.flashcardStability.totalReviews}
            reduced={reduced}
          />
        </motion.div>
      </div>
    </motion.div>
  );
}
